// Embedded question bank data
const EMBEDDED_DATA = {
  edu: [{"type": "单选", "num": 1, "text": "纽曼认为，大学的职能是教学，而不是科研，大学是为传授知识而设。他的大学理念属于（ ）。", "options": {"A": "实用主义", "B": "要素主义", "C": "存在主义", "D": "理性主义"}, "answer": "D", "explanation": "纽曼是理性主义大学理念的典型代表。他在《大学的理想》中明确提出，大学是传授普遍知识的场所，其目的是理智训练而非科研。理性主义强调知识本身即为目的，大学应远离世俗功利，追求纯粹的理智发展。"}, {"type": "单选", "num": 2, "text": "泰勒提出的教育评价模式是（ ）。", "options": {"A": "目标模式", "B": "人本模式", "C": "决策模式", "D": "过程模式"}, "answer": "A", "explanation": "泰勒被誉为\"课程评价之父\"，他提出的\"目标达成模式\"（目标模式）认为评价的核心是看课程目标是否实现。该模式以预先确定的课程目标为评价依据，通过测量学生行为变化来判断目标达成程度。"}, {"type": "单选", "num": 3, "text": "下列有关建构主义教学的基本观点，说法不正确的是（ ）。", "options": {"A": "教师是学生学习的促进者", "B": "以教师为中心进行教学", "C": "注重在实际情景中进行教学", "D": "提倡合作学习"}, "answer": "B", "explanation": "建构主义主张以学生为中心，强调学生主动建构知识。教师应是学习的促进者、帮助者，而非中心。选项B\"以教师为中心\"恰恰是传统教学的观点，与建构主义背道而驰。"}, {"type": "单选", "num": 4, "text": "在大学发展实践中，大学精神文化最显性的一种形式是（ ）。", "options": {"A": "校园建筑", "B": "管理制度", "C": "校歌", "D": "校训"}, "answer": "D", "explanation": "校训是大学精神文化最集中、最显性的表达形式，它以精炼的文字概括大学的办学理念和价值追求，对内形成文化向心力，对外展示学校精神面貌。"}, {"type": "单选", "num": 5, "text": "高等教育大众化的提出者是（ ）。", "options": {"A": "蒙田", "B": "马克思·韦伯", "C": "马丁·特罗", "D": "保罗·朗格朗"}, "answer": "C", "explanation": "美国教育社会学家马丁·特罗（Martin Trow）在20世纪70年代提出了高等教育发展阶段理论，以毛入学率为指标将高等教育分为精英化（<15%）、大众化（15%-50%）和普及化（>50%）三个阶段。"}, {"type": "单选", "num": 6, "text": "上级将权力借贷给较低层次，权力可随时被收回，这属于权力的（ ）。", "options": {"A": "分散", "B": "委托", "C": "下放", "D": "非中心化"}, "answer": "B", "explanation": "权力的委托（delegation）是指上级将权力临时借给下级使用，下级只有使用权而无所有权，上级可以随时收回该权力。这与权力下放（devolution）不同，后者是永久性的权责转移。"}, {"type": "单选", "num": 7, "text": "从危机产生的来源与后果看，高校危机可分为安全性、灾变性、管理性和群体性等危机类型。以下属于安全性危机的是（ ）。", "options": {"A": "台风", "B": "食物中毒", "C": "游行示威", "D": "乱收费"}, "answer": "B", "explanation": "安全性危机主要指因安全措施不到位导致的人身安全事故，食物中毒属于典型的安全性危机。台风属于灾变性危机，游行示威属于群体性危机，乱收费属于管理性危机。"}, {"type": "单选", "num": 8, "text": "高等学校一切工作的中心是（ ）。", "options": {"A": "政治学习", "B": "社会服务", "C": "科研", "D": "教学"}, "answer": "D", "explanation": "教学是高等学校的中心工作。培养人才是高校的根本任务，而教学是实现人才培养目标的基本途径，因此教学处于高校一切工作的中心地位。"}, {"type": "单选", "num": 9, "text": "构成教案的核心是（ ）。", "options": {"A": "教学过程设计", "B": "班级及学生状况分析", "C": "教学方法", "D": "教学手段"}, "answer": "A", "explanation": "教学过程设计是教案的核心部分，它规定了教学的具体步骤、师生活动安排和时间分配，是教学设计的集中体现。"}, {"type": "单选", "num": 10, "text": "对内能形成文化上的向心力，对外则是学校个性和精神面貌的一种重要彰显，这是大学的（ ）。", "options": {"A": "学风", "B": "教风", "C": "校风", "D": "校训"}, "answer": "D", "explanation": "教材原文明确说明：校训对一所大学而言是一种重要的精神文化元素，“对内能形成一种文化上的向心力，对外则是学校个性和精神面貌的一种重要彰显”。因此本题应选“校训”。"}, {"type": "单选", "num": 11, "text": "苏格拉底提出的\"产婆术\"，本质上是一种什么教学方式？", "options": {"A": "讲授法", "B": "演示法", "C": "操作法", "D": "启发法"}, "answer": "D", "explanation": "苏格拉底的\"产婆术\"（精神助产术）通过不断追问、反诘，引导学生自己发现问题、得出答案，本质上是启发式教学，而非直接灌输。"}, {"type": "单选", "num": 12, "text": "下列关于我国高校教师的学术晋升制度描述错误的是（ ）。", "options": {"A": "我国实施终身聘任制后评审制度将更加普遍、严格", "B": "末位淘汰的机制将激化高校教师职务晋升的竞争", "C": "我国高校教师职务不能实施评聘协调制度", "D": "我国学术职业阶梯体系和职称晋升制度是全国统一的"}, "answer": "C", "explanation": "我国高校教师职务可以实施评聘协调（评聘结合）制度，即评审与聘任相统一。选项C说法错误。其他选项均符合我国高校教师学术晋升制度的实际情况。"}, {"type": "单选", "num": 13, "text": "提出\"大学有四项任务：第一是研究、教学专业知识课程；第二是教育与培养；第三是生命的精神交往；第四是学术\"的人是（ ）。", "options": {"A": "雅斯贝尔斯", "B": "洪堡", "C": "乌申斯基", "D": "伯顿·克拉克"}, "answer": "A", "explanation": "德国存在主义哲学家雅斯贝尔斯（Karl Jaspers）在《大学的理念》中系统阐述了大学的任务，强调大学是研究、教学、精神交往和学术的统一体。"}, {"type": "单选", "num": 14, "text": "以下属于技术性教学方法的是（ ）。", "options": {"A": "发现式", "B": "讲授法", "C": "启发式", "D": "注入式"}, "answer": "B", "explanation": "技术性教学方法是指具体的操作层面的教学方法，讲授法属于最基础的技术性教学方法。发现式、启发式、注入式属于原理性教学方法（思想层面的分类）。"}, {"type": "单选", "num": 15, "text": "理性主义大学理念的代表人物是（ ）。", "options": {"A": "杜威", "B": "纽曼", "C": "里科夫", "D": "科尔"}, "answer": "B", "explanation": "纽曼（John Henry Newman）是理性主义大学理念的奠基人和代表人物。杜威是实用主义代表，科尔是工具主义代表。"}, {"type": "单选", "num": 16, "text": "大学优秀的文化传统和一代又一代的大学人共同创造的精神财富，构成了大学的（ ）。", "options": {"A": "校训", "B": "理念", "C": "校风", "D": "精神"}, "answer": "D", "explanation": "大学精神是大学在长期发展过程中积淀形成的、为全体师生认同的精神财富和文化传统，是大学文化的核心和灵魂。"}, {"type": "单选", "num": 17, "text": "教学设计最基本的表现形式是（ ）。", "options": {"A": "教学过程", "B": "教学手段", "C": "教学目标", "D": "教案"}, "answer": "D", "explanation": "教案是教学设计最具体、最直接的表现形式，是教师实施教学活动的方案和蓝图。"}, {"type": "单选", "num": 18, "text": "\"华盛顿共识\"的思想基础是（ ）。", "options": {"A": "新自由主义", "B": "改良主义", "C": "民粹主义", "D": "自由主义"}, "answer": "A", "explanation": "\"华盛顿共识\"是20世纪80年代末由国际货币基金组织等机构提出的一系列政策主张，其思想基础是新自由主义，强调市场化、私有化和自由化。"}, {"type": "单选", "num": 19, "text": "古希腊智者学派的代表人物是（ ）。", "options": {"A": "伊索克拉特", "B": "芝诺", "C": "亚里斯多德", "D": "普罗泰哥拉"}, "answer": "D", "explanation": "普罗泰哥拉（Protagoras）是古希腊智者学派（Sophists）最著名的代表人物，提出\"人是万物的尺度\"。智者学派以教授辩论术、修辞学为业，是西方最早的职业教师群体。"}, {"type": "单选", "num": 20, "text": "对各种各样学者的学术观点、学术行为的兼容并包，这体现了大学精神文化的（ ）。", "options": {"A": "兼容性", "B": "发展性", "C": "整合性", "D": "个性"}, "answer": "A", "explanation": "兼容性指大学能够容纳不同学术观点、不同思想流派的开放特质，典型代表是蔡元培在北大推行的\"兼容并包\"方针。这是大学精神文化的重要特征。"}, {"type": "单选", "num": 21, "text": "CIPP决策模式的提出者是（ ）。", "options": {"A": "斯特克", "B": "斯克里文", "C": "布鲁纳", "D": "斯塔佛比姆"}, "answer": "D", "explanation": "CIPP评价模式由斯塔佛比姆（Stufflebeam）提出，包括背景评价（Context）、输入评价（Input）、过程评价（Process）和成果评价（Product）四个部分。"}, {"type": "单选", "num": 22, "text": "在一段时间的教学结束后，用于确定教学目标达到的程度，了解学生的整体情况，评定学生的发展水平，同时教学策略及内容的有效性，这种评价方式是（ ）。", "options": {"A": "诊断性评价", "B": "形成性评价", "C": "总结性评价", "D": "定位性评价"}, "answer": "C", "explanation": "总结性评价（终结性评价）是在教学活动结束后进行，用于判断教学效果、评定学生成绩、检验目标达成程度。诊断性评价在教学前进行，形成性评价在教学过程中进行。"}, {"type": "单选", "num": 23, "text": "1975年，第35届国际教育会议的召开城市是（ ）。", "options": {"A": "伦敦", "B": "东京", "C": "巴黎", "D": "日内瓦"}, "answer": "D", "explanation": "1975年第35届国际教育会议在日内瓦召开。联合国教科文组织下属的国际教育局（IBE）总部设在日内瓦，国际教育会议通常在此举行。"}, {"type": "单选", "num": 24, "text": "高校科研管理中，评价人员来源的多样化，评价内容的全面化、具体化，评价过程的公开化、透明化，这反映了（ ）。", "options": {"A": "科研评价具有管理咨询的性质", "B": "科研评价的量化性", "C": "科研评价发展的历史性", "D": "科研评价具有民主性"}, "answer": "D", "explanation": "评价主体多元化、内容全面化、过程公开透明化，这些都是民主性的体现。民主性强调多方参与、公开透明、广泛听取意见。"}, {"type": "单选", "num": 25, "text": "美国课程学者古德莱德认为有五种不同的课程在不同的层次运转，从最高层次理念课程到最低层次经验课程，课程信息呈现的特征是（ ）。", "options": {"A": "信息质变", "B": "信息增多", "C": "信息减少", "D": "信息弱化"}, "answer": "C", "explanation": "古德莱德将课程运行划分为理念课程、正式课程、领悟课程、运作课程、经验课程五个层次。课程从专家构想和制度文本进入教师理解、课堂实施，再到学生实际经验时，会经过文件编制、教师解读、课堂实施和学生吸收等环节的过滤，信息量逐层损耗，因此呈现“信息减少”的特征。"}, {"type": "单选", "num": 26, "text": "在高校教师的教学发展过程中，处于基础地位的是（ ）。", "options": {"A": "提升教学能力", "B": "提升专业知识素养", "C": "形成良好的教师素质", "D": "积累高超的教学技能"}, "answer": "C", "explanation": "形成良好的教师素质是教师教学发展的基础。教师素质涵盖思想、知识、能力等多个维度，是教学能力提升和专业成长的前提。专业知识素养提升是教师素质的一部分，但\"形成良好的教师素质\"是更综合、更基础的要求。"}, {"type": "单选", "num": 27, "text": "教学策略的核心是（ ）。", "options": {"A": "教学方法的设计", "B": "教学媒体的设计", "C": "教学目的的设计", "D": "教学形式的设计"}, "answer": "A", "explanation": "教学策略的核心是教学方法的设计。教学策略是实施教学过程的系统决策，其中教学方法的选用和设计是其关键环节。"}, {"type": "单选", "num": 28, "text": "创办柏林大学的德国教育家是（ ）。", "options": {"A": "佛兰克", "B": "拉福来特", "C": "洪堡", "D": "纽曼"}, "answer": "C", "explanation": "威廉·冯·洪堡（Wilhelm von Humboldt）于1810年创办柏林大学，提出\"教学与研究相统一\"的原则，确立了科学研究的大学职能，被誉为\"现代大学之父\"。"}, {"type": "单选", "num": 29, "text": "高等学校的学生工作涵盖多方面内容，下列不属于学生工作的是（ ）。", "options": {"A": "学生服务", "B": "学生管理", "C": "学生教育", "D": "法律援助"}, "answer": "D", "explanation": "高校学生工作主要包括学生教育、学生管理和学生服务三大方面。法律援助不属于高校学生工作的常规内容。"}, {"type": "单选", "num": 30, "text": "各层次、各部门在权力和责任方面的分工及相互关系，是大学的（ ）。", "options": {"A": "职能结构", "B": "层次结构", "C": "部门结构", "D": "职权结构"}, "answer": "D", "explanation": "职权结构是指组织中各层次、各部门在权力和责任方面的分工及相互关系。它规定了谁对谁负责、谁向谁汇报的权力链条。"}, {"type": "单选", "num": 31, "text": "大学完成自身使命和履行国家职责的先决条件是（ ）。", "options": {"A": "大学的全民化", "B": "大学的质量观", "C": "大学自治和学术自由", "D": "大学的多样化"}, "answer": "C", "explanation": "大学自治和学术自由是大学完成使命、履行国家职责的先决条件。没有学术自由，大学就无法探求真理、创新知识；没有大学自治，大学就无法按照自身规律发展。"}, {"type": "单选", "num": 32, "text": "高等学校的第一职能是（ ）。", "options": {"A": "科学研究", "B": "培养人才", "C": "国际合作", "D": "社会服务"}, "answer": "B", "explanation": "培养人才是高等学校的首要职能（第一职能），也是最根本的职能。科学研究和社会服务都是在此基础上衍生出来的。"}, {"type": "单选", "num": 33, "text": "形成性评价与终结性评价的主要差异在于（ ）。", "options": {"A": "评价目的不同", "B": "评价方法不同", "C": "评价内容不同", "D": "评价主体不同"}, "answer": "A", "explanation": "形成性评价与终结性评价的根本区别在于评价目的不同。形成性评价旨在改进教学过程、提供反馈，而终结性评价旨在判定最终学习结果、进行等级评定。"}, {"type": "单选", "num": 34, "text": "高校课程一般按学科分类或社会职业分工来设置，这说明高校课程具有鲜明的（ ）。", "options": {"A": "职业性", "B": "前沿性", "C": "专业性", "D": "探究性"}, "answer": "C", "explanation": "高校课程按学科或社会职业分工设置，体现的是专业性。专业性是高校课程区别于中小学课程的本质属性。"}, {"type": "单选", "num": 35, "text": "中国古代第一部专门的教育著作是（ ）。", "options": {"A": "《大学》", "B": "《论语》", "C": "《学记》", "D": "《礼记》"}, "answer": "C", "explanation": "《学记》是中国古代也是世界上最早的一篇专门论述教育和教学问题的论著，成文于战国晚期，是《礼记》中的一篇。"}, {"type": "单选", "num": 36, "text": "主张智力训练用\"智慧率领知识\"，把教育从死的知识和无活力的概念中解放出来的是（ ）。", "options": {"A": "萨特", "B": "纽曼", "C": "赫钦斯", "D": "怀特海"}, "answer": "D", "explanation": "怀特海（Alfred North Whitehead）在《教育的目的》中提出\"智慧率领知识\"的著名论断，认为教育的核心目的是培养智慧而非灌输死知识，反对\"无活力的概念\"。"}, {"type": "单选", "num": 37, "text": "高校教师是课程资源的（ ）。", "options": {"A": "组织者与管理者", "B": "引导者与协助者", "C": "开发者与拓展者", "D": "合作者与参与者"}, "answer": "C", "explanation": "在新课程改革背景下，教师不仅是课程的执行者，更是课程资源的开发者和拓展者。教师可以根据教学需要开发、整合和利用各种课程资源。"}, {"type": "单选", "num": 38, "text": "学术专业一直致力于建立知识操作的伦理规范，罗伯特·K.默顿提出了五项经典的科学规范，这些规范简称（ ）。", "options": {"A": "UADOS", "B": "KUDOS", "C": "CUDOS", "D": "CADOS"}, "answer": "C", "explanation": "默顿（Robert K. Merton）提出的科学精神气质的五个规范简称CUDOS：普遍主义（Universalism）、公有主义（Communism）、无私利性（Disinterestedness）、有条理的怀疑主义（Organized Skepticism）。"}, {"type": "单选", "num": 39, "text": "下列选项中不属于教师备课\"三备\"之说的是（ ）。", "options": {"A": "备教材", "B": "备学生", "C": "备手段", "D": "备方法"}, "answer": "C", "explanation": "教师备课的\"三备\"通常指：备教材（钻研教学内容）、备学生（了解学生情况）、备方法（选择教学方法和策略）。\"备手段\"不属于三备的经典表述。"}, {"type": "单选", "num": 40, "text": "大学初创且规模很小的阶段，通常采用的组织结构类型是（ ）。", "options": {"A": "职能制", "B": "直线职能制", "C": "矩阵结构", "D": "直线制"}, "answer": "D", "explanation": "直线制是最简单的组织结构形式，权力从上到下垂直领导，结构简单、权责明确、指挥统一，适合规模小、初创阶段的组织。"}, {"type": "单选", "num": 41, "text": "专家介入型教学发展模式中，教学专家的角色应根据不同阶段做出相应的改变。在初期，教学专家不能扮演的角色是（ ）。", "options": {"A": "顾问", "B": "专业人员", "C": "专家", "D": "好朋友"}, "answer": "D", "explanation": "在专家介入型教学发展模式的初期，专家扮演的是顾问、专业人员和专家的角色，为教师提供专业指导。\"好朋友\"是在后期阶段、与教师建立了信任关系后才能扮演的角色。"}, {"type": "单选", "num": 42, "text": "以\"塔克西拉\"和\"那烂陀\"为代表的高等教育学术中心，属于下列哪个国家？", "options": {"A": "古埃及", "B": "巴比伦", "C": "古印度", "D": "希伯来"}, "answer": "C", "explanation": "塔克西拉（Taxila）和那烂陀（Nalanda）是古印度著名的佛教高等教育中心，是早期高等教育机构的雏形，吸引了大批来自世界各地的学者。"}, {"type": "单选", "num": 43, "text": "课程编制总体包括三个逐级具体化的层次，其中不包括（ ）。", "options": {"A": "培养方案", "B": "课程标准", "C": "教材", "D": "社团活动"}, "answer": "D", "explanation": "课程编制逐级具体化的三个层次是：培养方案（课程计划）→课程标准（教学大纲）→教材。社团活动不属于课程编制的层次。"}, {"type": "单选", "num": 44, "text": "提出\"思想自由、兼容并包\"的办学方针，对北京大学进行改革的校长是（ ）。", "options": {"A": "梅贻琦", "B": "杨东平", "C": "李鸿章", "D": "蔡元培"}, "answer": "D", "explanation": "蔡元培在1917年出任北京大学校长后，提出\"思想自由、兼容并包\"的办学方针，对北大进行了一系列改革，使之成为中国现代大学的典范。"}, {"type": "单选", "num": 45, "text": "关于课程评价，泰勒提出了\"目标达成模式\"，该模式评价程序的核心是（ ）。", "options": {"A": "学生", "B": "教师", "C": "课程计划", "D": "课程目标"}, "answer": "D", "explanation": "泰勒目标达成模式的核心是课程目标。该模式以预先确定的课程目标为出发点和归宿，通过测量学生行为与目标的一致性程度来评价课程效果。"}, {"type": "单选", "num": 46, "text": "本土高等教育国际化的过程不包括（ ）。", "options": {"A": "高等院校面向国际化进行的组织转型、制度建设", "B": "高等学校教育教学过程的改革", "C": "政府层面的促进高等教育国际化的决策与规划", "D": "区域之间的交流合作过程"}, "answer": "D", "explanation": "本土高等教育国际化是指在本国境内进行的国际化活动（如课程国际化、制度国际化等），而区域之间的交流合作属于跨境教育（向外的国际化）范畴。"}, {"type": "单选", "num": 47, "text": "终身教育的思想作为一种重要的国际教育思潮，最早提出该思想的学者是（ ）。", "options": {"A": "康德尔", "B": "保罗·朗格朗", "C": "赞可夫", "D": "布鲁纳"}, "answer": "B", "explanation": "法国教育家保罗·朗格朗（Paul Lengrand）于1965年在联合国教科文组织会议上首次系统阐述了终身教育思想，被誉为\"终身教育之父\"。"}, {"type": "单选", "num": 48, "text": "高等教育的核心，办学的主体是（ ）。", "options": {"A": "管理人员", "B": "教师", "C": "学生", "D": "学科"}, "answer": "B", "explanation": "教材在论述大学组织要素时明确指出：“教师是高等学校的核心，是办学的主体。”教师的质量和水平对高等学校发展具有决定性作用。因此本题应选“教师”。"}, {"type": "单选", "num": 49, "text": "课程结构合理性以及课时安排合理性的评价属于（ ）。", "options": {"A": "培养目标评价", "B": "课程设置评价", "C": "课程目标评价", "D": "课程内容评价"}, "answer": "B", "explanation": "课程设置评价主要考察课程结构是否合理、课程安排是否科学、课时分配是否恰当等。课程结构合理性和课时安排都属于课程设置层面的评价内容。"}, {"type": "单选", "num": 50, "text": "高校管理权力大部分集中于学校行政管理人员手中，这种决策模式属于（ ）。", "options": {"A": "双重结合模式", "B": "复式组合模式", "C": "学术主导模式", "D": "行政主导模式"}, "answer": "D", "explanation": "行政主导模式是指行政权力在学校决策中占主导地位，权力集中于行政管理人员手中。学术主导模式则是学术人员在决策中居于主导地位。"}, {"type": "单选", "num": 51, "text": "从管理的视角而言，高校学生服务主要指入学服务、（ ）和就业服务等三个方面。", "options": {"A": "健康服务", "B": "升学服务", "C": "法律服务", "D": "学业服务"}, "answer": "D", "explanation": "高校学生服务主要包括入学服务（招生录取、入学注册）、学业服务（学习过程管理和学业评价管理）和就业服务（职业指导、就业推荐）三个方面。"}, {"type": "单选", "num": 52, "text": "学校组织、校园文化、师生相互作用对学生所产生的潜移默化的影响，我们称之为（ ）。", "options": {"A": "正式课程", "B": "非正式课程", "C": "显性课程", "D": "隐性课程"}, "answer": "D", "explanation": "隐性课程（Hidden Curriculum）是指学生在学校环境中无意识获得的、非正式的学习经验，包括校园文化、师生关系、学校制度等潜移默化的影响因素。"}, {"type": "单选", "num": 53, "text": "明确提出科学研究与教学相分离的学者是（ ）。", "options": {"A": "麦卡锡", "B": "纽曼", "C": "克拉克", "D": "洪堡"}, "answer": "B", "explanation": "纽曼在《大学的理想》中明确主张大学只应从事教学，不应进行科学研究，认为科研与教学应该分离。而洪堡则主张教学与科研相统一。"}, {"type": "单选", "num": 54, "text": "全面实行高等教育收费政策的年份是（ ）。", "options": {"A": "1998年", "B": "1999年", "C": "1996年", "D": "1997年"}, "answer": "D", "explanation": "1997年，我国全面实行高等教育收费政策，取消了公费生和自费生的双轨制，实行统一的招生收费制度。"}, {"type": "单选", "num": 55, "text": "高校组织结构类型中容易出现\"政出多门\"的是（ ）。", "options": {"A": "矩阵结构", "B": "直线职能制", "C": "职能制", "D": "直线制"}, "answer": "C", "explanation": "职能制按职能分工设置多个职能部门，各部门在各自业务范围内均可向下级下达指令，导致下级接受多头领导、无所适从，最容易出现\"政出多门\"。直线制权力集中、垂直指挥，绝无此问题。矩阵结构虽也有双重领导，但职能制是高校组织教材中论述\"政出多门\"的标准考点。"}, {"type": "单选", "num": 56, "text": "立法权力、政府权力、学术权力出现边界渗透，尤其是学术权威渗透到院校行政权力中，这种现象属于大学权力的（ ）。", "options": {"A": "等级结构的多样化", "B": "部门的多样化", "C": "权力非中心化", "D": "层次的多样化"}, "answer": "C", "explanation": "教材在说明大学权力主体多元化时指出，权力非中心化的突出表现就是边界渗透，尤其是学术权威渗透到院校官僚权力、行会权力、董事权力、政府权力和中介组织权力中。题干正强调这种边界渗透现象，因此应选“权力非中心化”。"}, {"type": "单选", "num": 57, "text": "傅勒的教师关注阶段论中，教师开始较多地关注教学所需的知识、能力与技巧，并尽可能运用到教学情境去，这一类教师所处的阶段是（ ）。", "options": {"A": "早期生存关注", "B": "教学前关注", "C": "关注学生", "D": "教学情境关注"}, "answer": "D", "explanation": "傅勒（Fuller）的教师关注阶段论将教师发展分为：教学前关注→早期生存关注→教学情境关注→关注学生。教学情境关注阶段，教师关心教学所需的知识、能力和技巧，关注自身教学表现。"}, {"type": "单选", "num": 58, "text": "校长办公会、校务委员会、学校董事会等属于大学的（ ）。", "options": {"A": "战略制定层", "B": "中间管理层", "C": "操作人员层", "D": "监督控制层"}, "answer": "A", "explanation": "根据组织理论，大学的战略制定层是最高决策层，负责制定学校的战略、政策和目标，校长办公会、校务委员会、校董事会等属于这一层次。"}, {"type": "单选", "num": 59, "text": "高校课程评价过程分为不同阶段，制订评价方案属于（ ）。", "options": {"A": "撰写报告阶段", "B": "形成结论阶段", "C": "资料收集阶段", "D": "准备阶段"}, "answer": "D", "explanation": "课程评价的准备阶段包括建立评价机构、制定评价方案、确定评价人员等。制订评价方案是准备阶段的中心环节。"}, {"type": "单选", "num": 60, "text": "下列哪项不属于职业中期教师发展关注的内容？", "options": {"A": "澄清学术职业的价值", "B": "调适退休焦虑", "C": "平衡工作与家庭责任", "D": "实现职业发展目标"}, "answer": "B", "explanation": "调适退休焦虑属于职业后期阶段（生涯晚期）关注的内容。职业中期教师主要关注澄清职业价值、平衡工作与家庭、实现职业发展目标等。"}, {"type": "单选", "num": 61, "text": "最早的专才教育开始于（ ）。", "options": {"A": "中世纪大学", "B": "近代大学", "C": "古埃及", "D": "古罗马"}, "answer": "A", "explanation": "中世纪大学设立文、法、神、医四科，培养牧师、教师、医生和官吏等专门人才，是专才教育的开端。"}, {"type": "单选", "num": 62, "text": "清华大学的校训是（ ）。", "options": {"A": "博学而笃志，切问而近思", "B": "自强不息、厚德载物", "C": "爱国进步 民主科学", "D": "实事求是"}, "answer": "B", "explanation": "清华大学的校训\"自强不息、厚德载物\"出自《周易》：\"天行健，君子以自强不息；地势坤，君子以厚德载物。\""}, {"type": "单选", "num": 63, "text": "个人本位论的源头可追溯到雅典的（ ）。", "options": {"A": "道德教育", "B": "美育教育", "C": "约束教育", "D": "自由教育"}, "answer": "D", "explanation": "个人本位论强调教育应促进个人身心自由发展，其源头可追溯到雅典的自由教育（Liberal Education），即强调人的自由和理性发展，而非职业训练。"}, {"type": "单选", "num": 64, "text": "政府部门推进高等教育国际化的主要手段是（ ）。", "options": {"A": "政策工具", "B": "经济手段", "C": "宏观调控", "D": "学术资本"}, "answer": "A", "explanation": "政府部门主要通过制定政策、法规、规划等政策工具来推进高等教育国际化，如出台留学政策、学位互认协定、国际合作项目等。"}, {"type": "单选", "num": 65, "text": "《中华人民共和国中外合作办学条例》颁布实施的年份是（ ）。", "options": {"A": "2003年", "B": "2007年", "C": "2010年", "D": "2016年"}, "answer": "A", "explanation": "《中华人民共和国中外合作办学条例》于2003年3月1日颁布，2003年9月1日起正式施行。"}, {"type": "单选", "num": 66, "text": "高校的根本任务是培养各级各类专门人才，高等教育价值实现的程度，主要取决于人才培养的（ ）。", "options": {"A": "方式", "B": "质量", "C": "经费", "D": "条件"}, "answer": "B", "explanation": "高等教育价值的实现程度主要取决于人才培养的质量。质量是高等教育发展的生命线，没有质量就没有价值。"}, {"type": "单选", "num": 67, "text": "世界上第一个进入大众高等教育的国家是（ ）。", "options": {"A": "加拿大", "B": "英国", "C": "美国", "D": "澳大利亚"}, "answer": "C", "explanation": "美国是世界上第一个进入大众高等教育阶段的国家。二战结束后，通过《退伍军人权利法案》等一系列政策，美国高等教育毛入学率率先突破15%。"}, {"type": "单选", "num": 68, "text": "首先打破大学内部思想学术封闭性的是（ ）。", "options": {"A": "大学推广运动", "B": "新大学运动", "C": "启蒙运动", "D": "中世纪大学"}, "answer": "C", "explanation": "教材在论述大学理念历史发展时指出，首先打破大学内部思想学术封闭性的是启蒙运动者。启蒙运动推动哲学自由和思想解放，为近代大学理念转变提供了重要条件。"}, {"type": "单选", "num": 69, "text": "高校教师工作的真正对象是（ ）。", "options": {"A": "教学活动", "B": "学生的学习活动", "C": "文本知识", "D": "课本教材"}, "answer": "B", "explanation": "教材指出，教师工作的真正对象不是文本知识，也不是课本教材，而是学生的学习活动。教师的备课、讲授、辅导和评价都应围绕促进学生学习展开。"}, {"type": "单选", "num": 70, "text": "高校绿色\"GDP\"质量发展观的一个核心是（ ）。", "options": {"A": "着眼于高校毕业生的就业率", "B": "重视科研产出", "C": "教授担任本科教学工作", "D": "着眼于高校和人的可持续发展"}, "answer": "D", "explanation": "高校绿色\"GDP\"质量发展观强调可持续发展，着眼于高校自身的可持续发展和人的全面发展，反对片面追求数量指标。"}, {"type": "单选", "num": 71, "text": "跨学科课程是指促进学生在高度专业化基础上的高度综合，使学生能够横跨几科，融会贯通。下列不属于跨学科课程的是（ ）。", "options": {"A": "应用科学与技术", "B": "思想政治", "C": "社会与哲学", "D": "数学与逻辑"}, "answer": "B", "explanation": "思想政治属于独立的学科领域，通常不归入跨学科课程。应用科学与技术、社会与哲学、数学与逻辑均涉及多学科的交叉融合。"}, {"type": "单选", "num": 72, "text": "激烈反对大学\"下嫁\"的思想家是（ ）。", "options": {"A": "杜威", "B": "纽曼", "C": "怀特海", "D": "赫钦斯"}, "answer": "D", "explanation": "美国永恒主义教育思想家赫钦斯（R. Hutchins）激烈批判大学功利化，反对大学迎合社会的庸俗需求，将其斥为大学的\"下嫁\"或\"向社会献媚\"。他主张大学应坚守理性教育和永恒真理。"}, {"type": "单选", "num": 73, "text": "在我国，高等教育被定义为\"建立在普通教育基础上的专业性教育\"，因此通识教育和专业教育的关系是（ ）。", "options": {"A": "递进关系", "B": "下位关系", "C": "上位关系", "D": "并列关系"}, "answer": "B", "explanation": "教材在讨论通识教育与专业教育关系时指出，在我国“高等教育是建立在普通教育基础上的专业性教育”的语境下，通识教育是在专业教育之下进行的，专业教育是通识教育的上位概念。因此本题应选“下位关系”。"}, {"type": "单选", "num": 74, "text": "在学生学习新知识之前进行摸底考试，初步了解学生已有的知识基础和有关能力。这种考试属于（ ）。", "options": {"A": "总结性评价", "B": "相对性评价", "C": "定位性评价", "D": "诊断性评价"}, "answer": "C", "explanation": "定位性评价（Placement Evaluation）是在教学开始前为摸清学生现有水平、确定教学起点或分班而进行的\"摸底\"评价。诊断性评价虽也在前期进行，但其核心是\"查明学习困难的原因\"，而单纯的摸底和了解起点属于\"定位性评价\"。"}, {"type": "单选", "num": 75, "text": "学校教育的基本方式与途径是（ ）。", "options": {"A": "课堂教学", "B": "社团活动", "C": "企业实践", "D": "科研活动"}, "answer": "A", "explanation": "课堂教学是学校教育最基本、最主要的方式和途径。其他形式（社团、实践、科研）都是课堂教学的补充和延伸。"}, {"type": "单选", "num": 76, "text": "根据培养方案以纲要的形式编订的，有关课程教学内容的目的、结构与教学要求的纲领性文件是（ ）。", "options": {"A": "课程内容", "B": "课程标准", "C": "课程目标", "D": "课程体系"}, "answer": "B", "explanation": "课程标准（教学大纲）是以纲要形式编订的，规定课程的教学目的、内容结构、教学要求的纲领性文件，是教师教学和学生学习的基本依据。"}, {"type": "单选", "num": 77, "text": "美国高等学校资源配置的主要手段是（ ）。", "options": {"A": "政府调控", "B": "市场调节", "C": "第三方机构操控", "D": "政府调控与市场调节"}, "answer": "B", "explanation": "教材在比较各国高校管理模式时指出，美国高校管理受市场力量影响突出，市场是美国高等学校资源配置的主要手段。政府虽有调控作用，但题干问“主要手段”，应选市场调节。"}, {"type": "单选", "num": 78, "text": "课程活动连续互动模式的提出者是（ ）。", "options": {"A": "麦克唐纳", "B": "博比特", "C": "斯基尔贝克", "D": "斯坦豪斯"}, "answer": "A", "explanation": "课程活动连续互动模式强调课程系统中各要素之间的持续互动和动态平衡。该模式由美国课程学者塞勒（J. G. Saylor）和亚历山大（W. M. Alexander）在《课程规划》中提出，而非题目选项中的人员。题目选项中的\"麦克唐纳\"（Macdonald）亦曾提出类似连续互动理念。本题如按给定选项，选择A较为合适。"}, {"type": "单选", "num": 79, "text": "以群体的关系结构和组织功能为标准，大学生群体在组织结构上可分（ ）。", "options": {"A": "优生群体和差生群体", "B": "男生群体和女生群体", "C": "正式群体和非正式群体", "D": "区域群体和兴趣群体"}, "answer": "C", "explanation": "以关系结构和组织功能划分，大学生群体可分为正式群体（如班级、党支部、团支部）和非正式群体（如兴趣社团、同乡会等）。"}, {"type": "单选", "num": 80, "text": "首次提出了\"看不见的手原理\"的经济学著作是（ ）。", "options": {"A": "《纯粹经济学要义》", "B": "《资本论》", "C": "《政治经济学与赋税原理》", "D": "《国民财富的性质与原因研究》"}, "answer": "D", "explanation": "亚当·斯密（Adam Smith）在1776年出版的《国民财富的性质与原因的研究》（即《国富论》）中首次提出了\"看不见的手\"原理。"}, {"type": "单选", "num": 81, "text": "经济学领域\"看不见的手原理\"的提出者是（ ）。", "options": {"A": "亚当·斯密", "B": "凯恩斯", "C": "大卫·李嘉图", "D": "萨缪尔森"}, "answer": "A", "explanation": "\"看不见的手\"原理由亚当·斯密提出，指市场机制在价格引导下自发调节资源配置，使个人追求私利的行为最终促进社会公共利益。"}, {"type": "单选", "num": 82, "text": "西周时期的学校教育制度包括\"国学\"与（ ）。", "options": {"A": "\"乡学\"", "B": "\"私学\"", "C": "\"太学\"", "D": "\"私塾\""}, "answer": "A", "explanation": "西周时期的教育制度分为国学和乡学两级。国学设在王都，乡学设在地方。私学出现在春秋时期，太学始于汉代。"}, {"type": "单选", "num": 83, "text": "对教学评估表现优秀的基层教学单位予以嘉奖，对学业优异的学生授予荣誉，这体现教学质量保障的（ ）功能。", "options": {"A": "支持", "B": "激励", "C": "监控与评价", "D": "质量保障"}, "answer": "B", "explanation": "教学质量保障的激励功能，是指通过奖励、荣誉、表彰等方式调动基层教学单位、教师和学生改进教学与学习的积极性。题干中的“予以嘉奖”“授予荣誉”都属于正向激励，因此体现的是激励功能。"}, {"type": "单选", "num": 84, "text": "高校课程编制中，确定专业培养目标的主要依据不包括（ ）。", "options": {"A": "专业的发展", "B": "学费水平", "C": "当代社会生活的需要", "D": "学习者的需要"}, "answer": "B", "explanation": "确定专业培养目标的主要依据通常包括社会发展和当代社会生活的需要、学科专业发展的需要以及学习者发展的需要。选项A“专业的发展”、C“当代社会生活的需要”、D“学习者的需要”都属于依据；B“学费水平”属于经费或收费因素，不是确定专业培养目标的主要依据。因此本题选B。"}, {"type": "单选", "num": 85, "text": "关于教学方法，下列说法错误的是（ ）。", "options": {"A": "教学方法直接影响教师教学工作的效能", "B": "教学方法是教法和学法的有机结合和统一", "C": "间接关系着教学目标达到的程度", "D": "直接关系着教学工作的进度"}, "answer": "C", "explanation": "教学方法直接关系着教学目标达到的程度。教学方法的选择和运用直接影响到教学效果和目标达成度，而非间接关系。"}, {"type": "单选", "num": 86, "text": "大学组织各管理部门的构成，即大学组织的横向结构，又称为（ ）。", "options": {"A": "职权结权", "B": "部门结构", "C": "层次结构", "D": "职能结构"}, "answer": "B", "explanation": "部门结构是组织横向划分的管理部门及其相互关系。大学组织按职能设置不同的部门（教务处、科研处、人事处等），构成横向的部门结构。"}, {"type": "单选", "num": 87, "text": "高等教育发展的核心任务是（ ）。", "options": {"A": "提高整体质量", "B": "加快大众化进程", "C": "扩大教学规模", "D": "增加教学人数"}, "answer": "A", "explanation": "《国家中长期教育改革和发展规划纲要（2010-2020年）》明确提出，提高质量是高等教育发展的核心任务，是建设高等教育强国的基本要求。"}, {"type": "单选", "num": 88, "text": "高校质量文化应该体现的特征不包括（ ）。", "options": {"A": "宽松自由", "B": "以人为本", "C": "个性创新", "D": "国际交流"}, "answer": "D", "explanation": "高校质量文化的主要特征包括：宽松自由（学术氛围）、以人为本（以师生为中心）、个性创新（追求特色和卓越）。国际交流是高等教育国际化的内容，而非质量文化的特征。"}, {"type": "单选", "num": 89, "text": "营利性高等教育发展最具规模和特色的国家是（ ）。", "options": {"A": "美国", "B": "澳大利亚", "C": "英国", "D": "加拿大"}, "answer": "A", "explanation": "美国是世界上营利性高等教育最发达的国家，以凤凰城大学（University of Phoenix）为代表的营利性大学规模庞大、特色鲜明。"}, {"type": "单选", "num": 90, "text": "下列选项中不属于案例教学法的特点的是（ ）。", "options": {"A": "加强学生的分析能力和解决问题的能力", "B": "减少课堂时间", "C": "提高学生互动能力、团队工作能力", "D": "学生对某一问题有多角度探讨，促进深度学习"}, "answer": "B", "explanation": "案例教学法通常需要更多时间进行案例讨论和分析，而不是减少课堂时间。其他三项都是案例教学法的优点。"}, {"type": "单选", "num": 91, "text": "以下关于学生学习成果评估的特点说法不正确的是（ ）。", "options": {"A": "以学生为中心的价值理念", "B": "参与学生学习结果评价的组织和机构十分广泛", "C": "评价方法多样化", "D": "本土化的测评工具较多"}, "answer": "D", "explanation": "学生学习成果评估中，本土化的测评工具并不多。相反，国际上使用较多的是标准化的测评工具（如CLA、CAT等），本土化工具的开发仍处于发展阶段。"}, {"type": "单选", "num": 92, "text": "关于高等教育国际化的活动类型，下列说法错误的是（ ）。", "options": {"A": "跨境教育包括人员流动、机构流动与项目流动", "B": "本土高等教育国际化属于跨境教育", "C": "向外的国际化主要指跨境教育", "D": "高等教育国际化包括向外的国际化与向内的国际化"}, "answer": "B", "explanation": "本土高等教育国际化（如课程国际化、校园国际化等）是在本国境内进行的国际化活动，不属于跨境教育。跨境教育指跨越国界的教育服务。"}, {"type": "单选", "num": 93, "text": "高等学校的根本任务是（ ）。", "options": {"A": "服务社会", "B": "校企合作", "C": "培养人才", "D": "发展科学"}, "answer": "C", "explanation": "培养人才是高等学校的根本任务。《高等教育法》明确规定，高等教育的任务是培养具有创新精神和实践能力的高级专门人才。"}, {"type": "单选", "num": 94, "text": "下列哪一选项不是古希腊的\"七艺\"教育？", "options": {"A": "几何", "B": "文法", "C": "美术", "D": "音乐"}, "answer": "C", "explanation": "古希腊\"七艺\"包括\"三艺\"（文法、修辞、辩证法）和\"四艺\"（算术、几何、天文、音乐）。美术不属于\"七艺\"。"}, {"type": "单选", "num": 95, "text": "工具主义大学理念的代表人物是（ ）。", "options": {"A": "科尔", "B": "杜威", "C": "萨特", "D": "科南特"}, "answer": "A", "explanation": "科尔（Clark Kerr）在其著作《大学的功用》中提出了\"多元化巨型大学\"的概念，主张大学应服务于社会的多种需求，是工具主义的典型代表。"}, {"type": "单选", "num": 96, "text": "早期科学教育思想产生于英国，代表人物是被人们誉为\"近代科学之父\"的（ ）。", "options": {"A": "康德", "B": "斯宾塞", "C": "赫尔巴特", "D": "培根"}, "answer": "D", "explanation": "弗朗西斯·培根（Francis Bacon）被誉为\"近代科学之父\"，他提出\"知识就是力量\"的著名论断，倡导科学实验和归纳法。"}, {"type": "单选", "num": 97, "text": "学生评价在教育评价活动中处于（ ）。", "options": {"A": "核心地位", "B": "基础性地位", "C": "主要地位", "D": "重要地位"}, "answer": "A", "explanation": "教材在“高校学生评价”部分明确指出，学生评价是教育评价学科最基本的探究领域，在教育评价活动中处于核心地位。它不仅引导学生发展，也影响学校办学水平和人才培养质量。"}, {"type": "单选", "num": 98, "text": "高校学生的学习能力主要表现为（ ）。", "options": {"A": "自我评价能力和分工合作能力", "B": "自我管理能力和交往沟通能力", "C": "自我设计能力和组织协调能力", "D": "自主学习能力和合作学习能力"}, "answer": "D", "explanation": "高校学生的学习能力主要表现为自主学习能力（独立获取知识、自我管理学习）和合作学习能力（与他人协作、团队学习）。这是高等教育阶段最重要的学习能力。"}, {"type": "单选", "num": 99, "text": "提出\"知识就是力量\"的学者是（ ）。", "options": {"A": "赫钦斯", "B": "洪堡", "C": "纽曼", "D": "培根"}, "answer": "D", "explanation": "培根（Francis Bacon）在其著作中提出了\"Knowledge is power\"（知识就是力量）的著名论断，对近代科学和教育发展产生了深远影响。"}, {"type": "单选", "num": 100, "text": "大学的科研机构承担项目研究时，成立临时办公室完成某项任务，这些人既受中心的领导，又接受原来部门的指挥。这种组织结构类型属于（ ）。", "options": {"A": "职能制", "B": "直线制", "C": "矩阵结构", "D": "直线职能制"}, "answer": "C", "explanation": "矩阵结构的特点是在垂直领导系统的基础上，增加了横向的项目管理系统，员工同时接受职能部门和项目组的双重领导。题目描述的正是矩阵结构。"}, {"type": "单选", "num": 101, "text": "高等学校培养目标是要解决什么问题？", "options": {"A": "怎样培养人", "B": "培养什么样的人", "C": "为什么培养人", "D": "培养方案制定"}, "answer": "B", "explanation": "培养目标回答的是\"培养什么样的人\"的问题，即人才培养的规格和质量标准。\"怎样培养人\"是培养方式的问题，\"为什么培养人\"是教育目的的问题。"}, {"type": "单选", "num": 102, "text": "一般情况下，小组教学特别适用于课程教学的哪个阶段？", "options": {"A": "初期阶段", "B": "中期阶段", "C": "后期阶段", "D": "过渡阶段"}, "answer": "B", "explanation": "小组教学要求学生已具备一定基础知识（不宜在初期），又需要在总结冲刺前进行充分讨论与碰撞（不宜在后期），因此在课程教学的中期阶段开展最为合理。"}, {"type": "单选", "num": 103, "text": "高效管理人员研究生专业学位越来越多，高等教育行政管理逐渐成为一种职业，这反映了高校管理人员的（ ）。", "options": {"A": "忠诚性", "B": "学术性", "C": "专业性", "D": "行政性"}, "answer": "C", "explanation": "高等教育管理逐渐专业化和职业化，管理人员攻读专业学位、提升专业素养，体现了管理人员的专业性特征。"}, {"type": "单选", "num": 104, "text": "不属于教学手段的是（ ）。", "options": {"A": "多媒体教学", "B": "幻灯片", "C": "录像带", "D": "实验"}, "answer": "D", "explanation": "教学手段是教师在教学过程中使用的物质工具和媒介，如多媒体、幻灯片、录像带等。实验是一种教学方法，而非教学手段。"}, {"type": "单选", "num": 105, "text": "被誉为\"课程评价之父\"的学者是（ ）。", "options": {"A": "斯滕豪斯", "B": "博比特", "C": "泰勒", "D": "波斯纳"}, "answer": "C", "explanation": "拉尔夫·泰勒（Ralph Tyler）被称为\"课程评价之父\"，他提出了\"目标达成评价模式\"，奠定了现代课程评价理论的基础。"}, {"type": "单选", "num": 106, "text": "学籍管理是高校管理的重要内容，需要把好的三个关键性环节是新生入学审核、学习过程考核和（ ）。", "options": {"A": "出国留学审核", "B": "转学或转学业审核", "C": "奖学金评定审核", "D": "毕业资格审核"}, "answer": "D", "explanation": "学籍管理的三个关键环节是：入口（新生入学审核）、过程（学习过程考核）和出口（毕业资格审核）。"}, {"type": "单选", "num": 107, "text": "具体描述专业培养目标和培养规格的规范性文件是（ ）。", "options": {"A": "培养方案", "B": "课程标准", "C": "教学计划", "D": "课程计划"}, "answer": "A", "explanation": "培养方案（原称教学计划）是高等学校根据专业培养目标制定的、具体描述培养目标和培养规格的规范性文件，是组织教学的基本依据。"}, {"type": "单选", "num": 108, "text": "职业型人才在培养过程中强调知识的（ ）。", "options": {"A": "技术性或应用性", "B": "理论性或系统性", "C": "基础性或系统性", "D": "学术性或理论性"}, "answer": "A", "explanation": "职业型人才注重实际应用能力，在培养过程中强调知识的技术性和应用性，侧重解决实际问题的能力。"}, {"type": "单选", "num": 109, "text": "实现高等学校的基本职能的基础是（ ）。", "options": {"A": "教学", "B": "科研", "C": "社会服务", "D": "知识"}, "answer": "D", "explanation": "知识是高等学校一切活动的基础。高校以知识为工作对象，通过知识的传授、生产、传播和应用来实现人才培养、科学研究和为社会服务三大职能。"}, {"type": "单选", "num": 110, "text": "在某项教学活动的进程中，教师为使教学活动效果更好而不断进行评价，这种评价的类型属于（ ）。", "options": {"A": "相对性评价", "B": "标准化评价", "C": "总结性评价", "D": "形成性评价"}, "answer": "D", "explanation": "形成性评价是在教学过程中进行的评价，目的是及时发现问题、改进教学、提高效果。它与总结性评价（教学结束后进行）根本区别在于评价目的不同。"}, {"type": "单选", "num": 111, "text": "在科研管理中，调动教师的科研自由，尊重教师在科研中的主体地位，这体现了科研管理的（ ）。", "options": {"A": "重点性原则", "B": "协调性原则", "C": "公平性原则", "D": "自主性原则"}, "answer": "D", "explanation": "自主性原则强调尊重科研人员的主体地位和学术自由，给予教师充分的科研自主权。调动科研自由、尊重主体地位正是自主性原则的体现。"}, {"type": "单选", "num": 112, "text": "加强和改进大学生思想政治教育工作，深入进行树立正确的世界观、人生观和价值观教育的核心是（ ）。", "options": {"A": "公民道德教育", "B": "社会主义荣辱观教育", "C": "理想信念教育", "D": "民族精神教育"}, "answer": "C", "explanation": "理想信念教育是大学生思想政治教育的核心。引导大学生树立正确的世界观、人生观和价值观，首先解决的是理想信念这一根本问题。"}, {"type": "单选", "num": 113, "text": "德国现代教育的奠基人是（ ）。", "options": {"A": "洪堡", "B": "怀特海", "C": "纽曼", "D": "费希特"}, "answer": "A", "explanation": "洪堡（Wilhelm von Humboldt）创办柏林大学，提出\"教学与研究相统一\"原则，奠定了德国现代教育和大学制度的基础。"}, {"type": "单选", "num": 114, "text": "明确将\"全面提高高等教育质量\"作为21世纪第二个十年高等教育改革与发展的目标的文件是（ ）。", "options": {"A": "《2000年中国教育绿皮书》", "B": "《中共中央、国务院关于深化教育改革全面推进素质教育的决定》", "C": "《面向21世纪教育振兴行动计划》", "D": "《国家中长期教育改革和发展规划纲要（2010-2020年）》"}, "answer": "D", "explanation": "《国家中长期教育改革和发展规划纲要（2010-2020年）》明确提出\"全面提高高等教育质量\"是21世纪第二个十年高等教育改革发展的核心任务。"}, {"type": "单选", "num": 115, "text": "全面素质教育以人的综合素质，尤其以人的（ ）和实践能力为质量标准。", "options": {"A": "创新能力", "B": "创造能力", "C": "操作能力", "D": "动手能力"}, "answer": "A", "explanation": "全面素质教育以人的综合素质为质量标准，特别强调创新精神和实践能力。创新是一个民族进步的灵魂，也是素质教育的重点。"}, {"type": "单选", "num": 116, "text": "建立了人际关系学说，使得管理活动从\"以物为中心\"的管理转变为\"以人为中心\"的学者是（ ）。", "options": {"A": "福柯", "B": "梅奥", "C": "霍桑", "D": "卡拉克"}, "answer": "B", "explanation": "乔治·梅奥（George Mayo）通过霍桑实验建立了人际关系学说，提出管理要重视人的因素，实现了从\"以物为中心\"向\"以人为中心\"的转变。"}, {"type": "单选", "num": 117, "text": "高等教育国际化中跨境教育的形式不包括（ ）。", "options": {"A": "项目流动", "B": "开设双语课程", "C": "人员流动", "D": "机构流动"}, "answer": "B", "explanation": "跨境教育的主要形式有：人员流动（学生、教师跨国交流）、项目流动（合作办学项目）和机构流动（海外分校设立）。开设双语课程属于本土国际化，不属于跨境教育。"}, {"type": "单选", "num": 118, "text": "在官学中，古代中国的最高学府是（ ）。", "options": {"A": "白鹿洞书院", "B": "鸿都门学", "C": "太学和国子监", "D": "辟雍和泮宫"}, "answer": "C", "explanation": "太学和国子监是古代中国的最高学府。太学始于汉代，国子监始于隋代，两者都是中央官学的最高层级。白鹿洞书院是宋代著名的私立书院。"}, {"type": "单选", "num": 119, "text": "关于教学方法的选择的依据，下列说法错误的是（ ）。", "options": {"A": "根据学习方法的功能和类型", "B": "依据师生的条件与特点", "C": "依据教学内容", "D": "依据教学的目的和任务"}, "answer": "A", "explanation": "教学方法选择的依据主要包括：教学目的和任务、教学内容特点、师生条件与特点。以学习方法的功能和类型作为依据是本末倒置的说法。"}, {"type": "单选", "num": 120, "text": "学术型人才在培养过程中强调知识的（ ）。", "options": {"A": "理论性和实践性", "B": "理论性和系统性", "C": "职业性和技术性", "D": "应用性和技术性"}, "answer": "B", "explanation": "学术型人才侧重于理论知识的学习和研究能力的培养，强调知识的理论性和系统性，注重学科的理论基础和知识体系的完整性。"}, {"type": "单选", "num": 121, "text": "确定国家建立以财政拨款为主、其他多种渠道筹措高等教育经费为辅的体制。明确上述内容的文件是（ ）。", "options": {"A": "《中华人民共和国高等教育法》", "B": "《中国教育改革和发展纲要》", "C": "《面向21世纪教育振兴行动计划》", "D": "《国家中长期教育改革和发展规划纲要（2010-2020年）》"}, "answer": "A", "explanation": "《高等教育法》第六十条明确规定：\"国家建立以财政拨款为主、其他多种渠道筹措高等教育经费为辅的体制。\"1993年的《纲要》最早提出了构想方向，但以国家法律形式正式\"确定\"该体制的是1998年颁布的《高等教育法》。题干强调\"确定\"，故应选《高等教育法》。"}, {"type": "单选", "num": 122, "text": "从课程的表现形式或影响学生的方式看，可以把课程分为（ ）。", "options": {"A": "显性课程与隐性课程", "B": "学科课程与活动课程", "C": "基础课程与拓展课程", "D": "必修课程和选修课程"}, "answer": "A", "explanation": "按表现形式或影响方式，课程分为显性课程（有明确计划的课程）和隐性课程（潜移默化影响的课程）。"}, {"type": "单选", "num": 123, "text": "未借助教学专家的帮助，由教师群体的努力实现教师教学发展的教学发展模式，属于（ ）。", "options": {"A": "教师群体自助互动型教学发展模式", "B": "教师群体互动型教学发展模式", "C": "无专家介入型教学发展模式", "D": "专家介入型教学发展模式"}, "answer": "A", "explanation": "教材指出，可以按照“是否借助教学专家的帮助”为标准，将教学发展模式划分为两类：教师群体自助互动型教学发展模式和专家介入型教学发展模式。题干强调“未借助教学专家的帮助，由教师群体的努力实现”，对应的正是教师群体自助互动型教学发展模式。"}, {"type": "单选", "num": 124, "text": "高等教育国际化的行动主体是（ ）。", "options": {"A": "国家", "B": "高等教育机构", "C": "民族国家以及高等教育机构", "D": "民族"}, "answer": "C", "explanation": "高等教育国际化的行动主体是民族国家以及高等教育机构。国家层面进行政策制定和宏观推动，高校层面具体实施国际化活动。"}, {"type": "单选", "num": 125, "text": "收集、整理教学资源，研究教育教学技巧，借助各种计划、培训活动支持和帮助高校教师提升教学能力的机构是（ ）。", "options": {"A": "科研服务中心", "B": "教学发展中心", "C": "社会服务中心", "D": "国际交流中心"}, "answer": "B", "explanation": "教学发展中心（或教师教学发展中心）是专门为促进教师教学能力提升而设立的机构，提供教学资源、培训、咨询等服务。"}, {"type": "单选", "num": 126, "text": "将运作责任而不是决策责任交给下级部门，下级有责无权，属于分权形式的（ ）。", "options": {"A": "权力的下放", "B": "权力的分散", "C": "权力非中心化", "D": "权力的委托"}, "answer": "B", "explanation": "教材把高校权力分散列为分权的一种形式，其含义是将运作责任而不是决策责任交给下级部门，下级有责无权。题干所述正是“权力的分散”，不是权力下放或权力委托。"}, {"type": "单选", "num": 127, "text": "高校科研评价一般把精确的绩效指标数据作为分析、评价的基础，据此系统地准确地评价科研工作的实施情况及成果。这反映了（ ）。", "options": {"A": "科研评价的量化性", "B": "科研评价具有管理咨询的性质", "C": "科研评价具有民主性", "D": "科研评价发展的历史性"}, "answer": "A", "explanation": "以精确的绩效指标数据进行评价，体现的是科研评价的量化性特征，强调用数据和指标来客观衡量科研工作的成效。"}, {"type": "单选", "num": 128, "text": "下面哪项内容是价值层面的大学精神文化？", "options": {"A": "教风", "B": "校风", "C": "学风", "D": "校训"}, "answer": "D", "explanation": "校训属于价值层面的大学精神文化，它以精炼的语言表达了大学的价值观和办学理念。教风、校风、学风属于实践层面的精神文化。"}, {"type": "单选", "num": 129, "text": "认为大学有责任用自己的知识为社会提供服务的大学理念是（ ）。", "options": {"A": "实用主义", "B": "国家主义", "C": "永恒主义", "D": "理性主义"}, "answer": "A", "explanation": "实用主义大学理念强调大学有责任运用知识为社会服务，关注知识的实用价值和社会效益，典型代表是\"威斯康星理念\"。"}, {"type": "单选", "num": 130, "text": "高校教师最基本最重要的工作是（ ）。", "options": {"A": "管理", "B": "科研", "C": "德育", "D": "教学"}, "answer": "D", "explanation": "教学是高校教师最基本、最重要的工作。作为教师，教书育人是天职，教学是教师首要的职责。"}, {"type": "单选", "num": 131, "text": "体现高校教学的专业性、学术性、创新性的过程的是（ ）。", "options": {"A": "科学研究", "B": "学术报告", "C": "教学成果", "D": "教学设计"}, "answer": "D", "explanation": "教材原文指出，教学设计是当代教师的基本专业技能，是体现高校教学专业性、学术性、创新性的过程。题干所问正对应“教学设计”。"}, {"type": "单选", "num": 132, "text": "以下组织属于大学生非正式群体的是（ ）。", "options": {"A": "兴趣社团", "B": "党支部", "C": "团支部", "D": "班级"}, "answer": "A", "explanation": "非正式群体是基于共同兴趣、爱好或需要自发形成的群体。兴趣社团是典型的非正式群体。党支部、团支部、班级属于正式群体。"}, {"type": "单选", "num": 133, "text": "1966年，联合国教科文组织和国际劳工组织在《关于教师地位的建议》中提出了应该把教师工作视为（ ）。", "options": {"A": "独立的社会职业", "B": "非独立的社会职业", "C": "非专门职业", "D": "专门职业"}, "answer": "D", "explanation": "1966年联合国教科文组织和国际劳工组织在《关于教师地位的建议》中明确提出，教师工作应被视为一种专门职业（Profession），具有专业性和不可替代性。"}, {"type": "单选", "num": 134, "text": "从高等学校职能发展来看，研究型大学始于（ ）。", "options": {"A": "巴黎大学", "B": "柏林大学", "C": "约翰·霍普金斯大学", "D": "哥廷根大学"}, "answer": "B", "explanation": "从高等学校职能发展来看，1810年成立的柏林大学提出教学与研究相统一，开启了研究型大学的未来。约翰·霍普金斯大学是美国研究型大学的重要代表，但不是世界研究型大学的起点。"}, {"type": "单选", "num": 135, "text": "当代高等教育国际化的第一推手是（ ）。", "options": {"A": "学术化", "B": "全球化", "C": "产业化", "D": "市场化"}, "answer": "B", "explanation": "经济全球化是当代高等教育国际化的第一推手。全球化促进了人才、资本、信息的跨国流动，推动了高等教育的国际化进程。"}, {"type": "单选", "num": 136, "text": "赫钦斯是20世纪理性主义大学理念的代表人物和集大成者，他的教育哲学思想属于（ ）。", "options": {"A": "永恒主义", "B": "要素主义", "C": "存在主义", "D": "实用主义"}, "answer": "A", "explanation": "赫钦斯（Robert Hutchins）是永恒主义教育哲学的代表人物，主张大学应教授永恒真理，强调经典著作的阅读和理智训练，反对功利主义和职业化倾向。"}, {"type": "单选", "num": 137, "text": "大学不是一个温度计，不应对社会每一流行风尚都要做出反应。持这种观点的学者是（ ）。", "options": {"A": "杜威", "B": "赫钦斯", "C": "弗莱克斯纳", "D": "纽曼"}, "answer": "C", "explanation": "现代高等教育学泰斗弗莱克斯纳（A. Flexner）在《大学：美国、英国、德国》中指出：\"大学不是一个温度计，不应对社会每一流行风尚都要做出反应。\"该名言在高等教育学权威文献中归属弗莱克斯纳。"}, {"type": "单选", "num": 138, "text": "由学生所在学校的教师编制、实施和评价的课程是（ ）。", "options": {"A": "学科课程", "B": "核心课程", "C": "校本课程", "D": "综合课程"}, "answer": "C", "explanation": "校本课程（School-based Curriculum）是由学校教师根据本校实际情况编制、实施和评价的课程，体现学校的办学特色和自主权。"}, {"type": "单选", "num": 139, "text": "联邦德国为代表的欧洲大陆国家，表现的高校管理模式是（ ）。", "options": {"A": "官僚学术权威双元管理模式", "B": "国家权威模式", "C": "市场主导模式", "D": "学术权威模式"}, "answer": "A", "explanation": "教材指出，以联邦德国为代表的欧洲大陆国家，表现出典型的官僚、学术权威双元管理模式：一方面有国家和行政体系的官僚管理，另一方面保留大学内部的学术权威。"}, {"type": "单选", "num": 140, "text": "\"所谓大学者，非谓大楼之谓也，也有大师之谓也\"，提出这个观点的教育家是（ ）。", "options": {"A": "梅贻琦", "B": "蒋梦麟", "C": "胡适", "D": "蔡元培"}, "answer": "A", "explanation": "梅贻琦在就任清华大学校长时发表了\"大学者，非谓有大楼之谓也，有大师之谓也\"的著名言论，强调大师对大学的重要性。"}, {"type": "单选", "num": 141, "text": "美国教育家帕克认为，\"一切教育的真正目的，是人，即人的身体、思想和灵魂的和谐发展\"。这种教育目的观属于（ ）。", "options": {"A": "个人本位论", "B": "社会本位论", "C": "生活本位论", "D": "文化本位论"}, "answer": "A", "explanation": "个人本位论主张教育目的应以促进个人发展为根本，强调人的身体、思想和灵魂的和谐发展。帕克的观点正是个人本位论的典型表述。"}, {"type": "单选", "num": 142, "text": "按照美国学者古德莱德的课程层次理论，由教育行政部门规定的课程计划、课程标准和教材等属于（ ）。", "options": {"A": "经验课程", "B": "正式课程", "C": "领悟课程", "D": "运作课程"}, "answer": "B", "explanation": "古德莱德课程五层次：理念课程→正式课程→领悟课程→运作课程→经验课程。正式课程是指由教育行政部门规定的课程计划、课程标准和教材。"}, {"type": "单选", "num": 143, "text": "美国的威斯康星大学之所以形成了风靡世界的\"威斯康星理念\"，因为其创造出现代大学发展的一种崭新模式是（ ）。", "options": {"A": "推崇理性", "B": "重视科研", "C": "注重实用", "D": "民主自治"}, "answer": "C", "explanation": "\"威斯康星理念\"的核心是大学为社会服务，强调大学要走出象牙塔，注重实用，将知识应用于解决社会实际问题。"}, {"type": "单选", "num": 144, "text": "从整体上探讨教师生涯的发展历程，提出了一套动态的教师生涯循环理论的是（ ）。", "options": {"A": "伯顿", "B": "傅勒", "C": "布鲁贝克", "D": "费斯勒"}, "answer": "D", "explanation": "费斯勒（Fessler）提出了动态的教师生涯循环理论，将教师生涯分为职前阶段、入职阶段、能力建立阶段、热情与成长阶段、职业挫折阶段、职业稳定阶段、职业消退阶段和职业退出阶段。"}, {"type": "单选", "num": 145, "text": "满足学习需求和实现教学目标安排要求学生系统学习的知识、技能和行为经验的总和的是（ ）。", "options": {"A": "教学要求", "B": "教学内容", "C": "教学大纲", "D": "教学计划"}, "answer": "B", "explanation": "教学内容是为实现教学目标而要求学生系统学习的知识、技能和行为经验的总和，是教学活动中最核心的要素。"}, {"type": "单选", "num": 146, "text": "欧洲近代大学产生的渊源是（ ）。", "options": {"A": "中世纪大学", "B": "教会学校", "C": "骑士学校", "D": "宫廷学校"}, "answer": "A", "explanation": "欧洲近代大学直接源于中世纪大学。中世纪大学（如波伦亚大学、巴黎大学、牛津大学等）为近代大学提供了组织模式、教学制度和学术传统。"}, {"type": "单选", "num": 147, "text": "下列不属于教师群体内部不同年龄、不同水平的教师之间在学术研究上应保持的关系是（ ）。", "options": {"A": "共进关系", "B": "竞争关系", "C": "依从关系", "D": "合作关系"}, "answer": "C", "explanation": "教师群体内部应保持合作、共进和适当竞争的关系。依从关系（下级对上级的被动服从）不适合教师群体，学术研究应强调平等和自主。"}, {"type": "单选", "num": 148, "text": "下列选项属于高校就业指导服务体系的重要组成部分的是（ ）。", "options": {"A": "思想政治理论课程", "B": "心理咨询服务", "C": "就业指导课程", "D": "实习基地建设"}, "answer": "C", "explanation": "就业指导课程是高校就业指导服务体系的重要组成部分，通过课程形式对学生进行职业规划、求职技能等方面的系统指导。"}, {"type": "单选", "num": 149, "text": "教学过程的本质属性是（ ）。", "options": {"A": "课内学习与课外学习的统一", "B": "教与学的统一", "C": "学生的学", "D": "教师的教"}, "answer": "B", "explanation": "教学过程的本质是教与学的统一，是教师引导学生学习的过程。教学是教师教和学生学的双边活动，两者相互依存、相互促进。"}, {"type": "单选", "num": 150, "text": "终身教育的\"四个支柱\"指的是学会认知、学会做事、学会生存和（ ）。", "options": {"A": "学会关心", "B": "学会创造", "C": "学会共同生活", "D": "学会交往"}, "answer": "C", "explanation": "1996年联合国教科文组织在《教育——财富蕴藏其中》报告中提出终身教育的\"四个支柱\"：学会认知、学会做事、学会共同生活、学会生存。"}, {"type": "单选", "num": 151, "text": "不属于高校教学特征的是（ ）。", "options": {"A": "内容的基础性", "B": "本质的专业性", "C": "过程的探究性", "D": "对象的差异性"}, "answer": "A", "explanation": "高校教学的特征包括：本质的专业性（专业教育）、过程的探究性（教学与科研结合）、对象的差异性（学生多样）。内容的基础性是中小学教学的特征，而非高校。"}, {"type": "单选", "num": 152, "text": "柏林大学的创办及其发展，使大学的（ ）职能得到快速发展？", "options": {"A": "科学研究", "B": "培养人才", "C": "传授知识", "D": "为社会服务"}, "answer": "A", "explanation": "柏林大学的创办确立了\"教学与研究相统一\"的原则，将科学研究正式引入大学，使科学研究成为大学的第二职能并得到快速发展。"}, {"type": "单选", "num": 153, "text": "强调\"确定国际公认的可比较的质量标准\"的文件是（ ）。", "options": {"A": "《教育——财富蕴藏其中》", "B": "《21世纪的高等教育：展望和行动世界宣言》", "C": "《19世纪的高等教育：展望和行动世界宣言》", "D": "《20世纪的高等教育：展望和行动世界宣言》"}, "answer": "B", "explanation": "1998年联合国教科文组织在巴黎召开世界高等教育大会，发表了《21世纪的高等教育：展望和行动世界宣言》，强调要\"确定国际公认的可比较的质量标准\"。"}, {"type": "单选", "num": 154, "text": "认识论哲学，更接近的\"大学理念\"是（ ）。", "options": {"A": "杜威", "B": "赫钦斯", "C": "纽曼", "D": "怀特海"}, "answer": "C", "explanation": "认识论哲学认为大学应以追求知识、探求真理为目的，这与纽曼的理性主义大学理念最为接近。纽曼主张大学是传授普遍知识的场所，知识本身即为目的。"}, {"type": "单选", "num": 155, "text": "高校对学生进行奖惩管理依据的权威文件是（ ）。", "options": {"A": "《普通高等学校学生行为守则》", "B": "《中华人民共和国教师法》", "C": "《中国人民共和国教育法》", "D": "《普通高等学校学生管理规定》"}, "answer": "D", "explanation": "《普通高等学校学生管理规定》是高校对学生进行奖惩管理的基本依据，对学生的权利与义务、学籍管理、奖励与处分等做出了明确规定。"}, {"type": "单选", "num": 156, "text": "准备阶段是课程评价实施前的预备工作阶段，其中心环节或重要工作是（ ）。", "options": {"A": "建立评价机构", "B": "制定评价方案", "C": "设定评价机构人员构成", "D": "建立课程评价专家库"}, "answer": "B", "explanation": "课程评价准备阶段的中心环节是制定评价方案。评价方案明确了评价目的、内容、方法、步骤等，是整个评价工作的行动指南。"}, {"type": "单选", "num": 157, "text": "关于推进我国高等教育国际化错误的是（ ）。", "options": {"A": "审时度势，制定合理的国际化策略", "B": "认识为先，理性地把握国际化的本质", "C": "抱团发展，促进区域联盟发展", "D": "瞄准目标，全面提升高等教育国际化水平"}, "answer": "C", "explanation": "\"抱团发展，促进区域联盟发展\"不是推进我国高等教育国际化的核心策略。国际化应立足全球视野，而非仅仅局限于区域联盟。"}, {"type": "单选", "num": 158, "text": "高等教育领域\"中心-边缘\"理论的提出者是美国高等教育学者（ ）。", "options": {"A": "威廉·大内", "B": "阿尔特巴赫", "C": "西蒙", "D": "凯恩斯"}, "answer": "B", "explanation": "阿尔特巴赫（Philip Altbach）提出了高等教育领域的\"中心-边缘\"理论，认为世界高等教育体系存在中心国家（发达国家）和边缘国家（发展中国家）的不平等关系。"}, {"type": "单选", "num": 159, "text": "古希腊哪位教育家认为哲学的目的不在于认识自然，而在于\"认识自己\"？", "options": {"A": "苏格拉底", "B": "柏拉图", "C": "黑格尔", "D": "亚里士多德"}, "answer": "A", "explanation": "苏格拉底提出\"认识你自己\"（Know thyself）的哲学命题，认为哲学的目的在于认识人自身和道德，而非认识外部自然。"}, {"type": "单选", "num": 160, "text": "高校教师专业发展的路径没有形成（ ）。", "options": {"A": "国际化的合作组织", "B": "建制化的专业组织", "C": "专门的群体繁衍机制", "D": "完整的职业发展道路"}, "answer": "A", "explanation": "高校教师专业发展已经形成了建制化的专业组织、专门的群体繁衍机制和完整的职业发展道路，但尚未形成国际化的合作组织。"}, {"type": "单选", "num": 161, "text": "高等学校最基层的学术组织是（ ）。", "options": {"A": "职能部门", "B": "班级", "C": "学科", "D": "管理部门"}, "answer": "C", "explanation": "学科是高等学校最基层的学术组织。高校以学科为基础来设置院系和研究机构，学科是教师从事教学、科研的基本单位。"}, {"type": "单选", "num": 162, "text": "叶澜教授对教师专业发展阶段的划分与美国的傅勒类似，都属于（ ）。", "options": {"A": "生涯循环论", "B": "互助发展论", "C": "关注阶段论", "D": "发展阶段论"}, "answer": "C", "explanation": "叶澜教授和傅勒（Fuller）对教师专业发展阶段的划分都采用\"关注阶段论\"的视角，即教师在不同发展阶段关注的重点不同。"}, {"type": "单选", "num": 163, "text": "进入大学后，大学生首先面临着对大学生活的适应。以下哪项不属于大学适应的内容？", "options": {"A": "生活适应", "B": "学习方式适应", "C": "人际环境的适应", "D": "他人监督的适应"}, "answer": "D", "explanation": "大学生适应主要包括：生活适应（独立生活）、学习方式适应（自主学习）、人际环境适应（新的社交圈）。\"他人监督的适应\"不是大学适应的内容，大学更强调自我管理。"}, {"type": "单选", "num": 164, "text": "下列选项中属于高校学生管理难点的是（ ）。", "options": {"A": "学籍管理", "B": "资困助学管理", "C": "危机管理", "D": "社团管理"}, "answer": "C", "explanation": "危机管理是高校学生管理中最大的难点。突发事件、安全事故、心理危机等具有不可预测性和紧迫性，对管理者的应急处理能力要求极高。"}, {"type": "单选", "num": 165, "text": "以下关于高校学生的心理发展特征的说法不正确的是（ ）。", "options": {"A": "社会经验丰富", "B": "个性心理发展基本稳定", "C": "自我意识发展趋向成熟", "D": "认知心理发展处于最佳状态"}, "answer": "A", "explanation": "大学生虽然智力发展水平高、认知能力强，但社会经验相对缺乏，不够丰富。选项A的说法不正确。"}, {"type": "单选", "num": 166, "text": "学校管理权力集中于学术人员手中，学术人员在学校决策中居于主导地位，这种决策模式属于（ ）。", "options": {"A": "双重结合模式", "B": "服务主导模式", "C": "行政主导模式", "D": "学术主导模式"}, "answer": "D", "explanation": "学术主导模式是指学术权力在学校决策中占主导地位，学术人员在重大决策中具有决定权，典型体现是\"教授治校\"。"}, {"type": "单选", "num": 167, "text": "学业服务就是对大学生参与学习活动的数量和质量的服务，包括学业过程管理服务和（ ）两方面。", "options": {"A": "学业水平服务", "B": "学业需要服务", "C": "学业成绩管理服务", "D": "学业评价管理服务"}, "answer": "C", "explanation": "教材原文指出，学业服务是对大学生参与学习活动的数量和质量的服务，包括学业过程管理服务和学业成绩管理服务两方面。因此本题应选“学业成绩管理服务”。"}, {"type": "单选", "num": 168, "text": "朱熹邀请陆九渊赴（ ）书院讲学，首开书院\"讲会\"之先河。", "options": {"A": "白鹿洞书院", "B": "嵩阳书院", "C": "应天府书院", "D": "岳麓书院"}, "answer": "A", "explanation": "南宋淳熙二年（1175年），朱熹邀请陆九渊赴白鹿洞书院讲学，首开书院\"讲会\"制度的先河，促进了不同学派之间的学术交流。"}, {"type": "单选", "num": 169, "text": "在大学生思想政治教育中发挥主渠道作用的是（ ）。", "options": {"A": "哲学社会科学课", "B": "辅导员工作", "C": "学生会、团委工作", "D": "思想政治理论课教学"}, "answer": "D", "explanation": "思想政治理论课是大学生思想政治教育的主渠道和主阵地。其他渠道（辅导员、社团等）是辅助和补充。"}, {"type": "单选", "num": 170, "text": "正式提出和论证了\"班级授课制\"的教育家是（ ）。", "options": {"A": "赫尔巴特", "B": "卢梭", "C": "裴斯泰洛奇", "D": "夸美纽斯"}, "answer": "D", "explanation": "夸美纽斯（Comenius）在《大教学论》中系统论述了班级授课制，确立了其理论基础和实践模式，被誉为\"教育学之父\"。"}, {"type": "单选", "num": 171, "text": "下面哪项不属于教学三维目标的内容？", "options": {"A": "知识", "B": "情感", "C": "技能", "D": "心理"}, "answer": "D", "explanation": "教学三维目标包括：知识与技能（知识、技能）、过程与方法、情感态度与价值观。\"心理\"不是三维目标的独立维度。"}, {"type": "单选", "num": 172, "text": "\"欧共体高校学生流动行动计划\"也称作（ ）。", "options": {"A": "\"苏格拉底计划\"", "B": "图兰朵计划", "C": "伊拉斯谟计划", "D": "\"博洛尼亚进程\""}, "answer": "C", "explanation": "伊拉斯谟计划（Erasmus Programme）是欧共体于1987年发起的高校学生流动行动计划，旨在促进欧洲高校间的学生交流与合作。"}, {"type": "单选", "num": 173, "text": "《高等教育哲学》一书认为，高等教育是以满足各自所属历史时期的需要来获得合法性的，该书的作者是（ ）。", "options": {"A": "纽曼", "B": "罗伯特", "C": "布鲁贝克", "D": "马克斯"}, "answer": "C", "explanation": "布鲁贝克（John S. Brubacher）在《高等教育哲学》中提出了高等教育的认识论和政治论两种哲学基础，认为高等教育通过满足历史时期的需要来获得合法性。"}, {"type": "单选", "num": 174, "text": "夸美纽斯的代表作是（ ）。", "options": {"A": "《林哈德与葛笃德》", "B": "《教育漫画》", "C": "《爱弥儿》", "D": "《大教学论》"}, "answer": "D", "explanation": "夸美纽斯的代表作是《大教学论》（Didactica Magna），这是近代第一部系统的教育学著作，奠定了教育学理论基础。"}, {"type": "单选", "num": 175, "text": "教学系统设计属于（ ）。", "options": {"A": "宏观设计层次", "B": "中观设计层次", "C": "微观设计层次", "D": "三者兼有"}, "answer": "A", "explanation": "教材把教学设计分为三个层次：以教学系统为对象的是教学系统设计，属于宏观设计层次；以教学过程为对象的是教学过程设计；以教学产品为对象的是教学产品设计。因此本题问“教学系统设计属于”，应选宏观设计层次。"}, {"type": "单选", "num": 176, "text": "关于学生评价改革的说法不正确的是（ ）。", "options": {"A": "评价重点从关注结果转向重视过程", "B": "评价内容由认知评价扩展为全面、综合的评价", "C": "评价的目的为甄别性与选拔性", "D": "学生在评价过程中的地位由被动转向主动"}, "answer": "C", "explanation": "学生评价改革的方向是从甄别选拔转向促进发展，而非强化甄别性与选拔性。评价的目的应是促进学生的全面发展，而非单纯筛选。"}, {"type": "单选", "num": 177, "text": "中国近代史上第一所国立综合性大学是（ ），它既是全国最高学府，又是国家最高教育行政机关，统辖各省学堂。", "options": {"A": "燕京大学", "B": "京师同文馆", "C": "南京大学", "D": "京师大学堂"}, "answer": "D", "explanation": "京师大学堂创办于1898年（戊戌变法期间），是中国近代史上第一所国立综合性大学，同时兼有国家最高教育行政机关的职能。"}, {"type": "单选", "num": 178, "text": "学校教育最基本的课程资源与教学依据是（ ）。", "options": {"A": "教师", "B": "学生", "C": "教材", "D": "教学参考资料"}, "answer": "C", "explanation": "教材是学校教育最基本的课程资源和教学依据。教材根据课程标准编写，是教师教学和学生学习的主要材料。"}, {"type": "单选", "num": 179, "text": "洪堡大学理念的发源地是（ ）。", "options": {"A": "德国", "B": "加拿大", "C": "美国", "D": "英国"}, "answer": "A", "explanation": "洪堡大学理念产生于德国。威廉·冯·洪堡在德国创办柏林大学，提出了\"教学与研究相统一\"的大学理念。"}, {"type": "单选", "num": 180, "text": "高等教育的主体与基础是（ ）。", "options": {"A": "专科教育", "B": "本科教育", "C": "硕士生教育", "D": "博士生教育"}, "answer": "B", "explanation": "本科教育是高等教育的主体和基础。本科阶段既是培养高层次专门人才的主要阶段，也是研究生教育的基础。"}, {"type": "单选", "num": 181, "text": "法国国家科学研究中心的研究人员有研究员和研究主任两种职衔，与高等教育机构的（ ）职衔相当。", "options": {"A": "讲师和教授", "B": "副教授和教授", "C": "助教和讲师", "D": "讲师和副教授"}, "answer": "A", "explanation": "法国国家科学研究中心的研究人员有两种职衔：研究员和研究主任，分别与高等教育机构中的讲师和教授两级职衔相当。因此本题应选“讲师和教授”。"}, {"type": "单选", "num": 182, "text": "通过科研评价，管理部门可以证明科研工作的效率和成就，掌握、解决科研工作中存在的问题，为以后的科研管理提供有针对性、可行性的建议。这反映了科研管理特性中的（ ）。", "options": {"A": "科研评价发展的历史性", "B": "科研评价具有民主性", "C": "科研评价具有管理咨询的性质", "D": "科研评价的量化性"}, "answer": "C", "explanation": "科研评价为管理决策提供依据和建议，证明效率成就、发现问题、提出建议，体现了其管理咨询的性质。"}, {"type": "单选", "num": 183, "text": "负责制定有关大学战略、政策、和目标，是大学的最高决策机构，根据组织理论，这属于（ ）。", "options": {"A": "战略制定层", "B": "中间管理层", "C": "操作人员层", "D": "监督控制层"}, "answer": "A", "explanation": "战略制定层是组织的最高层，负责制定战略、政策和目标。大学中的校董事会、校务委员会等属于战略制定层。"}, {"type": "单选", "num": 184, "text": "专业培养目标、学制、学位及学分要求主要体现在（ ）中。", "options": {"A": "教材", "B": "教学大纲", "C": "发展规划", "D": "培养方案"}, "answer": "D", "explanation": "培养方案（原称教学计划）是高校人才培养的总体设计，具体规定了专业培养目标、学制、学位授予、学分要求等内容。"}, {"type": "单选", "num": 185, "text": "关于\"高等教育国际化\"，下列说法错误的是（ ）。", "options": {"A": "国际化的内容是全方位的", "B": "国际化是一个持续不断的过程", "C": "高等教育国际化的目的是\"国际化\"", "D": "\"国际化\"活动中，国家的边界是清楚的"}, "answer": "C", "explanation": "高等教育国际化的目的是提升教育质量、促进跨文化交流和全球理解，而非\"为了国际化而国际化\"。国际化是手段，不是目的。"}, {"type": "单选", "num": 186, "text": "形成学术专业群体内部伦理规范的根本目的是（ ）。", "options": {"A": "服务教学", "B": "服务知识", "C": "服务教师", "D": "服务学术"}, "answer": "B", "explanation": "学术专业群体内部伦理规范的根本目的是服务知识。默顿的科学规范（CUDOS：普遍主义、公有主义、无私利性、有条理的怀疑主义）核心在于保护知识的客观性、真理性和可靠传播。服务知识是根本，服务学术是派生目的。"}, {"type": "单选", "num": 187, "text": "下列关于\"教学\"说法不正确的是（ ）。", "options": {"A": "课堂是主渠道", "B": "师生发展是目标", "C": "教师与学生共同参与", "D": "有计划有组织"}, "answer": "B", "explanation": "教材将教学定义为：教学是在学校环境中，以课堂为主渠道、以学生发展为目标，教师与学生共同参与的、有计划有组织的活动。A“课堂是主渠道”、C“教师与学生共同参与”、D“有计划有组织”均符合教材定义；B把目标说成“师生发展”，而教材表述是“学生发展”，因此B是不正确的说法。"}, {"type": "单选", "num": 188, "text": "高等学校的法人代表是（ ）。", "options": {"A": "校工会主席", "B": "法律顾问", "C": "党委书记", "D": "校长"}, "answer": "D", "explanation": "根据《高等教育法》的规定，高等学校的法定代表人由校长担任。校长是学校的法人代表，对外代表学校。"}, {"type": "单选", "num": 189, "text": "与传统的教授法相比，下列选项中不属于小组教学优点的是（ ）。", "options": {"A": "激发学生好奇心", "B": "耗时短", "C": "学生可以毫无顾虑地畅所欲言", "D": "更多学生参与到课程中来"}, "answer": "B", "explanation": "小组教学通常需要更多的时间来进行讨论、交流和合作，比传统讲授法更耗时。因此\"耗时短\"不是小组教学的优点。"}, {"type": "单选", "num": 190, "text": "完成组织目标所需的各项业务工作及其比例和关系，是大学组织的（ ）。", "options": {"A": "部门结构", "B": "职权结构", "C": "职能结构", "D": "层次结构"}, "answer": "C", "explanation": "职能结构是指组织为完成目标所需开展的各项业务工作及其比例和关系。它规定了组织应该做什么、各职能之间的逻辑关系。"}, {"type": "单选", "num": 191, "text": "课程教学设计的核心是（ ）。", "options": {"A": "教学方法", "B": "教学目标", "C": "了解教学对象", "D": "编制教案"}, "answer": "D", "explanation": "教材在“大学教学设计实务”中指出，教案是教学设计最基本的表现形式，是课程教学设计的核心工作；同时，教学过程设计构成教案的核心。因此本题应选“编制教案”。"}, {"type": "单选", "num": 192, "text": "个人本位论的实质是主张高等教育的主要价值在于（ ）。", "options": {"A": "追求真理，创造知识", "B": "促进个人理智的发展", "C": "为社会服务", "D": "为政治服务"}, "answer": "B", "explanation": "个人本位论认为高等教育的价值在于促进个人的发展，特别是理性的发展，使人成为真正的人。选项B最符合个人本位论的精神实质。"}, {"type": "单选", "num": 193, "text": "不属于高等教育国际化的文化动因的计划是（ ）。", "options": {"A": "\"苏格拉底计划\"", "B": "田普斯计划", "C": "伊拉斯谟计划", "D": "富布赖特计划"}, "answer": "B", "explanation": "田普斯计划（TEMPUS）是欧盟对外高等教育援助项目，偏重制度改革和政策工具，不属于纯粹的文化动因计划。富布赖特计划虽也有外交色彩，但通常被归类为文化教育交流项目。"}, {"type": "单选", "num": 194, "text": "第三级教育不包括以下哪个教育类型？", "options": {"A": "博士教育", "B": "博士后教育", "C": "专科教育", "D": "硕士教育"}, "answer": "B", "explanation": "第三级教育（Tertiary Education）指中等教育以上的各级各类教育，包括专科、本科、硕士和博士教育。博士后教育属于研究人员的进修阶段，不属于正式的第三级教育。"}, {"type": "单选", "num": 195, "text": "建设高等教育强国的基本要求是（ ）。", "options": {"A": "加快大众化进程", "B": "增加教学人数", "C": "扩大教学规模", "D": "提高整体质量"}, "answer": "D", "explanation": "建设高等教育强国的基本要求是提高整体质量。质量是高等教育的生命线，规模和数量不能代表教育强国。"}, {"type": "单选", "num": 196, "text": "不属于欧盟成员国高等教育国际化最重要的推动力的是（ ）。", "options": {"A": "\"伊拉斯谟计划\"", "B": "\"图兰朵计划\"", "C": "\"苏格拉底计划\"", "D": "\"博洛尼亚进程\""}, "answer": "B", "explanation": "\"图兰朵计划\"（Turandot Program）是意大利针对中国艺术类学生的留学项目，不是欧盟层面的国际化推动力。伊拉斯谟计划、苏格拉底计划和博洛尼亚进程都是欧盟高等教育国际化的重要推动力。"}, {"type": "单选", "num": 197, "text": "运用住房分配、工资待遇、福利享受、科研资助等方式，激励高校科研人员积极从事科学研究，最大化地追求经济效益，这是科研管理方法中的（ ）。", "options": {"A": "专家管理方法", "B": "数学管理方法", "C": "行政管理方法", "D": "经济管理方法"}, "answer": "D", "explanation": "经济管理方法通过经济杠杆（住房、工资、福利、资助等）来激励和约束科研人员的行为，追求经济效益最大化。"}, {"type": "单选", "num": 198, "text": "科学研究事业的特殊性，要求科研管理必须采用（ ）。", "options": {"A": "专家管理方法", "B": "数学管理方法", "C": "行政管理方法", "D": "经济管理方法"}, "answer": "A", "explanation": "科学研究具有高度的专业性和创造性，必须依靠专家来进行管理。专家管理方法尊重科学规律，由同行专家进行评价和决策。"}, {"type": "单选", "num": 199, "text": "认为大学的主要目的是教学而不是科研的是（ ）。", "options": {"A": "赫钦斯", "B": "布鲁纳", "C": "洪堡", "D": "纽曼"}, "answer": "D", "explanation": "纽曼在《大学的理想》中明确主张大学的主要目的是教学，是传授普遍知识，而不是科研。这与洪堡主张的\"教学与研究相统一\"形成鲜明对比。"}, {"type": "单选", "num": 200, "text": "下列不属于推进学术休假制度应遵循的基本原则的是（ ）。", "options": {"A": "学术性原则", "B": "可行性原则", "C": "专业发展为主、身心调整和个人休假为辅原则", "D": "实效性原则"}, "answer": "A", "explanation": "教材列出的推进学术休假制度原则包括：实效性原则、专业发展为主且身心调整和个人休假为辅的原则、保证可行的原则。选项A“学术性原则”不在教材所列原则中，因此属于“不包括”的项目。"}, {"type": "单选", "num": 201, "text": "将教学过程划分为\"明了、联想、系统、方法\"四阶段的教育家是（ ）。", "options": {"A": "夸美纽斯", "B": "裴斯泰洛奇", "C": "赫尔巴特", "D": "卢梭"}, "answer": "C", "explanation": "赫尔巴特（Herbart）将教学过程分为四个阶段：明了（清楚感知新知识）、联想（新旧知识联系）、系统（形成知识体系）、方法（应用和练习）。"}, {"type": "单选", "num": 202, "text": "认为大学应该走出封闭的象牙塔，成为沟通社会各界、身兼多重职能的超级复合机构的教育家是（ ）。", "options": {"A": "科尔", "B": "杜威", "C": "博克", "D": "萨特"}, "answer": "C", "explanation": "教材提到，德里克·博克在《超越象牙塔》中认为大学应该走出封闭的象牙塔，成为沟通社会各界、身兼多重职能的超级复合机构。该表述对应博克，而不是科尔。"}, {"type": "单选", "num": 203, "text": "高校学生综合评价体系的设计原则是导向性原则、整体性原则、客观性原则和（ ）。", "options": {"A": "发展性原则", "B": "可测性原则", "C": "淘汰性原则", "D": "激励性原则"}, "answer": "B", "explanation": "高校学生综合评价体系的设计原则包括：导向性原则、整体性原则、客观性原则和可测性原则（可操作性原则）。发展性更多是评价的功能取向，而非体系设计原则。"}, {"type": "单选", "num": 204, "text": "高等教育国际化最引入关注的部分是（ ）。", "options": {"A": "国际会议", "B": "高等教育援助", "C": "跨境高等教育", "D": "本土高等教育"}, "answer": "C", "explanation": "跨境高等教育（人员、机构、项目的跨国流动）是高等教育国际化最引人关注的部分，因为它直接涉及跨越国界的教育交流与合作。"}, {"type": "单选", "num": 205, "text": "高等学校为社会服务的职能最早产生于（ ）。", "options": {"A": "意大利", "B": "英国", "C": "美国", "D": "德国"}, "answer": "C", "explanation": "美国通过《莫雷尔法案》（1862年）建立赠地学院，特别是威斯康星大学倡导\"为社会服务\"的理念，使社会服务成为高等学校的第三职能。"}, {"type": "单选", "num": 206, "text": "以决策为中心的CIPP综合评价模式，由背景评价、输入评价、（ ）和结果评价四种评价组成。", "options": {"A": "表现评价", "B": "行为评价", "C": "过程评价", "D": "目标评价"}, "answer": "C", "explanation": "CIPP评价模式的四大组成部分：背景评价（Context）、输入评价（Input）、过程评价（Process）和成果评价（Product）。"}, {"type": "单选", "num": 207, "text": "大众高等教育最显著的特征是（ ）。", "options": {"A": "高等教育的影响加深", "B": "高等教育的规模扩大", "C": "高等教育的区域增扩大", "D": "高等教育的人数增长"}, "answer": "D", "explanation": "教材明确指出，大众高等教育最显著的特征是接受高等教育的人数持续增长。高等教育大众化首先表现为入学机会扩大、受教育人数增加，因此本题应选“高等教育的人数增长”。"}, {"type": "单选", "num": 208, "text": "芝加哥大学哪位校长十分重视经典著作的教育作用？", "options": {"A": "赖斯", "B": "亨尼斯", "C": "赫钦斯", "D": "洪堡"}, "answer": "C", "explanation": "赫钦斯（Robert Hutchins）在担任芝加哥大学校长期间，大力推行\"名著课程\"（Great Books Program），强调经典著作在大学教育中的核心作用。"}, {"type": "单选", "num": 209, "text": "根据时代、环境发展的需求对校训赋予新的内涵与诠释，提出新的校训，这体现了大学精神文化的（ ）。", "options": {"A": "兼容性", "B": "个性", "C": "发展性", "D": "整合性"}, "answer": "C", "explanation": "大学精神文化具有发展性，能够随着时代发展不断丰富和完善。对校训赋予新的时代内涵，正体现了其发展性特征。"}, {"type": "单选", "num": 210, "text": "极力主张知识与市场和政治分离，把大学作为\"象牙塔\"的大学理念是（ ）。", "options": {"A": "理性主义", "B": "永恒主义", "C": "存在主义", "D": "实用主义"}, "answer": "A", "explanation": "理性主义大学理念主张大学应远离市场和政治的干扰，坚持为知识而知识，把大学作为纯粹的学术\"象牙塔\"。"}, {"type": "单选", "num": 211, "text": "单一的垂直领导，结构简单，每一级的个人或组织只有一个领导，不与相邻个人或组织及其领导发生任何命令与服从关系。这种大学组织结构类型属于（ ）。", "options": {"A": "矩阵结构", "B": "直线职能制", "C": "职能制", "D": "直线制"}, "answer": "D", "explanation": "直线制是最简单的组织结构形式，权力从最高层到最低层垂直领导，命令链单一，每个人都只向一个上级负责。"}, {"type": "单选", "num": 212, "text": "CIPP模式把课程评价分为背景评价、投入评价、过程评价和（ ）。", "options": {"A": "主体评价", "B": "社会评价", "C": "内部评价", "D": "成果评价"}, "answer": "D", "explanation": "CIPP评价模式的四个环节是：背景评价（Context）、投入评价（Input）、过程评价（Process）和成果评价（Product）。成果评价是最后一个环节。"}, {"type": "单选", "num": 213, "text": "教学策略的核心和完成教学任务的保障是（ ）。", "options": {"A": "教学目标", "B": "教学手段", "C": "教学方法", "D": "教学计划"}, "answer": "C", "explanation": "教学方法是教学策略的核心内容，也是完成教学任务、实现教学目标的直接保障。没有恰当的教学方法，教学策略就无法落实。"}, {"type": "单选", "num": 214, "text": "美国课程论家泰勒在《课程与教学的基本原理》中认为课程编制最重要的问题是（ ）。", "options": {"A": "课程内容", "B": "教学经验", "C": "教学评价", "D": "课程目标"}, "answer": "D", "explanation": "泰勒认为课程编制中最重要的问题是确定课程目标。泰勒原理的四个基本问题中，确定目标是第一步也是最关键的一步，其他环节都围绕目标展开。"}, {"type": "单选", "num": 215, "text": "社会本位论的代表人物不包括（ ）。", "options": {"A": "赫尔巴特", "B": "涂尔干", "C": "孔德", "D": "卢梭"}, "answer": "D", "explanation": "卢梭是社会本位论的反对者，他是个人本位论的典型代表人物。赫尔巴特、涂尔干、孔德都是社会本位论的代表。"}, {"type": "单选", "num": 216, "text": "关于应答模式，表述错误的是（ ）。", "options": {"A": "提出者是斯克里文", "B": "包括描述阶段和判断阶段", "C": "强调多方人员的广泛参与", "D": "也称为外观评价模式"}, "answer": "A", "explanation": "应答模式（Responsive Model）由斯泰克（Stake）提出，因此A\"提出者是斯克里文\"是明确的事实错误。斯克里文（Scriven）提出的是目标游离模式（Goal-Free Model）。D\"也称为外观评价模式\"虽也错误，但单选题以最根本的事实错误A为正确答案。"}, {"type": "单选", "num": 217, "text": "1945年，哈佛大学颁布的一份文件认为，大学应该\"培养健全的个人和自由社会中健全的公民\"，这种教育类型属于（ ）。", "options": {"A": "人文教育", "B": "专业教育", "C": "专才教育", "D": "通识教育"}, "answer": "D", "explanation": "1945年哈佛大学发表了《自由社会中的通识教育》（General Education in a Free Society，即\"红皮书\"），主张大学应推行通识教育，培养自由社会中的健全公民。"}, {"type": "单选", "num": 218, "text": "高校教师教学考核的首要内容是（ ）。", "options": {"A": "科研水平", "B": "教学水平", "C": "师生关系", "D": "学术水平"}, "answer": "B", "explanation": "高校教师教学考核的首要内容是教学水平。教师的首要职责是教学，因此对教师考核首先应关注其教学能力、教学效果和教学质量。"}, {"type": "单选", "num": 219, "text": "教材内容评价时需要注意概念、原理、数据是否科学可靠，对应的评价指标是（ ）。", "options": {"A": "便利性", "B": "准确性", "C": "完整性", "D": "公正性"}, "answer": "B", "explanation": "教材内容评价的准确性指标要求概念、原理、数据科学可靠、表述准确、无错误。"}, {"type": "单选", "num": 220, "text": "提出\"以学术为业\"不仅是谋生的手段，更应看成为响应知识的'神召'\"的学者是（ ）。", "options": {"A": "雅斯贝尔斯", "B": "马克斯·韦伯", "C": "费希特", "D": "乌申斯基"}, "answer": "B", "explanation": "马克斯·韦伯（Max Weber）在《以学术为业》的演讲中提出，学者应将学术视为一种\"神召\"（天职），而非仅仅是谋生的职业。"}, {"type": "单选", "num": 221, "text": "美国于1862年颁布的《莫里尔法案》，使各州开始普遍设立（ ）。", "options": {"A": "独立学院", "B": "社区学院", "C": "赠地学院", "D": "文理学院"}, "answer": "C", "explanation": "《莫里尔法案》（Morrill Act，又称《赠地法案》）规定联邦政府向各州赠予土地，用于建立讲授农业和机械技术的学院，即赠地学院（Land-grant Colleges）。"}, {"type": "单选", "num": 222, "text": "美国学者波斯纳和鲁德尼斯基提出的单门课程编制模式包括16个步骤，其中心思想是（ ）。", "options": {"A": "让教师有目的地进行教学", "B": "让学生有目的地进行学习", "C": "让课程有序进行", "D": "让课程达到预期目标"}, "answer": "A", "explanation": "波斯纳（Posner）和鲁德尼斯基（Rudnitsky）在《课程设计：教师指南》中提出的16步骤模式，其核心导向是\"有意图的教学\"（Intentional Teaching），即帮助教师明确教学意图并转化为具体课程结构。卡片答案A（让教师有目的地进行教学）更符合原意。"}, {"type": "单选", "num": 223, "text": "高等学校强调教学与科研相结合，表明高校教学过程具有（ ）。", "options": {"A": "探究性", "B": "基础性", "C": "理论性", "D": "复杂性"}, "answer": "A", "explanation": "教学与科研相结合使高校教学过程具有探究性。学生在学习过程中接触科学研究方法，培养探究精神和创新能力，这是高校教学区别于中小学教学的重要特征。"}, {"type": "单选", "num": 224, "text": "关于教师职业能力发展阶段的理论，傅勒编制了著名的《教师关注问卷》，提出（ ）。", "options": {"A": "教师生涯循环论", "B": "教师能力发展阶段论", "C": "教师发展阶段论", "D": "教师关注阶段论"}, "answer": "D", "explanation": "傅勒（Fuller）通过编制《教师关注问卷》，提出了教师关注阶段论（Concerns-Based Adoption Model），将教师发展划分为不同关注阶段。"}, {"type": "单选", "num": 225, "text": "根据我国高等学校内部管理体制和运行机制改革的要求，在一所管理层次划分为\"校、系、教研室\"三级的高校，其管理重心应放在（ ）。", "options": {"A": "系", "B": "学校", "C": "学校和系", "D": "教研室"}, "answer": "A", "explanation": "我国高校管理体制改革的方向是管理重心下移，在\"校、系、教研室\"三级管理中，管理重心应放在系（学院）一级，赋予系更多的自主权。"}, {"type": "单选", "num": 226, "text": "学术职业具有崇尚自由的精神气质，柏林大学第一任经选举产生的校长以《论学术自由唯一可能遇到的干扰》为题发表就职演讲，他是著名的哲学家（ ）。", "options": {"A": "费希特", "B": "施莱尔马赫", "C": "雅斯贝尔斯", "D": "乌申斯基"}, "answer": "A", "explanation": "费希特（Johann Gottlieb Fichte）是柏林大学第一任经选举产生的校长，他在就职演讲中专门论述了学术自由的重要性。"}, {"type": "单选", "num": 227, "text": "中世纪大学的古典学术综合型大学为基本样式的时期是（ ）。", "options": {"A": "平民化时期", "B": "精英化时期", "C": "大众化时期", "D": "普及化时期"}, "answer": "B", "explanation": "中世纪大学以古典学术综合型大学为基本样式，实行的是精英教育，培养少数教士、律师、医生等专业人才，属于精英化时期。"}, {"type": "单选", "num": 228, "text": "\"教授治校\"是哪种决策模式的典型体现？", "options": {"A": "双重结合模式", "B": "复式组合模式", "C": "行政主导模式", "D": "学术主导模式"}, "answer": "D", "explanation": "\"教授治校\"是学术主导模式的典型体现，强调由教授（学术人员）掌握学校的决策权，学术权力主导学校事务。"}, {"type": "单选", "num": 229, "text": "以下哪类高等教育市场不属于通过商品及服务获得资金的形态类型？", "options": {"A": "资本市场", "B": "学术市场", "C": "教育市场", "D": "研究市场"}, "answer": "B", "explanation": "教材引用金子元久的分类，从高等学校提供商品及服务而获得资金的形态出发，将高等教育市场分为教育市场、研究市场与资本市场。“学术市场”不属于这一分类。"}, {"type": "单选", "num": 230, "text": "下列国家中，实施多重型学术职业阶梯结构的是（ ）。", "options": {"A": "意大利", "B": "德国", "C": "美国", "D": "法国"}, "answer": "C", "explanation": "美国实施多重型学术职业阶梯结构，表现为各层次高校的教师职称序列多元化（社区学院、教学型大学、研究型大学的职称体系不同）。"}, {"type": "单选", "num": 231, "text": "中国高等教育大众化进程大致可以划分为三个阶段，不包括（ ）。", "options": {"A": "全面发展阶段", "B": "提高质量阶段", "C": "调整结构阶段", "D": "提速扩张阶段"}, "answer": "A", "explanation": "中国高等教育大众化进程的三个阶段是：提速扩张阶段（1999-2001年）→调整结构阶段（2001-2005年）→提高质量阶段（2005年以后）。\"全面发展阶段\"不是独立阶段。"}, {"type": "单选", "num": 232, "text": "以下关于终生学习的说法不正确的是（ ）。", "options": {"A": "终生学习是一种终结性学习方式", "B": "终生学习必须以学习化社会为前提", "C": "终生学习是以个人的自发意愿为基础", "D": "终生学习必须将教育功能扩大至整个社会"}, "answer": "A", "explanation": "终生学习不是终结性的学习方式，恰恰相反，它是贯穿人一生的持续性学习过程，强调学习的连续性和终身性。"}, {"type": "单选", "num": 233, "text": "教学实践中占据核心地位的教学方法是（ ）。", "options": {"A": "实验法", "B": "讲授法", "C": "演示法", "D": "研讨法"}, "answer": "B", "explanation": "讲授法是教学实践中占据核心地位的教学方法。尽管有各种新的教学方法出现，但讲授法仍然是高校最基本、最常用的教学方法。"}, {"type": "单选", "num": 234, "text": "院校和教授为获取外部资金而进行的市场的或类似市场的活动称之为（ ）。", "options": {"A": "凯恩斯主义", "B": "哈马斯主义", "C": "知识经济主义", "D": "学术资本主义"}, "answer": "D", "explanation": "学术资本主义（Academic Capitalism）是指大学及其教师为获取外部资金而进行的市场或类市场活动，如争取科研经费、专利转化、企业合作等。"}, {"type": "单选", "num": 235, "text": "高校教学的基本功能是（ ）。", "options": {"A": "促进学生的全面发展", "B": "培养高精尖人才", "C": "增加学生就业竞争力", "D": "挖掘学生的才能"}, "answer": "A", "explanation": "高校教学的基本功能是促进学生的全面发展，包括知识、能力、素质、人格等各方面的全面成长。"}, {"type": "单选", "num": 236, "text": "德国、意大利等实施单一型学术职业阶梯结构国家，高校教师学术晋升说法不正确的是（ ）。", "options": {"A": "教师都能获得教授职务", "B": "各大学地位平等", "C": "学术职位具有同等地位", "D": "博士毕业后获得大学授课资格"}, "answer": "A", "explanation": "单一型学术职业阶梯结构中，教授职位数量有限，并非所有教师都能获得教授职务。选项A说法错误。"}, {"type": "单选", "num": 237, "text": "高等学校培养目标制定的依据不包括（ ）。", "options": {"A": "个人需求", "B": "社会需求", "C": "专业需求", "D": "法律需求"}, "answer": "D", "explanation": "培养目标制定的主要依据包括社会发展需求、个人发展需求和学科专业发展需求。法律需求不是培养目标制定的依据。"}, {"type": "单选", "num": 238, "text": "早期中世纪大学实行的是专业教育，主要围绕哪四科来组织教学活动？", "options": {"A": "神、哲、理、法", "B": "法、商、工、农", "C": "文、理、法、农", "D": "文、法、医、神"}, "answer": "D", "explanation": "早期中世纪大学设文学院（基础教育）、法学院、医学院和神学院四科，学生先在文学院学习\"七艺\"，然后进入其他三科之一深造。"}, {"type": "单选", "num": 239, "text": "马斯洛需要层次理论中，属于成长性的需要是（ ）。", "options": {"A": "自我实现", "B": "尊重的需要", "C": "安全的需要", "D": "生理的需要"}, "answer": "A", "explanation": "马斯洛将需要分为缺失性需要（生理、安全、归属与爱、尊重）和成长性需要（自我实现）。自我实现是最高层次的成长性需要。"}, {"type": "单选", "num": 240, "text": "建构主义学习理论强调的是（ ）。", "options": {"A": "课堂学习", "B": "机械学习", "C": "情境学习", "D": "接受学习"}, "answer": "C", "explanation": "建构主义学习理论强调情境学习，认为知识是在真实或模拟的情境中通过主动建构获得的。学习不是被动接受，而是在情境中主动建构意义的过程。"}, {"type": "单选", "num": 241, "text": "有的高校规定讲师、副教授的任职年限，超过年限未能晋升则予以解聘。上述规定属于（ ）。", "options": {"A": "\"非升即走\"", "B": "\"评聘分离\"", "C": "\"末位淘汰\"", "D": "\"评聘协调\""}, "answer": "A", "explanation": "\"非升即走\"（Up or Out）是指教师在规定期限内未能晋升到更高一级职称则需离开学校。这不同于末位淘汰（按绩效排名淘汰）。"}, {"type": "单选", "num": 242, "text": "认为大学存在的根本原因是\"在富于想象地探讨学问中把青年人和老年人联合起来\"的是（ ）。", "options": {"A": "怀特海", "B": "洪堡", "C": "纽曼", "D": "赫钦斯"}, "answer": "A", "explanation": "怀特海（Alfred North Whitehead）在《教育的目的》中提出，大学存在的理由在于它将青年人和老年人联合在富于想象的学问探讨中。"}, {"type": "单选", "num": 243, "text": "伯顿提出的教师发展阶段论指出，教师在每一个发展的逻辑单元中一般会经历三个阶段，下列错误的是（ ）。", "options": {"A": "调整阶段", "B": "适应阶段", "C": "成熟阶段", "D": "求生存阶段"}, "answer": "B", "explanation": "伯顿（Burden）的教师发展阶段论认为，教师在每一个发展的逻辑单元中一般经历三个阶段：求生存阶段、调整阶段、成熟阶段。选项B“适应阶段”不是伯顿提出的阶段名称，题干问“错误的是”，因此应选B。"}, {"type": "单选", "num": 244, "text": "英国高等教育双轨制的文件是（ ）。", "options": {"A": "《罗宾斯报告》", "B": "《高等教育：一个新的框架》", "C": "《高等教育法》", "D": "《国防教育法》"}, "answer": "B", "explanation": "教材在介绍英国“二战”后高等教育发展时，将1963年《罗宾斯报告》和1991年白皮书《高等教育：一个新的框架》区分为两个阶段：前者提出高等教育向所有成绩合格、有能力的人开放的原则，推动英国高等教育扩张；后者则“废除了高等教育的双轨制，建立了单一的高等教育体制”。因此本题若问与英国高等教育双轨制相关的文件，尤其按教材关于“废除双轨制”的表述，应选B。"}, {"type": "单选", "num": 245, "text": "以职业或进行某个专业领域的人才为基本目标的教育活动属于（ ）。", "options": {"A": "通识教育", "B": "技工教育", "C": "通才教育", "D": "专才教育"}, "answer": "D", "explanation": "专才教育（Specialist Education）以培养特定职业或专业领域的人才为目标，强调专门知识和技能的培养。"}, {"type": "单选", "num": 246, "text": "保障大学独立办学的地位，让大学作为民事主体开展民事活动，需要建立（ ）。", "options": {"A": "学术委员会制度", "B": "中介组织", "C": "基层组织", "D": "法人制度"}, "answer": "D", "explanation": "法人制度是保障大学独立办学地位的法律基础。高校取得法人资格后，才能作为独立的民事主体开展各种民事活动。"}, {"type": "单选", "num": 247, "text": "将充分发展，能够提供优质教学的教师称为\"非常教师\"的是（ ）。", "options": {"A": "苏霍姆林斯基", "B": "史蒂芬森", "C": "布鲁贝克", "D": "马克思·韦伯"}, "answer": "B", "explanation": "史蒂芬森（Stephenson）将充分发展、能够提供优质教学的教师称为\"非常教师\"（Extraordinary Teacher）。"}, {"type": "单选", "num": 248, "text": "高等学校教学工作中的\"学科设置与安排\"体现于（ ）。", "options": {"A": "课程标准", "B": "培养方案", "C": "教材", "D": "教学内容"}, "answer": "B", "explanation": "学科设置与安排是培养方案的重要内容。培养方案规定了专业的学科结构、课程体系和教学安排。"}, {"type": "单选", "num": 249, "text": "认为大学是传授普遍知识的场所，知识本身即为目的，教育是为了理智训练的是（ ）。", "options": {"A": "赫钦斯", "B": "洪堡", "C": "纽曼", "D": "布鲁纳"}, "answer": "C", "explanation": "纽曼在《大学的理想》中系统阐述了这一观点：大学是传授普遍知识的场所，知识本身就是目的，教育的价值在于理智训练，而非功利性目的。"}, {"type": "单选", "num": 250, "text": "某项教学活动的进程中，为使活动效果更好而不断进行的评价是（ ）。", "options": {"A": "总结性评价", "B": "形成性评价", "C": "相对性评价", "D": "诊断性评价"}, "answer": "B", "explanation": "在教学过程中不断进行的、旨在改进教学效果的评价是形成性评价。它提供即时反馈，帮助师生调整教与学的行为。"}, {"type": "单选", "num": 251, "text": "建构主义的知识观强调的知识特性是（ ）。", "options": {"A": "动态性", "B": "具体性", "C": "客观性", "D": "确定性"}, "answer": "A", "explanation": "建构主义知识观认为知识是动态的、不断发展的，而非静止不变的。知识是个体在与社会环境的互动中主动建构的，会随着认知发展而不断重构。"}, {"type": "单选", "num": 252, "text": "在大学决策上采取典型的双重结合模式的国家是（ ）。", "options": {"A": "英国", "B": "美国", "C": "中国", "D": "德国"}, "answer": "A", "explanation": "英国在大学决策上采取典型的双重结合模式，即行政权力与学术权力相互制衡、共同参与决策。"}, {"type": "单选", "num": 253, "text": "辅导员在与王明谈话时说:\"根据前段时间你的表现，虽然学习效果不很理想，但非常努力，如果注意改进学习方法，相信成绩会不断提高。\"辅导员对王明的评价属于（ ）。", "options": {"A": "总结性评价", "B": "鉴定性评价", "C": "诊断性评价", "D": "形成性评价"}, "answer": "D", "explanation": "辅导员的评价是在学习过程中进行的，目的是发现问题和提供改进建议，属于形成性评价。形成性评价强调反馈和改进。"}, {"type": "单选", "num": 254, "text": "高校科研管理的对象是人，对所有的科研人员要一视同仁，这体现了科研管理的（ ）原则？", "options": {"A": "协调性", "B": "自主性", "C": "公平性", "D": "重点性"}, "answer": "C", "explanation": "公平性原则要求对所有科研人员一视同仁，不偏不倚，在资源分配、评价标准等方面公平对待。"}, {"type": "单选", "num": 255, "text": "关于目标游离课程评价模式，表述错误的是（ ）。", "options": {"A": "提出者是斯克里文", "B": "主张课程目标与评价分离", "C": "强调对目标进行预先规定", "D": "主张评价不以目标为依据"}, "answer": "C", "explanation": "目标游离评价模式（Goal-Free Evaluation）恰恰反对预先规定目标，主张评价应超出预定目标范围，关注课程实施带来的全部结果（包括非预期结果）。"}, {"type": "单选", "num": 256, "text": "大众化阶段，高等学校的培养目标应当（ ）。", "options": {"A": "平民化", "B": "国际化", "C": "精英化", "D": "多样化"}, "answer": "D", "explanation": "大众化阶段，高等教育对象群体更加多元，社会需求更加多样，高校的培养目标应当多样化，满足不同群体的教育需求。"}, {"type": "单选", "num": 257, "text": "传统课程编制理论的典型代表是目标模式，这一理论的提出者是（ ）。", "options": {"A": "查特斯", "B": "博比特", "C": "斯坦豪斯", "D": "泰勒"}, "answer": "D", "explanation": "泰勒（Ralph Tyler）是目标模式的系统提出者，他在《课程与教学的基本原理》中确立了目标模式的基本框架。"}, {"type": "单选", "num": 258, "text": "泰勒提出的\"目标达成模式\"中的评价属于（ ）。", "options": {"A": "相对性评价", "B": "绝对性评价", "C": "总结性评价", "D": "形成性评价"}, "answer": "C", "explanation": "教材在介绍泰勒“目标达成模式”时明确指出，该模式“因其评价是终结性的结果评价”。在本题选项中，“终结性的结果评价”对应“总结性评价”。虽然该模式也以既定目标为标准，但本题依据教材原段落的分类表述，应选“总结性评价”。"}, {"type": "单选", "num": 259, "text": "因为其不符合科研的特点和规律，导致大量低水平成果的出现，而受到批评的科研管理方法是（ ）。", "options": {"A": "数学管理方法", "B": "专家管理方法", "C": "经济管理方法", "D": "行政管理方法"}, "answer": "A", "explanation": "数学管理方法（盲目追求论文数量、计件工分制等定量考核）严重违背科研的质性规律与长期性，是导致学术浮躁和大量低水平重复成果产生的制度根源。行政管理虽也受批评，但\"大量低水平成果\"这一特定因果关系在教材中对应的是数学管理。"}, {"type": "单选", "num": 260, "text": "以下哪项职能不属于高等学校的基本职能？", "options": {"A": "企业生产", "B": "社会服务", "C": "科学研究", "D": "人才培养"}, "answer": "A", "explanation": "高等学校的三大基本职能是：人才培养、科学研究和社会服务。企业生产不是高校的基本职能。"}, {"type": "单选", "num": 261, "text": "注重学生社会责任感和公民素质培养的教育类型是（ ）。", "options": {"A": "通识教育", "B": "专业教育", "C": "骑士教育", "D": "绅士教育"}, "answer": "A", "explanation": "通识教育（General Education）注重培养学生的社会责任感、公民素质、批判性思维和广泛的知识视野。专业教育侧重职业能力培养。"}, {"type": "单选", "num": 262, "text": "高校课程的本质属性是（ ）。", "options": {"A": "研究性", "B": "多样性", "C": "前沿性", "D": "专业性"}, "answer": "D", "explanation": "专业性（Professionalism）是高校课程的本质属性。高校课程按学科或职业分工设置，服务于培养各类专门人才的目标。"}, {"type": "单选", "num": 263, "text": "高校学生奖惩管理的基本原则是（ ）。", "options": {"A": "奖惩结合、以奖为主", "B": "物质奖励为主，精神鼓励为辅", "C": "奖惩结合、以罚为主", "D": "只能奖励，不能惩罚"}, "answer": "A", "explanation": "高校学生奖惩管理的基本原则是\"奖惩结合、以奖为主\"，即奖励与惩罚相结合，以正面激励为主导。"}, {"type": "单选", "num": 264, "text": "教学与教育这两个概念的关系是（ ）。", "options": {"A": "互斥关系", "B": "部分与整体", "C": "递进关系", "D": "并列关系"}, "answer": "B", "explanation": "教学与教育是部分与整体的关系。教学是教育的基本途径和重要组成部分，教育的内涵比教学更为广泛。"}, {"type": "单选", "num": 265, "text": "教师工作坊是高校教师教学发展中心的工作方式之一，下列描述错误的是（ ）。", "options": {"A": "教师工作坊不仅能为新教师提供培训和帮助，还能为老教师提供服务", "B": "教师工作坊可以邀请校内外教学名师主讲，交流成功经验和优良心得，也可以质疑诘难", "C": "教师工作坊由高校教师教学发展中心组织，校内需要帮助的教师必须参加", "D": "教师工作坊可以利用现代信息技术，提供\"网络工作坊\""}, "answer": "C", "explanation": "教师工作坊是自愿参加的，不是强制性的。\"校内需要帮助的教师必须参加\"说法错误，工作坊强调自愿参与和自主学习。"}, {"type": "单选", "num": 266, "text": "现代大学崇尚科学研究职能并使之制度化，这项改革始于（ ）。", "options": {"A": "牛津大学", "B": "中世纪大学", "C": "柏林大学", "D": "剑桥大学"}, "answer": "C", "explanation": "柏林大学（1810年）的创办标志着现代大学将科学研究纳入制度化轨道。洪堡提出\"教学与研究相统一\"的原则，使科研正式成为大学的职能。"}, {"type": "单选", "num": 267, "text": "个人本位论的代表人物不包括（ ）。", "options": {"A": "福禄贝尔", "B": "裴斯泰洛奇", "C": "孔德", "D": "卢梭"}, "answer": "C", "explanation": "孔德（Auguste Comte）是社会本位论的代表人物，而非个人本位论。福禄贝尔、裴斯泰洛奇和卢梭都是个人本位论的代表。"}, {"type": "单选", "num": 268, "text": "中世纪大学的主要职能是（ ）。", "options": {"A": "人才培养", "B": "科学研究", "C": "社会服务", "D": "发展宗教"}, "answer": "A", "explanation": "中世纪大学的主要职能是人才培养。它们主要培养神职人员、律师、医生等专业人才，科研和社会服务职能尚未出现。"}, {"type": "单选", "num": 269, "text": "高校课程组合基本上以知识为导向，以学科为经纬，结合社会需要进行安排和组织的，使得高校课程具有典型的（ ）。", "options": {"A": "针对性", "B": "多样性", "C": "专业性", "D": "前沿性"}, "answer": "C", "explanation": "高校课程以学科为经纬来组织，按学科分类设置课程，这是高等学校课程专业性的典型体现。"}, {"type": "单选", "num": 270, "text": "下面哪项不属于人才培养方案的内容？", "options": {"A": "专业培养目标", "B": "修业年限", "C": "教学计划", "D": "教学方法"}, "answer": "D", "explanation": "培养方案包括专业培养目标、修业年限、课程设置（教学计划）、学分要求、教学安排等。教学方法是教师在教学过程中具体运用的方式，不属于培养方案的内容。"}, {"type": "单选", "num": 271, "text": "下列有关终身教育理念的说法不正确的是（ ）。", "options": {"A": "学校教育不再享有教育的垄断权", "B": "学习贯穿人的一生", "C": "当地社会在终身教学体系中起着重要作用", "D": "终身教育从正规学校教育结束时开始"}, "answer": "D", "explanation": "终身教育不是从正规学校教育结束时才开始，而是贯穿人的一生，包括从出生到死亡的各个阶段，是持续不断的教育过程。"}, {"type": "单选", "num": 272, "text": "我国高等教育大众化正式启动的标志是（ ）。", "options": {"A": "《国家中长期教育改革和发展规划纲要（2010-2020年）》", "B": "《2000年中国教育绿皮书》", "C": "《面向21世纪教育振兴行动计划》", "D": "《中共中央、国务院关于深化教育改革全面推进素质教育的决定》"}, "answer": "C", "explanation": "教材原文指出，1999年国务院颁布《面向21世纪教育振兴行动计划》，提出到2010年使高等教育毛入学率达到15%；“行动计划”的颁布，标志着我国高等教育大众化正式启动。"}, {"type": "单选", "num": 273, "text": "自我意识的调节性由三部分构成，分别是自我认识、自我监控和（ ）。", "options": {"A": "自我发展", "B": "自我反省", "C": "自我教育", "D": "自我体验"}, "answer": "D", "explanation": "自我意识的调节性由自我认识（认知成分）、自我体验（情感成分）和自我监控（意志成分）三部分构成。"}, {"type": "单选", "num": 274, "text": "最能体现教学设计创造性的环节是（ ）。", "options": {"A": "教学评价的设计", "B": "教学策略的设计", "C": "教学媒体的设计", "D": "教学目标的设计"}, "answer": "B", "explanation": "教学策略的设计最能体现教学设计者的创造性。选择何种教学策略、如何组织教学活动、怎样创新教学方法，都需要教师发挥创造性。"}, {"type": "单选", "num": 275, "text": "哪所大学以其浓厚的重科研气息，使得世界高等教育中心转移到德国？", "options": {"A": "慕尼黑大学", "B": "哈勒大学", "C": "海德堡大学", "D": "柏林大学"}, "answer": "D", "explanation": "柏林大学的创办确立了\"教学与研究相统一\"的原则，使德国成为世界高等教育的中心（19世纪至20世纪初），吸引了大批国际学者。"}, {"type": "单选", "num": 276, "text": "在我国，有不少组织机构担负着促进高校教师教学发展的职责，下列不属于此类机构的是（ ）。", "options": {"A": "师资管理中心", "B": "教师工作坊", "C": "高校师资培训中心", "D": "教务处"}, "answer": "A", "explanation": "教材列举的促进高校教师教学发展的相关机构包括高校师资培训中心、教务处及其教研科、高等教育研究所、教师发展中心、教师教学能力发展中心等，未列“师资管理中心”。师资管理中心通常偏教师招聘、职称、考核等人事管理事务；教师工作坊虽然不是行政机构，但教材明确将其作为教师教学发展中心可采用的工作方式。因此本题按“不属于此类机构”选“师资管理中心”。"}, {"type": "单选", "num": 277, "text": "西方国家提出\"美德即知识\"的思想家是（ ）。", "options": {"A": "苏格拉底", "B": "柏拉图", "C": "亚里士多德", "D": "夸美纽斯"}, "answer": "A", "explanation": "苏格拉底提出了\"美德即知识\"（Virtue is Knowledge）的著名命题，认为道德的根源在于知识，无知是罪恶的根源。"}, {"type": "单选", "num": 278, "text": "下列国家中，实施交叉型学术职业阶梯结构的是（ ）。", "options": {"A": "法国", "B": "德国", "C": "意大利", "D": "美国"}, "answer": "A", "explanation": "法国实施交叉型学术职业阶梯结构。学术职业阶梯结构分为单一型（德国、意大利）、多重型（美国）和交叉型（法国）。法国的大学与大学校（Grandes Écoles）并行的双轨制允许学术人员在两类机构之间交叉流动，形成交叉型结构。"}, {"type": "单选", "num": 279, "text": "\"威斯康星思想\"代表的是大学哪项职能？", "options": {"A": "科学研究职能", "B": "社会服务职能", "C": "教学职能", "D": "人才培养职能"}, "answer": "B", "explanation": "\"威斯康星思想\"（Wisconsin Idea）的核心是大学为社会服务，强调大学应走出校园，将知识应用于解决社会现实问题，标志着社会服务成为大学的第三职能。"}, {"type": "单选", "num": 280, "text": "案例教学法的中心环节是（ ）。", "options": {"A": "课前准备", "B": "教学设计", "C": "教学评价", "D": "课堂讨论"}, "answer": "D", "explanation": "课堂讨论是案例教学法的中心环节。学生围绕案例进行分析、讨论、辩论，在互动中深化理解、培养分析问题和解决问题的能力。"}, {"type": "单选", "num": 281, "text": "高校科研评价中存在不重视科研对教学的促进作用，偏离高校育人的基本职能的问题，这种问题属于（ ）。", "options": {"A": "重短期轻长期", "B": "重科研轻教学", "C": "重数量轻质量", "D": "重形式轻实质"}, "answer": "B", "explanation": "教材在“重科研轻教学”部分指出，当前科研评价片面强调科研，不重视对教师教学的评价，也不重视科研对教学的促进作用，偏离高校育人的基本职能。题干正对应这一问题，因此应选“重科研轻教学”。"}, {"type": "单选", "num": 282, "text": "为了广泛收集教学信息，对教学质量进行评价和诊断，高校离不开（ ）。", "options": {"A": "教学质量保障组织系统", "B": "教学质量监控与评价系统", "C": "教学质量保障激励系统", "D": "教学质量保障支持系统"}, "answer": "B", "explanation": "教学质量监控与评价系统负责广泛收集教学信息、评价教学质量、诊断教学问题，是教学质量保障体系的核心部分。"}, {"type": "单选", "num": 283, "text": "绿色\"GDP\"占\"GDP\"的比重越高，表明了国民经济增长的（ ）。", "options": {"A": "负面效应低", "B": "正面效应低", "C": "无影响", "D": "负面效应高"}, "answer": "A", "explanation": "绿色GDP是指在传统GDP中扣除环境资源损失后得到的结果。绿色GDP占比越高，说明经济增长对环境的负面效应越低，发展越可持续。"}, {"type": "单选", "num": 284, "text": "以学分为计量单位衡量学生是否达到培养目标和要求，这种教学运行制度属于（ ）。", "options": {"A": "选修制", "B": "顶岗实习制", "C": "学分制", "D": "学年制"}, "answer": "C", "explanation": "学分制以学分为计量单位衡量学生的学习量，学生通过修读课程获得学分，达到规定的总学分即可毕业。学分制具有灵活性高的特点。"}, {"type": "单选", "num": 285, "text": "学习能力评价应遵循的原则不包括（ ）。", "options": {"A": "统一性原则", "B": "激励性原则", "C": "多样化原则", "D": "发展性原则"}, "answer": "A", "explanation": "学习能力评价更强调发展性、激励性和多样化原则，统一性（标准化）不宜作为学习能力评价的核心原则，因为学习能力评价更注重个体差异和发展性。"}, {"type": "单选", "num": 286, "text": "中国高等教育毛入学率达到15%，步入大众高等教育阶段的年份是（ ）。", "options": {"A": "2015年", "B": "2002年", "C": "1998年", "D": "1995年"}, "answer": "B", "explanation": "2002年，中国高等教育毛入学率达到15%，标志着我国高等教育从精英化阶段进入大众化阶段。"}, {"type": "单选", "num": 287, "text": "中世纪的巴黎大学设有文学院、神学院、法学院和医学院，其中属于低级学院的是（ ）。", "options": {"A": "神学院", "B": "法学院", "C": "文学院", "D": "医学院"}, "answer": "C", "explanation": "中世纪大学中文学院（艺学院）是低级学院，学生必须先进入文学院学习\"七艺\"等基础课程，然后才能进入高级学院（神学、法学、医学）深造。"}, {"type": "单选", "num": 288, "text": "20世纪末以来，关于国家高等教育系统的管理模式下列说法不正确的是（ ）。", "options": {"A": "市场力量不断增强", "B": "学术影响力受到限制，逐渐失去传统的影响力", "C": "国家角色由控制者向监督者转变", "D": "伴随着高校走向自治，院校一级的行政管理权力减小"}, "answer": "D", "explanation": "随着高校走向自治，院校一级的行政管理权力实际上是增大的，而不是减小。高校自主权扩大，院校管理层在决策中发挥更大作用。"}, {"type": "单选", "num": 289, "text": "现代大学理念的时代内涵不包括（ ）。", "options": {"A": "针对性或适切性", "B": "国际化", "C": "功利性", "D": "追求高深学问"}, "answer": "C", "explanation": "现代大学理念的时代内涵包括追求高深学问、国际化和针对性（适切性）。功利性不是大学理念的应有内涵，大学应超越功利追求。"}, {"type": "单选", "num": 290, "text": "实用主义大学理念的代表人物是（ ）。", "options": {"A": "范海斯", "B": "洪堡", "C": "赫钦斯", "D": "阿德勒"}, "answer": "A", "explanation": "范海斯（Charles Van Hise）在担任威斯康星大学校长期间（1904-1918年）提出了\"威斯康星计划\"，是实用主义大学理念的代表人物。"}, {"type": "单选", "num": 291, "text": "下列课程中，不属于按管理层次划分的课程是（ ）。", "options": {"A": "校本课程", "B": "乡土课程", "C": "地方课程", "D": "国家课程"}, "answer": "B", "explanation": "按管理层次划分，课程分为国家课程、地方课程和校本课程三级。\"乡土课程\"不是按管理层次划分的课程类型，而是以内容特色命名的课程。"}, {"type": "单选", "num": 292, "text": "早在大学产生之初，教师们借助与基督教会的身份同构使得教师具有（ ）。", "options": {"A": "宗教性", "B": "神圣性", "C": "独立性", "D": "自由性"}, "answer": "B", "explanation": "早期大学教师借助与基督教会的身份同构，获得了神圣性——教师被视为知识的传播者和真理的守护者，享有崇高的社会地位和身份认同。"}, {"type": "单选", "num": 293, "text": "以下哪种活动不属于教育教学领域的市场化行动？", "options": {"A": "关注市场需求", "B": "教育课程模块化及标准化", "C": "收取或提高学费", "D": "聘请兼职教授"}, "answer": "D", "explanation": "聘请兼职教授是高校正常的人事聘任工作，不属于市场化行动。关注市场需求、课程模块化和标准化、收取学费都是教育市场化的表现。"}, {"type": "单选", "num": 294, "text": "高校教师运用研讨法，组织有效的教学讨论的前提是（ ）。", "options": {"A": "主体明确，准备充分", "B": "营造气氛，引导讨论", "C": "做好课堂发言记录", "D": "进行诊断性评价"}, "answer": "A", "explanation": "组织有效的教学讨论，前提是主题明确、准备充分。教师和学生都需要提前做好充分准备，明确讨论的主题和目标。"}, {"type": "单选", "num": 295, "text": "根据高等教育大众化理论，用高等教育毛入学率来表征，进入普及化阶段的指标是（ ）。", "options": {"A": "超过30%", "B": "超过40%", "C": "超过50%", "D": "超过60%"}, "answer": "C", "explanation": "马丁·特罗的高等教育发展阶段理论：毛入学率<15%为精英化阶段，15%-50%为大众化阶段，>50%为普及化阶段。"}, {"type": "单选", "num": 296, "text": "主张通识教育的人才培养模式表现为（ ）。", "options": {"A": "宽口径、厚基础", "B": "宽口径、薄基础", "C": "窄口径、厚基础", "D": "窄口径、薄基础"}, "answer": "A", "explanation": "通识教育主张\"宽口径、厚基础\"，即拓宽学生的知识面、夯实基础，注重综合素质和广泛的知识视野。"}, {"type": "单选", "num": 297, "text": "大学组织各管理层次的纵向结构，属于（ ）。", "options": {"A": "部门结构", "B": "职权结构", "C": "职能结构", "D": "层次结构"}, "answer": "D", "explanation": "层次结构是指组织纵向的管理层级划分。大学组织的校、院（系）、教研室等纵向层级构成了层次结构。"}, {"type": "单选", "num": 298, "text": "根据古德莱德对课程的分类，学生在课堂上通过教师的讲解实际学习到知识和经验的课程属于（ ）。", "options": {"A": "经验课程", "B": "运作课程", "C": "领悟课程", "D": "正式课程"}, "answer": "A", "explanation": "古德莱德五层课程中，运作课程是教师在班级教学时实际执行的课程，经验课程是学生实际学习或获取经验的课程。题干强调“学生在课堂上通过教师的讲解实际学习到知识和经验”，落点在学生实际获得的经验，因此应选“经验课程”。"}, {"type": "单选", "num": 299, "text": "学校组织的美术展、书画、文学、诗歌等社团发展学生个性，属于什么课程？", "options": {"A": "非正式课程", "B": "正式课程", "C": "隐性课程", "D": "显性课程"}, "answer": "C", "explanation": "教材在“显性课程与隐性课程”部分指出，大学生还会受到学校组织、校园文化和师生相互作用的影响，这些非正式的隐性课程会给学生以价值上、规范上的陶冶和潜移默化的影响。教材随后举学生社团、协会、学会等组织通过美术、书法、文学、诗歌等形式发展学生个性的例子，说明其属于隐性课程。"}, {"type": "单选", "num": 300, "text": "高等学校是以（ ）为基础的机构。", "options": {"A": "知识", "B": "经济", "C": "技能", "D": "就业"}, "answer": "A", "explanation": "高等学校是以知识为基础的机构。大学从事知识的传授、生产、传播和应用，知识是大学一切活动的根基。"}, {"type": "单选", "num": 301, "text": "认为大学是作为知识的生产者、批发商和零售商，既要为社会提供服务，也为每个人服务的思想流派是（ ）。", "options": {"A": "工具主义", "B": "结构主义", "C": "存在主义", "D": "新保守主义"}, "answer": "A", "explanation": "工具主义大学理念将大学视为知识的生产者、批发商和零售商，强调大学的社会服务功能和工具价值。"}, {"type": "单选", "num": 302, "text": "提出\"学会认知，学会做事，学会共同生活和学会生存\"的联合国报告是（ ）。", "options": {"A": "《学会生存——21世纪的教育改革》", "B": "《论终生教育》", "C": "《教育——财富蕴藏其中》", "D": "《推进终身教育事业发展》"}, "answer": "C", "explanation": "1996年联合国教科文组织发布《教育——财富蕴藏其中》（Learning: The Treasure Within）报告，提出了教育的四大支柱：学会认知、学会做事、学会共同生活、学会生存。"}, {"type": "单选", "num": 303, "text": "大学的中间管理层负责执行学校的各种决策，指学校的（ ）。", "options": {"A": "专业学院", "B": "职能部门", "C": "校务委员会", "D": "图书馆"}, "answer": "B", "explanation": "教材将大学组织结构分为战略制定层、中间管理层和操作人员层。其中，中间管理层指学校各个职能部门，负责执行学校的各种决策；院系等基层组织属于操作人员层。"}, {"type": "单选", "num": 304, "text": "高校教学质量保障体系有四个组成要素，其中描述错误的是（ ）。", "options": {"A": "教学质量保障标准系统", "B": "教学质量保障激励系统", "C": "教学质量监控与评价系统", "D": "教学质量保障组织系统"}, "answer": "A", "explanation": "教材列出的高校教学质量保障体系四个组成要素是：教学质量保障组织系统、教学质量监控与评价系统、教学质量保障激励系统、教学质量保障支持系统。“教学质量保障标准系统”不在这四项之中。"}, {"type": "多选", "num": 1, "text": "高等教育大众化的动因包括（ ）。", "options": {"A": "知识经济时代的到来", "B": "社会民主化与个人权利意识的增强", "C": "社会财富的积累", "D": "互联网技术的发展"}, "answer": "ABCD", "explanation": "高等教育大众化的动因包括知识经济时代的到来、社会民主化与个人权利意识的增强，以及社会财富的积累与互联网技术的发展。教材将“社会财富的积累与互联网技术的发展”合并作为重要动因之一，因此四项均应选。"}, {"type": "多选", "num": 2, "text": "大学教师工作的主要特点包括（ ）。", "options": {"A": "创造性", "B": "保守性", "C": "复杂性", "D": "专业性"}, "answer": "ACD", "explanation": "大学教师工作的主要特点包括：创造性（知识创新）、复杂性（多重角色）、专业性（学科专长）。保守性不是大学教师工作的特点。"}, {"type": "多选", "num": 3, "text": "高校课程目标评价的主要内容包括（ ）。", "options": {"A": "课程目标实现的可行性", "B": "课程目标与培养目标的一致性", "C": "课程目标表述的准确性", "D": "课程目标的人文性"}, "answer": "ABC", "explanation": "课程目标评价的主要内容包括：目标与培养目标的一致性、目标实现的可行性、目标表述的准确性。\"人文性\"不是课程目标评价的核心内容。"}, {"type": "多选", "num": 4, "text": "世界上各国形成了多种类型的学术职业阶梯结构，主要包括（ ）。", "options": {"A": "单一型", "B": "多重型", "C": "交叉型", "D": "双重型"}, "answer": "ABC", "explanation": "世界各国的学术职业阶梯结构主要分为三种类型：单一型（如德国、意大利）、多重型（如美国）和交叉型（如法国）。\"双重型\"不是标准分类。"}, {"type": "多选", "num": 5, "text": "高校战略是重大谋划与策略，它的特性包括（ ）。", "options": {"A": "可操作性", "B": "全局性", "C": "系统性", "D": "短期性"}, "answer": "ABC", "explanation": "高校战略的特性包括：全局性（涉及整体发展）、系统性（各要素有机统一）、可操作性（能够落实执行）。短期性不是战略的特征，战略着眼于长远发展。"}, {"type": "多选", "num": 6, "text": "美国在二战之后颁布的一系列相关法案极大地推动了高等教育的迅速发展，这些法案包括（ ）。", "options": {"A": "《高等教育设施法》", "B": "《高等教育法》", "C": "《退伍军人权利法案》", "D": "《国防教育法》"}, "answer": "ABCD", "explanation": "这四个法案都对美国战后高等教育发展起到了重要推动作用。《退伍军人权利法案》（GI Bill）使大量退伍军人进入大学；《国防教育法》（1958）加强了科技教育；《高等教育设施法》和《高等教育法》提供了资金支持。"}, {"type": "多选", "num": 7, "text": "我国高等学校教师职务根据学校所承担的教学、科学研究等任务的需要设置，包括（ ）。", "options": {"A": "助教", "B": "讲师", "C": "副教授", "D": "教授"}, "answer": "ABCD", "explanation": "我国高校教师职务分为四个等级：助教、讲师、副教授、教授，是根据学校承担的教学、科研任务需要来设置的。"}, {"type": "多选", "num": 8, "text": "心理健康教育是高校学生教育的重要内容，以下说法正确的是（ ）。", "options": {"A": "立足于创新增添心理健康教育的内容", "B": "把提高心理素质作为心理健康教育的重点", "C": "建立有效运行心理健康教育的机制", "D": "建设多方联动心理健康教育的模式"}, "answer": "ABCD", "explanation": "高校心理健康教育需要创新内容（A）、以提升心理素质为重点（B）、建立有效运行机制（C）、建设多方联动模式（D），以上说法均正确。"}, {"type": "多选", "num": 9, "text": "2001年至2005年是高等教育结构调整阶段，高等教育发展出现新的增长点包括（ ）。", "options": {"A": "民办高等教育", "B": "高等职业院校", "C": "大学本科学校", "D": "地方高等院校"}, "answer": "ABD", "explanation": "2001年至2005年是我国高等教育结构调整阶段。教材指出，这一时期地方高等院校、民办高等教育、高等职业教育得到扩展，成为高等教育发展新的增长点。因此应选A、B、D。"}, {"type": "多选", "num": 10, "text": "通识教育课程的主要领域包括（ ）。", "options": {"A": "生命科学", "B": "自然科学", "C": "社会科学", "D": "人文科学"}, "answer": "BCD", "explanation": "通识教育课程的三大传统领域是自然科学（B）、社会科学（C）和人文科学（D）。生命科学（A）在学理上包含在自然科学的大类之中，多选题中为避免子概念与母概念并列，通常不单独选A。"}, {"type": "多选", "num": 11, "text": "我国高等学校的教师取得助教、讲师、副教授、教授职务时应当具备的条件包括（ ）。", "options": {"A": "取得高等学校教师资格", "B": "系统掌握本学科的基础理论", "C": "具备相应职务的教学和科研能力", "D": "承担相应职务的课程和规定课时的教学任务"}, "answer": "ABCD", "explanation": "《高等教育法》规定，高校教师取得相应职务应具备：高等学校教师资格（A）、系统掌握本学科基础理论（B）、具备相应教学科研能力（C）、承担规定教学任务（D）。"}, {"type": "多选", "num": 12, "text": "学科质量评价标准涉及的主要内容包括（ ）。", "options": {"A": "人才培养质量", "B": "研究成果", "C": "社会实践", "D": "学术人员"}, "answer": "ABD", "explanation": "学科质量评价的主要内容包括：人才培养质量（A）、研究成果（B）和学术人员（D）。社会实践不是学科质量评价的直接内容。"}, {"type": "多选", "num": 13, "text": "对培养方案评价的主要内容包括（ ）。", "options": {"A": "课程目标的评价", "B": "指导思想的评价", "C": "课程标准的评价", "D": "课程设置的评价"}, "answer": "ABD", "explanation": "对培养方案评价的主要内容包括：课程目标的评价（A）、指导思想的评价（B）和课程设置的评价（D）。课程标准评价（C）属于更下位的课程文件评价，不属于培养方案层面的主要内容。"}, {"type": "多选", "num": 14, "text": "高校科研活动管理应遵循的原则包括（ ）。", "options": {"A": "重点性", "B": "公平性", "C": "自主性", "D": "协调性"}, "answer": "ABCD", "explanation": "高校科研管理应遵循的原则包括：重点性原则（突出重点）、公平性原则（公平对待）、自主性原则（尊重学术自由）和协调性原则（协调各方关系）。"}, {"type": "多选", "num": 15, "text": "高校教学任务的完成，需要处理的关系有（ ）。", "options": {"A": "课程知识与课程体系的关系", "B": "整体要求与因材施教的关系", "C": "学生引导与教师探究的关系", "D": "掌握知识与发展能力的关系"}, "answer": "ABD", "explanation": "高校教学任务需处理的关系包括：课程知识与课程体系（A）、整体要求与因材施教（B）、掌握知识与发展能力（D）。\"学生引导与教师探究\"（C）表述反常，通常应为教师引导与学生探究，故不选。"}, {"type": "多选", "num": 16, "text": "高校学生的生理发展特征包括（ ）。", "options": {"A": "从生长发育期步入生长稳定期", "B": "处于内分泌腺发育和性成熟阶段", "C": "神经系统发育基本成熟", "D": "身高体重停止增长"}, "answer": "ABC", "explanation": "高校学生的生理发展特征：生长发育趋于稳定（A）、内分泌和性成熟（B）、神经系统基本成熟（C）。身高体重并未停止增长，只是增长速度放缓（D错误）。"}, {"type": "多选", "num": 17, "text": "古希腊传统的四美德指（ ）。", "options": {"A": "节制、勇敢", "B": "爱智、公正", "C": "治国、平天下", "D": "修身、齐家"}, "answer": "AB", "explanation": "古希腊四美德（四枢德）为：智慧（爱智）、勇敢、节制、公正。C和D出自中国古代典籍。"}, {"type": "多选", "num": 18, "text": "北京大学提倡\"兼容并包\"的大学理念，由此形成的校风是（ ）。", "options": {"A": "严谨", "B": "民主", "C": "自由", "D": "认真"}, "answer": "BC", "explanation": "蔡元培在北大推行\"思想自由、兼容并包\"方针，由此形成了民主和自由的校风。"}, {"type": "多选", "num": 19, "text": "各国高校的课程改革重点各不相同，但总体上仍然具有共同趋势，表现为（ ）。", "options": {"A": "注重人文，实施\"全人教育\"", "B": "面向未来，课程设置国际化与信息化", "C": "拓宽基础，加强普通教育", "D": "跨越学科实施课程整合"}, "answer": "ABCD", "explanation": "各国高校课程改革的共同趋势：重视人文教育和全人教育（A）、课程国际化与信息化（B）、拓宽基础和通识教育（C）、跨学科整合课程（D）。"}, {"type": "多选", "num": 20, "text": "高等学校专业培养方案的主要内容包括（ ）。", "options": {"A": "课程设置", "B": "专业培养目标和基本规格", "C": "时间分配", "D": "主要教学活动"}, "answer": "ABCD", "explanation": "培养方案（教学计划）的主要内容包括：专业培养目标和规格（B）、课程设置（A）、时间分配（C）和主要教学活动安排（D）。"}, {"type": "多选", "num": 21, "text": "社会本位论的代表人物包括（ ）。", "options": {"A": "孔德", "B": "赫尔巴特", "C": "涂尔干", "D": "卢梭"}, "answer": "ABC", "explanation": "社会本位论的代表人物有孔德（A）、赫尔巴特（B）和涂尔干（C）。卢梭（D）是个人本位论的代表。"}, {"type": "多选", "num": 22, "text": "教学设计结果的评价主要有（ ）。", "options": {"A": "总结性评价", "B": "诊断性评价", "C": "目的性评价", "D": "形成性评价"}, "answer": "AD", "explanation": "教材明确指出，教学设计结果的评价主要有两种形式，即形成性评价和总结性评价，一般以形成性评价为主。诊断性评价属于其他评价语境，不是此处“教学设计结果评价”的主要形式。"}, {"type": "多选", "num": 23, "text": "中国高等教育大众化面临的挑战包括（ ）。", "options": {"A": "结构调整", "B": "经费问题", "C": "就业问题", "D": "质量问题"}, "answer": "ABCD", "explanation": "中国高等教育大众化面临的四大挑战：结构调整（A，科类、层次、区域结构）、经费问题（B，投入不足）、就业问题（C，毕业生就业压力）、质量问题（D，教学质量保障）。"}, {"type": "多选", "num": 24, "text": "学术专业群体赢得合法性、实现合法化的主要方式包括（ ）。", "options": {"A": "同行评价认可", "B": "外部权威认可", "C": "个体内部评价认可", "D": "顾客评价和市场认可"}, "answer": "ABD", "explanation": "教材指出，学术专业群体赢得合法性、实现合法化的方式主要有三种：外部权威认可、同行评价认可、顾客评价和市场认可。因此应选A、B、D。"}, {"type": "多选", "num": 25, "text": "高校学生服务的具体内容包括（ ）。", "options": {"A": "就业服务", "B": "婚恋服务", "C": "入学服务", "D": "学业服务"}, "answer": "ACD", "explanation": "高校学生服务的三个核心内容：入学服务（招生、注册）、学业服务（学习过程支持）和就业服务（职业指导、推荐就业）。婚恋服务不是高校学生服务的常规内容。"}, {"type": "多选", "num": 26, "text": "终身学习的特征主要包括（ ）。", "options": {"A": "以学习化社会为前提", "B": "以个人自发意愿为基础", "C": "是持续人一生的生活方式", "D": "教育功能扩大至整个社会"}, "answer": "ABCD", "explanation": "终身学习的特征：以学习化社会为前提（A）、以个人自发意愿为基础（B）、贯穿人一生的持续过程（C）、教育功能扩大至全社会（D）。"}, {"type": "多选", "num": 27, "text": "马丁·特罗提出工业化社会的高等教育都将经历三个发展阶段，分别是（ ）。", "options": {"A": "精英化阶段", "B": "大众化阶段", "C": "普及化阶段", "D": "全民化阶段"}, "answer": "ABC", "explanation": "马丁·特罗提出的高等教育三阶段：精英化（<15%）→大众化（15%-50%）→普及化（>50%）。\"全民化阶段\"不是特罗的分类。"}, {"type": "多选", "num": 28, "text": "关于《莫雷尔法案》说法正确的是（ ）。", "options": {"A": "引发高等学校第二项职能的出现", "B": "引发高等教育社会服务职能的出现", "C": "该法案又称为《赠地法案》", "D": "导致了一批农工学院和州立大学的建立"}, "answer": "BCD", "explanation": "《莫雷尔法案》即《赠地法案》（C），建立了赠地学院（D），引发了高等教育社会服务职能的出现（B）。注意科研是第二职能，社会服务是第三职能，A错误。"}, {"type": "多选", "num": 29, "text": "根据组织理论，大学组织层次可以为（ ）。", "options": {"A": "操作人员层", "B": "中间管理层", "C": "战略制定层", "D": "监督控制层"}, "answer": "ABC", "explanation": "根据组织理论，大学组织层次分为：战略制定层（最高决策层）、中间管理层（执行层）和操作人员层（基层工作人员）。监督控制层不是独立层次。"}, {"type": "多选", "num": 30, "text": "在《论语》一书中体现倡导教师精神的是（ ）。", "options": {"A": "教学相长", "B": "以身作则", "C": "诲人不倦", "D": "学而不厌"}, "answer": "ABCD", "explanation": "教材在介绍孔子教育思想时明确说，孔子还倡导教师要有以身作则、教学相长、学而不厌、诲人不倦的精神，并说明“这些思想都散见于《论语》一书中”。虽然“教学相长”作为固定表述常见于《学记》，但本题按教材关于《论语》思想体现的表述，应选ABCD。"}, {"type": "多选", "num": 31, "text": "大学生在大学中所扮演的角色包括（ ）。", "options": {"A": "消费者", "B": "学校管理参与者", "C": "学习者", "D": "来访者"}, "answer": "ABC", "explanation": "大学生在大学中的角色包括：学习者（A，核心角色）、学校管理参与者（B，参与治理）和消费者（C，教育服务接受者）。来访者（D）不是大学生在校期间的角色。"}, {"type": "多选", "num": 32, "text": "教学产品设计的对象包括（ ）。", "options": {"A": "网络课程", "B": "教学环境", "C": "教师用书", "D": "多媒体软件"}, "answer": "ABCD", "explanation": "教学产品设计涵盖教学过程中使用的各种产品：网络课程（A）、教学环境（B，如教室布局）、教师用书（C）和多媒体软件（D）。"}, {"type": "多选", "num": 33, "text": "大学权力主体的多元化表现为（ ）。", "options": {"A": "权力非中心化", "B": "层次的多样化", "C": "等级结构的多样化", "D": "部门的多样化"}, "answer": "ABCD", "explanation": "教材在“权力主体多元化”下依次列出四种表现：部门的多样化、等级结构的多样化、层次的多样化、权力非中心化。四个选项均属大学权力主体多元化的表现。"}, {"type": "多选", "num": 34, "text": "伯顿的教师发展阶段论认为教师生涯循环发展一般会经历哪三个阶段？", "options": {"A": "能力准备阶段", "B": "求生存阶段", "C": "调整阶段", "D": "成熟阶段"}, "answer": "BCD", "explanation": "伯顿（Burden）的教师发展阶段论认为，教师在每一发展单元中经历三个阶段：求生存阶段（B，关注自我生存）→调整阶段（C，适应和调整）→成熟阶段（D，稳定和成熟）。"}, {"type": "多选", "num": 35, "text": "高等教育的资本市场包括（ ）。", "options": {"A": "高校贷款", "B": "学生贷款", "C": "融资设立营利性高等教育机构", "D": "高校拆借市场"}, "answer": "ABC", "explanation": "高等教育资本市场的主要形式包括：高校贷款（A）、学生贷款（B）和融资设立营利性教育机构（C）。\"高校拆借市场\"是干扰项。"}, {"type": "多选", "num": 36, "text": "中国古人对教师的理想期待包括（ ）。", "options": {"A": "\"劳心\"的统治者", "B": "\"解惑\"的学者", "C": "授业的\"经师\"", "D": "传道的\"人师\""}, "answer": "BCD", "explanation": "韩愈《师说》中：\"师者，所以传道受业解惑也。\"古人期待教师是传道的\"人师\"（D）、授业的\"经师\"（C）和解惑的学者（B）。\"劳心\"的统治者不符合教师形象。"}, {"type": "多选", "num": 37, "text": "下列属于隐性课程的是（ ）。", "options": {"A": "校规", "B": "校风", "C": "班会", "D": "校园文化"}, "answer": "ABD", "explanation": "隐性课程是通过学校自然环境和社会环境对学生产生潜移默化影响的课程。校规、校风和校园文化都属于学校环境与规范文化的重要组成部分，能对学生产生价值和规范上的陶冶。班会是有目的、有计划、有组织的教育活动，更接近显性课程，因此不选C。"}, {"type": "多选", "num": 38, "text": "课程标准也称教学大纲，形式上包括（ ）。", "options": {"A": "主体部分", "B": "说明部分", "C": "考试大纲", "D": "附录部分"}, "answer": "ABD", "explanation": "教材指出，课程标准在形式上一般包括说明部分、主体部分和附录部分。考试大纲不是课程标准的标准组成部分，因此应选A、B、D。"}, {"type": "多选", "num": 39, "text": "高校课程编制是一项系统工程，涉及人员有（ ）。", "options": {"A": "教师", "B": "学生", "C": "院系领导", "D": "课程专家"}, "answer": "ABCD", "explanation": "高校课程编制涉及多方人员：教师（A，课程实施者）、学生（B，课程接受者）、院系领导（C，组织管理者）和课程专家（D，专业指导者）。"}, {"type": "多选", "num": 40, "text": "高等学校教学的主要特征包括（ ）。", "options": {"A": "教学对象的差异性", "B": "教学过程的探究性", "C": "教学本质的专业性", "D": "教学内容的高深性"}, "answer": "ABCD", "explanation": "高校教学的主要特征：教学对象的差异性（A，学生背景多元）、教学过程的探究性（B，教学与科研结合）、教学本质的专业性（C，专业教育）和教学内容的高深性（D，高深学问）。"}, {"type": "多选", "num": 41, "text": "美国学者伯顿·克拉克的观点，在高等教育的运作中一直有三股力量，分别是（ ）。", "options": {"A": "民间组织", "B": "国家权力", "C": "市场力量", "D": "学术权威"}, "answer": "BCD", "explanation": "伯顿·克拉克提出高等教育运作的三角协调模型：国家权力（B）、市场力量（C）和学术权威（D）三者相互作用、动态平衡。"}, {"type": "多选", "num": 42, "text": "教学的有效性包含的三重意蕴是（ ）。", "options": {"A": "有效果", "B": "有效率", "C": "有效益", "D": "有奖励"}, "answer": "ABC", "explanation": "教学有效性包含三重意蕴：有效果（A，达成目标）、有效率（B，投入产出比）和有效益（C，教育价值）。\"有奖励\"不是有效性的标准内涵。"}, {"type": "多选", "num": 43, "text": "个人本位论的代表人物包括（ ）。", "options": {"A": "洛克", "B": "柏拉图", "C": "福禄倍尔", "D": "裴斯泰洛齐"}, "answer": "ACD", "explanation": "个人本位论的代表人物：洛克（A）、福禄倍尔（C）、裴斯泰洛齐（D）。柏拉图（B）主张理想国和社会分工，倾向于社会本位论。"}, {"type": "多选", "num": 44, "text": "国家联合各部门出台的资助高校贫困家庭学生的政策和措施主要包括（ ）。", "options": {"A": "开展国家助学贷款", "B": "实行学费减免", "C": "设立奖助学金", "D": "开辟新生入学\"绿色通道\""}, "answer": "ABCD", "explanation": "高校贫困生资助体系包括：国家助学贷款（A）、学费减免（B）、奖助学金（C）和\"绿色通道\"（D，先入学后缴费）。"}, {"type": "多选", "num": 45, "text": "下列说法正确的是（ ）。", "options": {"A": "当代国际化的行动主体变成更加复杂", "B": "国际化，只是高等院校的行动", "C": "在当代国家或地区成为高等教育国际化的推动者", "D": "当代高等教育国际化的支持系统加强"}, "answer": "ACD", "explanation": "当代高等教育国际化：行动主体更加多元化（A，包括国家、高校、国际组织等），国家或地区成为重要推动者（C），支持系统不断加强（D）。国际化不只是高等院校的行动（B错误）。"}, {"type": "多选", "num": 46, "text": "被人类文化史上称为\"智慧的花朵\"的中世纪大学有（ ）。", "options": {"A": "牛津大学", "B": "剑桥大学", "C": "波伦亚大学", "D": "萨莱诺大学"}, "answer": "ABCD", "explanation": "被文化史上称为\"智慧的花朵\"的中世纪大学包括波伦亚大学（C）、萨莱诺大学（D），以及牛津大学（A）和剑桥大学（B）。这四所大学都是中世纪大学的杰出代表。"}, {"type": "多选", "num": 47, "text": "规范的教学目标一般应包括的要素有（ ）。", "options": {"A": "标准", "B": "条件", "C": "行为", "D": "对象"}, "answer": "ABCD", "explanation": "规范的教学目标应包含四个要素（ABCD法）：对象（Audience，谁学）、行为（Behavior，做什么）、条件（Condition，在什么条件下）和标准（Degree，达到什么程度）。"}, {"type": "多选", "num": 48, "text": "高等学校教学设计过程中普遍的、必须思考的核心问题有（ ）。", "options": {"A": "方法设计", "B": "评价监控设计", "C": "教学目标的制定", "D": "内容设计"}, "answer": "ABCD", "explanation": "高校教学设计需思考的核心问题：教学目标制定（C，为什么教）、内容设计（D，教什么）、方法设计（A，怎么教）和评价监控设计（B，教得怎样）。"}, {"type": "多选", "num": 49, "text": "大学精神文化的元素包括（ ）。", "options": {"A": "大学理念", "B": "大学精神", "C": "学风", "D": "校训"}, "answer": "ABCD", "explanation": "大学精神文化元素包括：大学理念（A，办学的指导思想）、大学精神（B，精神核心）、学风（C，学习风气）和校训（D，价值标识）。"}, {"type": "多选", "num": 50, "text": "蔡元培在改革北京大学时提出的治校理念是（ ）。", "options": {"A": "允公允能", "B": "兼容并包", "C": "思想自由", "D": "厚德载物"}, "answer": "BC", "explanation": "蔡元培改革北大的治校理念是\"思想自由\"（C）和\"兼容并包\"（B）。\"允公允能\"是南开大学校训，\"厚德载物\"是清华大学校训的一部分。"}, {"type": "多选", "num": 51, "text": "高等教育目的制定的依据是（ ）。", "options": {"A": "高校培养目标", "B": "马克思关于人的全面发展学说", "C": "人的身心发展规律和需要", "D": "社会发展需要"}, "answer": "BCD", "explanation": "高等教育目的制定的依据：马克思关于人的全面发展学说（B，理论基础）、人的身心发展规律和需要（C，个人依据）和社会发展需要（D，社会依据）。培养目标是教育目的的具体化（A是下位概念）。"}, {"type": "多选", "num": 52, "text": "选择和运用讲授法，对教师的基本要求有（ ）。", "options": {"A": "寓启发于讲授之中", "B": "教学语言清晰精炼生动", "C": "科学组织讲授内容", "D": "明确的目的性"}, "answer": "ABCD", "explanation": "运用讲授法的基本要求：明确的目的性（D）、科学组织内容（C）、语言清晰精炼生动（B）和寓启发于讲授之中（A，避免注入式）。"}, {"type": "多选", "num": 53, "text": "现代大学的时代内涵包括（ ）。", "options": {"A": "保持独立品格", "B": "追求高深学问", "C": "国际化", "D": "既有大师，也有大楼"}, "answer": "ABCD", "explanation": "教材“现代大学理念的时代内涵”部分包括：现代大学仍应追求高深学问，现代大学应保持独立品格，现代大学既应有大师也应有大楼，现代大学应是国际化的。因此四项均属于现代大学的时代内涵。"}, {"type": "多选", "num": 54, "text": "下列哪些属于古希腊的\"七艺\"教育？", "options": {"A": "天文", "B": "几何", "C": "修辞", "D": "文法"}, "answer": "ABCD", "explanation": "古希腊\"七艺\"包括\"三艺\"（文法D、修辞C、辩证法）和\"四艺\"（算术、几何B、天文A、音乐）。"}, {"type": "多选", "num": 55, "text": "课程评价是指对课程整体的评价，评价对象是课程本身，包括（ ）。", "options": {"A": "课程实施者评价", "B": "课程效果评价", "C": "学生学业成绩的评价", "D": "课程编制者评价"}, "answer": "ABD", "explanation": "教材指出，今天的课程评价是对整体课程的评价，评价对象是课程本身，包括对课程编制者、课程实施者和课程效果的评价。学生学业成绩评价可作为课程效果证据，但不等同于课程评价对象本身。"}, {"type": "多选", "num": 56, "text": "在高等学校，教学组织形式包括（ ）。", "options": {"A": "实验教学", "B": "课外辅导", "C": "班级授课", "D": "\"习明纳\"个别化教学"}, "answer": "ACD", "explanation": "教材列举高等学校的教学组织形式包括班级授课、“习明纳”（seminar）、个别化教学、实验教学、实习、见习、社会实践等。课外辅导未列入此处的教学组织形式。"}, {"type": "多选", "num": 57, "text": "1996年联合国教科文组织在《教育——财富蕴藏其中》报告中指出终生教育应建立在四个支柱的基础上，这些支柱包括（ ）。", "options": {"A": "学会认知", "B": "学会做事", "C": "学会生存", "D": "学会共同生活"}, "answer": "ABCD", "explanation": "终身教育的四大支柱：学会认知（A）、学会做事（B）、学会共同生活（D）、学会生存（C）。"}, {"type": "多选", "num": 58, "text": "巴班斯基把教学方法分为（ ）。", "options": {"A": "激发和形成动机的方法", "B": "组织和实施学习活动的方法", "C": "检查和自我检查的方法", "D": "实践和操作的方法"}, "answer": "ABC", "explanation": "巴班斯基（Babansky）的教学方法分类：组织和实施学习活动的方法（B）、激发和形成动机的方法（A）、检查和自我检查的方法（C）。\"实践和操作的方法\"不是巴班斯基的分类。"}, {"type": "多选", "num": 59, "text": "我国高校科研评价存在的主要问题有（ ）。", "options": {"A": "重形式轻实质", "B": "重数量轻质量", "C": "重科研轻教学", "D": "重短期轻长远"}, "answer": "ABCD", "explanation": "高校科研评价的主要问题：重数量轻质量（B）、重科研轻教学（C）、重形式轻实质（A）和重短期轻长远（D）。这\"四重四轻\"是学术界公认的问题。"}, {"type": "多选", "num": 60, "text": "下面哪项不属于实践层面的大学精神文化？", "options": {"A": "学风", "B": "办学理念", "C": "校训", "D": "教风"}, "answer": "BC", "explanation": "大学精神文化分为价值层面和实践层面。学风（A）和教风（D）属于实践层面的精神文化。办学理念（B）和校训（C）属于价值层面的精神文化。"}, {"type": "多选", "num": 61, "text": "大学精神文化的时代特征有（ ）。", "options": {"A": "发展性", "B": "保守性", "C": "整合性", "D": "兼容性"}, "answer": "ACD", "explanation": "大学精神文化的时代特征：发展性（A，与时俱进）、整合性（C，融合创新）和兼容性（D，对外开放）。保守性不是大学精神文化的特征。"}, {"type": "多选", "num": 62, "text": "高校学生对大学环境的适应包括（ ）。", "options": {"A": "人际环境的适应", "B": "家庭环境的适应", "C": "生活环境适应", "D": "学习方式适应"}, "answer": "ACD", "explanation": "大学生对大学环境的适应主要包括：生活适应（C，独立生活）、学习方式适应（D，自主学习）和人际环境适应（A，新社交圈）。家庭环境的适应不属于大学环境适应。"}, {"type": "多选", "num": 63, "text": "高校教师职业倦怠的表现主要包括（ ）。", "options": {"A": "挫败感强烈", "B": "精疲力竭", "C": "情绪紧张", "D": "工作绩效低下"}, "answer": "ABCD", "explanation": "高校教师职业倦怠的主要表现：精疲力竭（B，情感耗竭）、情绪紧张（C，焦虑不安）、挫败感强烈（A，成就感降低）和工作绩效低下（D，效率下降）。"}, {"type": "多选", "num": 64, "text": "高校教师教学发展的模式包括（ ）。", "options": {"A": "攻读博士学位", "B": "申请科研项目", "C": "教师群体自助互动", "D": "教学专家介入指导"}, "answer": "CD", "explanation": "高校教师教学发展模式主要分为：无专家介入型（教师群体自助互动，C）和专家介入型（D，专家指导）。攻读博士和申请科研项目属于学术发展而非教学发展。"}, {"type": "多选", "num": 65, "text": "学生综合素质的构成要素包括（ ）。", "options": {"A": "业务素质", "B": "身心素质", "C": "思想道德素质", "D": "科学文化素质"}, "answer": "ABCD", "explanation": "学生综合素质的四方面：思想道德素质（C，根本）、科学文化素质（D，基础）、业务素质（A，本领）和身心素质（B，本钱）。"}, {"type": "多选", "num": 66, "text": "从教师素质的角度看，高校教师发展主要包括（ ）。", "options": {"A": "工资待遇的提升", "B": "学术水平的提高", "C": "教师职业知识、技能的提高", "D": "师德的提升"}, "answer": "BCD", "explanation": "从素质角度看，高校教师发展主要包括：学术水平提高（B）、职业知识和技能提高（C）和师德提升（D）。工资待遇提升属于薪酬福利范畴。"}, {"type": "多选", "num": 67, "text": "进入21世纪，影响高校学生发展的理念包括（ ）。", "options": {"A": "终身教育理念", "B": "终身学习理念", "C": "素质教育理念", "D": "以学生为中心理念"}, "answer": "ABCD", "explanation": "21世纪影响高校学生发展的理念：终身教育（A）、终身学习（B）、素质教育（C）和以学生为中心（D），四大理念相互关联、共同影响。"}, {"type": "多选", "num": 68, "text": "下列选项中属于高等教育贸易方式的是（ ）。", "options": {"A": "跨境高等教育服务", "B": "出国留学", "C": "雇用外籍教师", "D": "境外机构设立的私立高等教育机构"}, "answer": "ABCD", "explanation": "高等教育贸易方式包括：跨境教育服务（A）、人员跨国流动（B，留学生）、教师国际流动（C，外教）和境外办学机构（D，海外分校等）。"}, {"type": "多选", "num": 69, "text": "大学制度的基本内容包括（ ）。", "options": {"A": "大学与社会关系的制度", "B": "大学内部制度", "C": "大学与政府关系的制度", "D": "教学科研制度"}, "answer": "ABC", "explanation": "大学制度的基本内容包括：大学与社会关系的制度（A）、大学与政府关系的制度（C）和大学内部制度（B）。教学科研制度属于大学内部制度的组成部分。"}, {"type": "多选", "num": 70, "text": "在实行学院制的高校，院级学术委员会或教授会行使学术权力，具体决策的事项包括（ ）。", "options": {"A": "职称评定", "B": "经费使用", "C": "专业发展规划", "D": "学科建设"}, "answer": "ABCD", "explanation": "教材指出，在实行学院制的高校，院级学术委员会或教授会行使学术权力，具体决策事项包括学科建设、专业发展规划、人事分配、人员引进、职称评定、教学计划制定、课程设置、经费使用等。因此四项均可选。"}, {"type": "多选", "num": 71, "text": "对于提供教育服务的高等学校而言，高等教育市场包括（ ）。", "options": {"A": "出口处的教育需求", "B": "出口处的劳动力需求", "C": "入口处的劳动需求", "D": "入口处的教育需求"}, "answer": "BD", "explanation": "高等教育市场包括入口处的教育需求（D，学生升学需求）和出口处的劳动力需求（B，社会用人需求）。A和C的表述相反。"}, {"type": "多选", "num": 72, "text": "理性主义大学理念的代表人物有（ ）。", "options": {"A": "纽曼", "B": "杜威", "C": "洪堡", "D": "费希特"}, "answer": "ACD", "explanation": "教材明确列出理性主义大学理念的代表人物有洪堡、纽曼、怀特海等；同时在大学理念历史发展部分提到费希特等人对“大学理念”的解答作出重要贡献，且费希特是柏林大学第一任校长，强调大学学术任务与自由环境。本题选项中没有怀特海，按题库来源应选纽曼、洪堡、费希特。杜威不属于理性主义大学理念代表。"}, {"type": "多选", "num": 73, "text": "下列关于威斯康星大学说法正确的是（ ）。", "options": {"A": "在《莫雷尔法案》的实施下，威斯康星大学提出了以提高本州的农业和工业生产效率作为办学的指导思想", "B": "1904年范海斯校长提出\"威斯康星计划\"，提出\"把知识传递给广大民众\"\"为全州服务\"的任务", "C": "威斯康星大学开启了高等学校第三职能\"为社会服务\"之始", "D": "1912年麦卡锡出版了《威斯康星理念》一书，宣传为社会服务的办学理念"}, "answer": "ABCD", "explanation": "四个选项均正确描述了威斯康星大学的发展历史和社会服务理念的确立过程。"}, {"type": "多选", "num": 74, "text": "目前我国大学拥有的自主权包括（ ）。", "options": {"A": "教育教学", "B": "机构设置", "C": "经费使用", "D": "科学研究"}, "answer": "ABCD", "explanation": "我国大学依法拥有的自主权包括：教育教学自主权（A）、科学研究自主权（D）、机构设置自主权（B）和经费使用自主权（C）。"}, {"type": "多选", "num": 75, "text": "教学对象分析包括（ ）。", "options": {"A": "学习风格分析", "B": "初始能力分析", "C": "学习动机分析", "D": "一般特征分析"}, "answer": "ABD", "explanation": "教材将教学对象分析概括为三个方面：一般特征分析、学习风格分析和初始能力分析。学习动机固然会影响学习，但不属于教材此处列出的教学对象分析三项内容。"}, {"type": "多选", "num": 76, "text": "实用主义大学理念的代表人物有（ ）。", "options": {"A": "范海斯", "B": "赫钦斯", "C": "弗莱克斯纳", "D": "杜威"}, "answer": "AD", "explanation": "实用主义大学理念的代表人物是范海斯（A，威斯康星思想）和杜威（D，实用主义哲学集大成者）。弗莱克斯纳（C）的观点介于理性主义与实用主义之间，在本套题标准答案中不列入。注：弗莱克斯纳虽主张大学应有社会担当，但其观点介于理性主义与实用主义之间，部分教材将其纳入实用主义范畴。"}, {"type": "多选", "num": 77, "text": "大学组织构成要素包括（ ）。", "options": {"A": "学科", "B": "管理人员", "C": "学生", "D": "教师"}, "answer": "ABCD", "explanation": "大学组织的构成要素包括：学科（A，基础）、教师（D，主体）、学生（C，对象）和管理人员（B，保障）。"}, {"type": "多选", "num": 78, "text": "泰勒认为，有效组织课程内容的三个标准是（ ）。", "options": {"A": "复杂性", "B": "统合性", "C": "程序性", "D": "连续性"}, "answer": "BCD", "explanation": "泰勒认为有效组织课程内容的三个标准：连续性（D，重复强化）、程序性（C，逐步递进）和统合性（B，横向联系）。\"复杂性\"不是泰勒提出的标准。"}, {"type": "多选", "num": 79, "text": "西方历史上的\"雅典大学\"是由以下哪几个大学组成的？", "options": {"A": "柏拉图的\"学园\"", "B": "伊索克拉特的修辞学校", "C": "亚里士多德的\"吕克昂\"", "D": "伊壁鸠鲁和芝诺的哲学学校"}, "answer": "ABCD", "explanation": "所谓\"雅典大学\"是指古希腊雅典地区四所著名哲学学校的总称：柏拉图的\"学园\"（A）、伊索克拉特的修辞学校（B）、亚里士多德的\"吕克昂\"（C）以及伊壁鸠鲁和芝诺的哲学学校（D）。"}, {"type": "多选", "num": 80, "text": "下列关于通才教育与专才教育的关系，说法正确的是（ ）。", "options": {"A": "互斥", "B": "矛盾", "C": "并存", "D": "互补"}, "answer": "CD", "explanation": "通才教育与专才教育是并存（C）和互补（D）的关系，而非互斥或矛盾。现代高等教育强调两者的有机结合。"}, {"type": "多选", "num": 81, "text": "大学组织的特性包括（ ）。", "options": {"A": "组织系统的稳定性", "B": "生命周期短", "C": "松散结合系统", "D": "目标多样性"}, "answer": "ACD", "explanation": "大学组织的特性包括：组织系统的稳定性（A，作为长寿组织具有相对稳定的结构）、松散结合系统（C，各院系学科相对独立）和目标多样性（D，教学科研社会服务等多目标并存）。生命周期短（B）不符合大学实际。"}, {"type": "多选", "num": 82, "text": "高校学生的心理发展特征包括（ ）。", "options": {"A": "社会心理发展成熟", "B": "认知心理发展处于最佳状态", "C": "自我意识发展趋向成熟", "D": "个性心理发展基本稳定"}, "answer": "BCD", "explanation": "高校学生心理发展特征：认知心理发展处于最佳状态（B，记忆力和思维力强）、自我意识发展趋向成熟（C，自我认识深化）、个性心理发展基本稳定（D，人格基本形成）。社会心理尚未完全成熟，A错误。"}, {"type": "多选", "num": 83, "text": "高等教育的三大基本职能是（ ）。", "options": {"A": "文化传播", "B": "科学研究", "C": "人才培养", "D": "社会服务"}, "answer": "BCD", "explanation": "高等教育的三大基本职能是：人才培养（C）、科学研究（B）和社会服务（D）。文化传播（A）是附属职能，不是三大基本职能之一。"}, {"type": "判断", "num": 1, "text": "在教学过程中，学生在教师的指导下不断成长，教师也在完成教学任务的同时得到提高，即古人所谓的\"教学相长\"。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教材在“高校教学的内涵”中说明教学过程时明确指出：在教学过程中，学生在教师的指导下不断成长，教师也在完成教学任务的同时得到提高，即古人所谓的“教学相长”。题干与教材原文一致，因此判断为对。"}, {"type": "判断", "num": 2, "text": "高校课程具有明显的专业性。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高校课程按学科分类或社会职业分工设置，以培养专门人才为目标，具有鲜明的专业性特征。"}, {"type": "判断", "num": 3, "text": "私学是始于春秋时期孟子设的学舍。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "私学始于春秋时期，但创始人是孔子，而非孟子。孔子开办私学，打破了\"学在官府\"的局面。"}, {"type": "判断", "num": 4, "text": "高等教育市场化最直接的表现形式是，高等学校及其他高等教育机构按照市场逻辑，调配、使用高等教育资源。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高等教育市场化最直接的表现是高校按照市场逻辑配置资源，通过市场竞争获取生源、资金和声誉。"}, {"type": "判断", "num": 5, "text": "从课程组织方式上，可以把课程分为隐性课程和显性课程。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "隐性课程和显性课程是按课程的表现形式或影响学生方式来划分的，而非按课程组织方式划分。"}, {"type": "判断", "num": 6, "text": "教育学之父夸美纽斯在《大教学论》中正式提出和论证了\"班级授课制\"。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "夸美纽斯被誉为\"教育学之父\"，他在《大教学论》中系统论证了班级授课制的优越性和可行性。"}, {"type": "判断", "num": 7, "text": "大学的各种制度规则体现了大学的隐性精神文化。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学的制度规则（校规、管理制度等）是隐性精神文化的载体，通过制度形式潜移默化地传递大学的价值观和行为规范。"}, {"type": "判断", "num": 8, "text": "培养方案只能按照学年编制。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "培养方案可以按照学年编制，也可以按照学分制弹性安排。随着学分制改革，培养方案的编制方式更加灵活。"}, {"type": "判断", "num": 9, "text": "在专家介入型的教学发展模式中，教师和作为顾问的教学专家之间必须建立良好的合作关系。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "专家介入型模式中，教师与教学专家的良好合作关系是模式成功的关键。缺乏信任和合作，专家指导就难以发挥作用。"}, {"type": "判断", "num": 10, "text": "培养方案修订的主体在学科和专业，学科和专业可以自主设置课程。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教材指出，培养方案修订的主体在学科和专业，但由于课程权力的限制，学科和专业往往不能自主设置课程。题干前半句正确，后半句“可以自主设置课程”与教材相反。"}, {"type": "判断", "num": 11, "text": "衡量高等教育质量的第一标准是人才培养水平。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人才培养是高等学校的根本任务，因此人才培养水平是衡量高等教育质量的第一标准。"}, {"type": "判断", "num": 12, "text": "全面素质教育以人的综合素质，尤其以人的创新精神和实践能力为质量标准。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "素质教育强调德智体美全面发展，特别重视创新精神和实践能力的培养，这是素质教育的核心要义。"}, {"type": "判断", "num": 13, "text": "每个国家高等教育规模扩张的速度总是向上的。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "高等教育规模扩张并非总是向上的，受经济、人口、政策等因素影响，可能会出现波动或放缓。"}, {"type": "判断", "num": 14, "text": "教学方法直接影响教师教学工作的效能。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教学方法的选择和运用直接关系到教学效率和质量，影响教师教学工作的效能。"}, {"type": "判断", "num": 15, "text": "高等教育规模的持续扩张会引起公共财政能力下降。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高等教育规模扩张需要大量的公共财政投入，可能对公共财政造成压力。这是一个普遍存在的现实问题。"}, {"type": "判断", "num": 16, "text": "高等教育大众化，指的就是高等教育由\"精英高等教育\"走向\"大众高等教育\"的发展过程。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高等教育大众化的本质就是从精英教育向大众教育转变的过程，是高等教育规模和范围的扩大。"}, {"type": "判断", "num": 17, "text": "赫钦斯是理性主义大学理念的代表人物和集大成者。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "赫钦斯是20世纪理性主义大学理念的集大成者，大力倡导永恒主义教育哲学和经典名著教育。"}, {"type": "判断", "num": 18, "text": "现代学位制度主要起源于西欧的中世纪大学。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "现代学位制度起源于中世纪大学。中世纪大学设立了学士、硕士、博士等学位层级，奠定了现代学位制度的基础。"}, {"type": "判断", "num": 19, "text": "高校学生服务涵盖了学生教育、学生管理和学生服务等三个方面。学生教育的核心是加强心理健康教育。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "学生教育的核心是思想政治教育，而非心理健康教育。虽然心理健康教育很重要，但思想政治教育的核心地位不可动摇。"}, {"type": "判断", "num": 20, "text": "教师群体内部不同年龄、不同水平的教师之间保持的关系仅是竞争-合作关系。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教师群体内部的关系不仅是竞争与合作，还包括共进关系、师徒关系等多种关系。\"仅\"字过于绝对化。"}, {"type": "判断", "num": 21, "text": "校风、学风，校训都是实践层面的大学精神文化。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "校风、学风属于实践层面的精神文化，而校训属于价值层面的精神文化，不是实践层面。"}, {"type": "判断", "num": 22, "text": "教师存在着\"做一天和尚撞一天钟\"的心态时，表明该教师处于生涯低落阶段。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教材在教师职业发展阶段中把“做一天和尚，撞一天钟”的心态放在“稳定和停滞阶段”，表现为只做分内工作、缺乏进取心；“生涯低落阶段”则是准备离开教育岗位、打算退休的低潮时期。"}, {"type": "判断", "num": 23, "text": "教学管理是高校的经常性工作，教学工作是高校管理的核心。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教学工作是高校的经常性工作，教学管理是高校管理的核心。题干的说法颠倒了教学和教学管理的关系。"}, {"type": "判断", "num": 24, "text": "现代大学的国际化有助于促进异质文化之间的相互了解、相互理解，进而推动多元文化的融合。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学国际化促进了不同文化背景的师生交流，有助于跨文化理解和多元文化融合。"}, {"type": "判断", "num": 25, "text": "个人本位论主张教育目的应依据个人的需要来确定，教育的首要目的不在于谋求国家利益和社会发展。其代表人物有凯兴斯泰纳、卢梭等。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "凯兴斯泰纳（Kerschensteiner）是社会本位论的代表人物，而非个人本位论的代表。卢梭是个人本位论的代表。"}, {"type": "判断", "num": 26, "text": "\"国际化\"就是跨境教育。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "\"国际化\"不等于\"跨境教育\"。国际化包括向内的国际化（本土国际化）和向外的国际化（跨境教育）两个方面，跨境教育只是国际化的一个组成部分。"}, {"type": "判断", "num": 27, "text": "如何提高思想政治教育的实效性，是目前高等教育必须解决的重大问题。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "思想政治教育实效性问题是当前高等教育面临的重大课题，如何使思政教育入耳入脑入心，是亟需解决的关键问题。"}, {"type": "判断", "num": 28, "text": "在官学中，太学和国子监是古代中国的最高学府，自汉代后历朝均设。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "太学始于汉代，国子监始于隋代，两者都是古代中国的中央官学最高学府，后世各朝多沿设。"}, {"type": "判断", "num": 29, "text": "战略规划是战略管理的先导。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "战略规划是战略管理的第一步和基础。没有规划，管理就失去方向和依据。所以战略规划是战略管理的先导。"}, {"type": "判断", "num": 30, "text": "高校教师绩效评价指标体系设计，应坚持指标划分的独立性、可操作性原则，避免多项指标之间的重复交叉，确保各项指标相互独立。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "科学的设计绩效指标体系应遵循独立性（指标间不重复）和可操作性原则，确保评价客观有效。"}, {"type": "判断", "num": 31, "text": "我国公办高校实行党委领导下的校长负责制。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "《高等教育法》规定，国家举办的高等学校实行中国共产党高等学校基层委员会领导下的校长负责制。"}, {"type": "判断", "num": 32, "text": "1809年洪堡创办柏林大学，提出\"通过研究进行教学\"、\"教学与研究统一\"作为办学原则。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "洪堡于1810年（实际创办年份）创办柏林大学，确立了\"通过研究进行教学\"、\"教学与研究相统一\"的办学原则。"}, {"type": "判断", "num": 33, "text": "洪堡是最早系统阐述理性主义大学理念的第一人。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "最早系统阐述理性主义大学理念的是纽曼（《大学的理想》），而非洪堡。洪堡更强调教学与科研的统一。"}, {"type": "判断", "num": 34, "text": "在\"行政主导模式\"中，学校的组织结构呈现金字塔形。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "行政主导模式下，权力集中于上层，按照层级由上到下分配，形成金字塔形的层级结构。"}, {"type": "判断", "num": 35, "text": "高校教学是实现高等教育职能的基本途径。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教学是高校最基本、最核心的活动，通过教学实现人才培养目标，是实现高等教育职能的基本途径。"}, {"type": "判断", "num": 36, "text": "教学目标可以是不可观察、不可测量的。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "规范的教学目标应该是可观察、可测量的，否则无法评价教学目标是否达成。\"不可观察、不可测量\"违背教学目标设计的基本原则。"}, {"type": "判断", "num": 37, "text": "科研成果的价值难以在短时间内做出准确判断，长期的实践检验才是唯一的标准。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "科学研究具有探索性和长期性。许多重大科研成果的价值需要经过长时间的实践检验才能被确认。"}, {"type": "判断", "num": 38, "text": "各国高等教育大众化的共同经验是发展短期应用型高等学校，以承担数量众多的新型学生。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "发展短期应用型高校（如社区学院、专科学校）是各国实现高等教育大众化的普遍经验，可以吸纳更多的学生接受高等教育。"}, {"type": "判断", "num": 39, "text": "素质教育包括思想道德素质、文化素质、业务素质、身心素质四个方面。其中思想道德素质是根本，文化素质是基础，业务素质是本领，身心素质是本钱。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "这是关于素质教育的经典表述，四个方面各有定位，有机统一。"}, {"type": "判断", "num": 40, "text": "1998年10月在巴黎召开的首次世界高等教育大会，发表了《21世纪的高等教育：展望和行动世界宣言》。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "1998年10月，联合国教科文组织在巴黎召开了首次世界高等教育大会，发表了《21世纪的高等教育：展望和行动世界宣言》。"}, {"type": "判断", "num": 41, "text": "讲授法主要以肢体语言为传递和交流教学信息的工具，教师语言素养的水平不会对教学效果产生直接的影响。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "讲授法主要以口头语言（而非肢体语言）为传递信息的主要工具，教师的语言素养直接影响教学效果。"}, {"type": "判断", "num": 42, "text": "案例教学法是以学生为中心，师生互动的教学过程。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "案例教学法以学生为中心，强调学生在分析和讨论案例中主动学习，师生之间、生生之间充分互动。"}, {"type": "判断", "num": 43, "text": "依据学生评价在教育教学活动中发挥的作用，可以将其分为定位性评价、形成性评价、诊断性评价、总结性评价。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "按作用分类，学生评价可分为：定位性评价（确定初始水平）、诊断性评价（诊断问题）、形成性评价（过程反馈）和总结性评价（最终评定）。"}, {"type": "判断", "num": 44, "text": "不同的课程评价模式在具体过程和使用的方法技术上必然存在差异，所以不存在统一化、标准化的评价过程与方法，也不存在一般步骤。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "虽然不同评价模式有差异，但仍然存在一般的评价步骤（如准备阶段→实施阶段→总结阶段）。\"不存在一般步骤\"的说法过于绝对。"}, {"type": "判断", "num": 45, "text": "学习者目前水平与期望学习者达到的水平之间的差距是进行教学设计的后端分析。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "学习者目前水平与期望水平之间的差距是前端分析（需求分析），而非后端分析。后端分析是教学实施后的评价分析。"}, {"type": "判断", "num": 46, "text": "大学理念方面，科尔是一个典型的工具主义者或实用主义者。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "科尔（Clark Kerr）提出\"多元化巨型大学\"概念，强调大学的社会服务功能，是工具主义或实用主义大学理念的代表人物。"}, {"type": "判断", "num": 47, "text": "我国最早采用班级授课制的是京师同文馆。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "京师同文馆（1862年）是中国最早采用班级授课制的教育机构，标志着西方教学制度在中国的引入。"}, {"type": "判断", "num": 48, "text": "柏林大学是现代大学崇尚科学研究职能并使之制度化的始祖。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "柏林大学将科学研究正式纳入大学职能，确立了教学与研究相统一的制度，是现代研究型大学的始祖。"}, {"type": "判断", "num": 49, "text": "1998年高校扩招政策在中国高等教育发展史上具有里程碑式的意义。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "高校扩招政策于1999年启动，而非1998年。1999年的扩招标志着我国高等教育大众化的开端。"}, {"type": "判断", "num": 50, "text": "学术活动的同工不同酬是不能被认可的。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "在学术职业语境中，报酬常与学术贡献、声望、岗位性质差异相关。\"同工不同酬\"在学术活动中通常被允许（例如不同职称教师承担相同课时但薪酬不同），\"不能认可\"的说法过于绝对。"}, {"type": "判断", "num": 51, "text": "科研评价指标权重确定方法较为常用的有专家意见平均法、德尔菲法、秩和运算法、层次分析法等。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "这些方法确实是确定科研评价指标权重的常用方法，每种方法各有利弊，适用于不同场景。"}, {"type": "判断", "num": 52, "text": "整合课程被多个国家视为高校课程结构改革的焦点所在，因为整合课程扬弃了分科课程的缺陷，符合人类整体认知特点。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "整合课程克服了分科课程知识割裂的缺陷，有助于学生形成整体认知，因此成为多国课程改革的焦点。"}, {"type": "判断", "num": 53, "text": "牛津大学、巴黎大学、哈佛大学等都是著名的中世纪大学。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "牛津大学和巴黎大学是中世纪大学，但哈佛大学成立于1636年，已经属于近代大学范畴，不是中世纪大学。"}, {"type": "判断", "num": 54, "text": "大学精神源于大学理念，大学理念一定会成为大学精神的一部分。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "大学精神源于大学理念，但并非所有大学理念都能成为大学精神。只有经过长期实践和师生广泛认同的理念才会转化为大学精神。\"一定\"过于绝对。"}, {"type": "判断", "num": 55, "text": "1810年成立的威斯康星大学则开启了研究型大学的未来。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "1810年成立的柏林大学开启了研究型大学的未来，而非威斯康星大学。威斯康星大学（1848年成立）以社会服务理念闻名。"}, {"type": "判断", "num": 56, "text": "在高等学校教学质量保障活动中，激励导向和监控手段是对立统一的两个方面。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "激励（正向引导）和监控（约束规范）在质量保障中是辩证统一的关系，既相互制约又相互促进。"}, {"type": "判断", "num": 57, "text": "马斯洛的需要层次理论认为，人的基本需要从低级到高级依次是生理需要、安全需要、尊重的需要、自我实现的需要、归属与爱的需要。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "正确的顺序是：生理需要→安全需要→归属与爱的需要→尊重的需要→自我实现的需要。题干中归属与爱的需要和尊重的需要顺序错误。"}, {"type": "判断", "num": 58, "text": "高校质量文化应当体现\"刚性\"约束与\"柔性\"约束的紧密结合。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高校质量文化建设需要刚柔并济：刚性约束（规章制度、标准规范）与柔性约束（文化引领、价值认同）相结合。"}, {"type": "判断", "num": 59, "text": "1912年麦卡锡出版了《威斯康星理念》一书，威斯康星大学是第一个将\"为社会服务\"作为高等学校职能的高校。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "麦卡锡的《威斯康星理念》系统阐述了威斯康星大学\"为社会服务\"的办学理念。威斯康星大学确实开创了大学社会服务职能。"}, {"type": "判断", "num": 60, "text": "课程评价实施中的基础性工作是确定评价机构的人员构成。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "课程评价实施中的基础性工作是制定评价方案（或确定评价目标）。人员构成虽重要，但不是基础性工作。"}, {"type": "判断", "num": 61, "text": "高等学校的三项基本职能包括人才培养、科学研究和社会服务。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "这是对高校三大基本职能的标准表述：人才培养、科学研究和社会服务。"}, {"type": "判断", "num": 62, "text": "孟子主张在教学上发挥学生的主动性，提倡存疑的精神（尽信书，则不如无书）。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "孟子提出\"尽信书，则不如无书\"，鼓励学生独立思考、不盲从书本，体现了发挥学生主动性的教学思想。"}, {"type": "判断", "num": 63, "text": "学术自由不是单个学者绝对的言论自由，而是学术专业群体在思想、探究、讨论和教学方面的绝对自由。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教材原文指出，为防止自由滥用，学术自由不是单个学者绝对的言论自由，而是学术专业群体在思想、探究、讨论和教学方面的绝对自由。题干表述与教材原文一致，因此判断为对。"}, {"type": "判断", "num": 64, "text": "一所现代大学有真正的大师就能够培养出大师级人才。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "有大师不一定能培养出大师级人才，人才培养涉及多方面的因素（学生素质、制度环境、文化氛围等），不是由个别大师决定的。"}, {"type": "判断", "num": 65, "text": "形成性评价是在教学过程中检查学生的进步情况，为师生提供有关教学的成功或失败的反馈信息，以达到改进教和学的目的。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "这是对形成性评价的准确定义：在教学过程中进行，提供反馈信息，旨在改进教学。"}, {"type": "判断", "num": 66, "text": "教师低效教学的首要表现是不能有效地传授学科知识。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "低效教学的首要表现应是不能促进学生有效学习与发展，而非单纯不能传授学科知识。教学的有效性体现在学生学到了什么、能力是否提升，而非教师是否完成了知识传授。"}, {"type": "判断", "num": 67, "text": "知识型社会与现代工业社会的差别在于它的技术能力，它把知识作为间接的生产力。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "知识型社会的核心特征是知识作为直接（而非间接）的生产力发挥作用，这是与工业社会的根本区别。"}, {"type": "判断", "num": 68, "text": "学习者特征分析一般在开始授课之前详细地做一次，不必每节课的设计都做。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "学习者特征分析一般在开始授课之前做一次详细的分析即可，不必每节课的设计都重复做完整的分析。日常教学中可根据需要进行微调，但系统性的详细分析不需要每节课都做。"}, {"type": "判断", "num": 69, "text": "大学精神、理念、管理作风、教风等都是价值层面的精神文化。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教材将大学精神、大学理念、校训等归入价值层面的精神文化；将校风、学风、教风、管理作风等归入实践层面的精神文化。题干把管理作风、教风都说成价值层面，表述不准确。"}, {"type": "判断", "num": 70, "text": "建立有效的质量监控与评价系统，首先是要建立良好的创新机制。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教材原文指出，建立有效的质量监控与评价系统，首先要建立良好的机制，体制创新是关键；其次评价体系建设是重点；第三队伍建设是保障。题干说“首先是要建立良好的创新机制”，与教材原意一致，因此判断为对。"}, {"type": "判断", "num": 71, "text": "案例教学法中学生是导演，教师是演员。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "案例教学法中，教师是导演（引导和组织讨论），学生是演员（主动参与分析和讨论）。题干说反了。"}, {"type": "判断", "num": 72, "text": "\"以学生为中心\"，最根本的是实现从\"教\"为中心向\"学\"为中心的转变，从\"老三中心\"向\"新三中心\"转变。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "\"以学生为中心\"的核心是从\"课堂、教师、教材\"（老三中心）转向\"学生、学习、学习过程\"（新三中心），关注学生的学习和发展。"}, {"type": "判断", "num": 73, "text": "教师将知识传授给学生旨在培养学生的能力，包括培养学生学会做人、学会做事、学会共处、学会生活。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教材涉及的联合国教科文组织“四个学会”通常表述为学会认知、学会做事、学会共同生活、学会生存。题干写成“学会做人、学会做事、学会共处、学会生活”，且把教师传授知识的目的概括得过于笼统，与教材表述不一致。"}, {"type": "判断", "num": 74, "text": "最早的专业教育始于中世纪大学，大学设文、法、神、医四科，培养专业人才。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "中世纪大学设立文、法、神、医四科，培养牧师、律师、医生等专业人才，是世界最早的专才教育。"}, {"type": "判断", "num": 75, "text": "通才教育主要针对具体岗位和行业需要来进行人才培养。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "通才教育（通识教育）注重拓宽知识面、培养综合素质，而非针对具体岗位和行业。针对具体岗位的是专才教育。"}, {"type": "判断", "num": 76, "text": "高校战略管理是一个静态的管理过程。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "高校战略管理是一个动态的、持续的过程，包括战略制定、战略实施、战略评估和战略调整，而非静态的。"}, {"type": "判断", "num": 77, "text": "学术漂移的首要表现是重行政权力、轻学术权力。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "学术漂移的首要表现不是重行政权力、轻学术权力。教材明确说，学术漂移的首要表现是重科研、轻教学；重行政权力、轻学术权力是第二大表现。因此本题错误。"}, {"type": "判断", "num": 78, "text": "泰勒倡导的目标模式中，教师是课程实施的主体，学生是课程实施的对象，他们都是课程编制的主体。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "泰勒目标模式中，教师是课程实施的主体，学生是课程实施的对象，但他们都不是课程编制的主体；该模式下课程编制主要由专业课程专家完成。因此“他们都是课程编制的主体”的说法错误。"}, {"type": "判断", "num": 79, "text": "高校学生社团属于学生自发性组织，主要作用是丰富业余生活，对于学生的成长和素质教育作用不大。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "学生社团虽然以丰富业余生活为主要形式，但它在提升学生综合素质（组织能力、沟通能力、团队协作等）方面具有重要作用。因此，题干“作用不大”的说法错误。"}, {"type": "判断", "num": 80, "text": "\"学在官府\"、\"吏师合一\"是指官学的教育形式。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "\"学在官府\"指教育由官府垄断，\"吏师合一\"指官吏兼任教师，两者都描述了先秦时期官学教育的特征。"}, {"type": "判断", "num": 81, "text": "大学生群体在组织结构上可分为正式的群体和非正式的群体两大类。非正式群体只会产生负面影响。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "非正式群体既有正面影响（满足社交需要、丰富课余生活），也可能有负面影响，不能一概而论。\"只会产生负面影响\"说法错误。"}, {"type": "判断", "num": 82, "text": "在我国大学的内部权力中，权力矛盾的焦点仍然是行政权力与学术权力的矛盾。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "行政权力与学术权力的关系是大学治理的核心问题，两者之间的矛盾和张力是我国大学内部权力运行的焦点。"}, {"type": "判断", "num": 83, "text": "把课程理解为学习方案或具体的学习科目，是我国教育理论界和广大教师最为熟悉的课程定义。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "将课程理解为教学科目或学习方案，是我国传统教育中最普遍、最熟悉的课程定义方式。"}, {"type": "判断", "num": 84, "text": "高等教育机构不仅被看作是一种文化机构，而且也被看作是一种经济机构。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教材指出，在高等教育市场化背景下，高等教育机构不仅被看作是一种文化机构，而且也被看作是一种服务机构。题干将其说成“经济机构”，与教材原文不符。"}, {"type": "判断", "num": 85, "text": "古罗马高等教育，开设了修辞、辩证法、算术、天文、几何、历史、音乐课程，培养哲学王。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "培养\"哲学王\"是柏拉图的教育理想（古希腊），而非古罗马。古罗马高等教育重视修辞和实用学科，培养演说家和政治家。"}],
  psych: [{"type": "单选", "num": 1, "text": "内容型激励理论不包括", "options": {"A": "麦克利兰的成就需要理论", "B": "弗鲁姆的期望理论", "C": "马斯洛的需要层次论", "D": "赫茨伯格的双因素理论"}, "answer": "B", "explanation": "弗鲁姆的期望理论属于过程型激励理论。内容型包括需要层次论、成就需要理论和双因素理论。"}, {"type": "单选", "num": 2, "text": "下列说法错误的是", "options": {"A": "道德认识的形成是品德形成的客观标志。", "B": "道德信念的形成和道德评价能力的完善是衡量大学生道德认识成熟的主要标志。", "C": "道德意志的作用就在于发动与既定目的相符的行动，制止与既定目的相悖的行动。", "D": "道德技能的掌握有助于实现道德目的，它将指导人做出对他人和社会具有道德意义的事情。"}, "answer": "A", "explanation": "品德形成的客观标志是道德行为，不是道德认识。A说法错误。"}, {"type": "单选", "num": 3, "text": "什么是教师威信形成的基本条件", "options": {"A": "教师的仪表、生活作风和习惯", "B": "师生平等交往", "C": "良好的道德品质", "D": "教师给学生的第一印象"}, "answer": "C", "explanation": "教材明确指出，良好的道德品质是教师威信形成的基本条件。"}, {"type": "单选", "num": 4, "text": "关于心理冲突，下列说法错误的是", "options": {"A": "如果不给予足够重视并及时调适，持续下去将会导致更加严重的心理疾病。", "B": "又称为心理失衡，属于轻微的心理异常。", "C": "通常不存在心理状态的病理性变化，是正常心理活动中的局部异常状态。", "D": "是指个体在有目的的活动中，存在两个或两个以上相反或相互排斥的情绪、动机或价值观，个体既不能丢掉一个保留一个，又不能把两者在较高的层面上整合起来，因而产生的一种矛盾的心理状态。"}, "answer": "A", "explanation": "教材把大学生心理问题按严重程度分为心理冲突、心理障碍、心理疾病。心理冲突又称心理失衡，属于轻微心理异常，通常不存在心理状态的病理性变化，持续时间较短；选项B、C、D均符合教材对心理冲突的表述。选项A“如果不给予足够重视并及时调适，持续下去将会导致更加严重的心理疾病”是教材对心理障碍的说明，不是心理冲突的特征，因此A错误。"}, {"type": "单选", "num": 5, "text": "A－B型的人格分类由哪两位心理学家提出", "options": {"A": "培因和李波特", "B": "弗瑞德曼和李波特", "C": "弗瑞德曼和罗森曼", "D": "阿德勒和荣格"}, "answer": "C", "explanation": "A-B型人格分类由弗瑞德曼和罗森曼提出。"}, {"type": "单选", "num": 6, "text": "以下不属于大学生常见的心理冲突的是", "options": {"A": "交往与闭锁的心理冲突", "B": "理想化和现实感的心理冲突", "C": "适应心理问题", "D": "性生理成熟与性心理相对幼稚的心理冲突"}, "answer": "C", "explanation": "大学生常见心理冲突包括交往与闭锁、理想化与现实感、性成熟与性心理幼稚的冲突。\"适应心理问题\"是适应问题，不是心理冲突类型。"}, {"type": "单选", "num": 7, "text": "强化理论的提出者是", "options": {"A": "斯金纳", "B": "洛克", "C": "弗鲁姆", "D": "马斯洛"}, "answer": "A", "explanation": "强化理论由斯金纳提出，是操作性条件反射的核心内容。"}, {"type": "单选", "num": 8, "text": "教师所掌握的专业知识既包括特定的学科知识，也包括如何传授这些知识的知识，被称为", "options": {"A": "实践的知识", "B": "理解教材的知识", "C": "组织教材的知识", "D": "教学的知识"}, "answer": "A", "explanation": "教材指出，教师的专业知识既包括学科知识，也包括如何传授学科知识的知识，这类知识被称为“实践的知识”。"}, {"type": "单选", "num": 9, "text": "关于心理问题，下列说法正确的是", "options": {"A": "心理疾病通常不存在心理状态的病理性变化，是正常心理活动中的局部异常状态。", "B": "心理障碍通常不存在心理状态的病理性变化，是正常心理活动中的局部异常状态。", "C": "心理障碍属于轻微的心理异常。", "D": "心理疾病是比较严重或严重的心理异常，是多种心理障碍集中或综合的表现。"}, "answer": "D", "explanation": "心理疾病是较严重的心理异常，是多种心理障碍的综合表现。"}, {"type": "单选", "num": 10, "text": "在把新信息从工作记忆转到长时记忆的过程中，关键一步是", "options": {"A": "反馈", "B": "练习", "C": "测查", "D": "教授"}, "answer": "B", "explanation": "信息从工作记忆转入长时记忆的关键是练习（复述）。"}, {"type": "单选", "num": 11, "text": "耶基斯和多德森的研究表明，在难度较大的任务中（如写作或解决复杂问题），什么样的动机水平有利于任务完成", "options": {"A": "中等的", "B": "极高的", "C": "较低的", "D": "较高的"}, "answer": "C", "explanation": "耶克斯-多德森定律：困难任务需要较低的动机水平。"}, {"type": "单选", "num": 12, "text": "激励的起点是", "options": {"A": "未满足的需要", "B": "需要", "C": "动机", "D": "目标"}, "answer": "A", "explanation": "激励的起点是未满足的需要。需要是激励的源泉。"}, {"type": "单选", "num": 13, "text": "19世纪后期，许多心理学家致力于研究健全人格问题。其中，哪一流派心理学家的贡献最大。", "options": {"A": "认知心理学家", "B": "精神分析心理学家", "C": "行为主义心理学家", "D": "人本主义心理学家"}, "answer": "D", "explanation": "19世纪后期研究健全人格贡献最大的是人本主义心理学家。"}, {"type": "单选", "num": 14, "text": "教师组织教学、维持课堂秩序，评分、定等，决定学生的升留级，评判行为的正确性，调停打架、争吵与争论，施用奖赏与惩罚，此时他是在扮演什么样的角色", "options": {"A": "模范公民", "B": "家长的代理人", "C": "团体的领导", "D": "侦探和纪律执行者"}, "answer": "D", "explanation": "教材把教师组织教学、维持课堂秩序以及评分、定等、调停争论、施用奖惩等归入法律和纪律执行者角色，题目对应“侦探和纪律执行者”。"}, {"type": "单选", "num": 15, "text": "教师的情感是丰富的，尤其是教师的职业情感更具有特色，以下哪些不属于教师的情感特征", "options": {"A": "教师的情操", "B": "教师的品德", "C": "以师爱为核心的积极情感", "D": "对学生满怀期望"}, "answer": "B", "explanation": "教师的品德属于道德品质范畴，不属于情感特征。教师情感特征包括师爱、期望和情操。"}, {"type": "单选", "num": 16, "text": "如果将记忆的按时间分类，则不包括", "options": {"A": "永久记忆", "B": "长时记忆", "C": "短时记忆", "D": "感觉记忆"}, "answer": "A", "explanation": "记忆按时间分类包括感觉记忆（瞬时记忆）、短时记忆和长时记忆。\"永久记忆\"不是标准的时间分类名称。"}, {"type": "单选", "num": 17, "text": "下列不属于创造性的特点是", "options": {"A": "社会价值或个人价值", "B": "独特性", "C": "概括性", "D": "新颖性"}, "answer": "C", "explanation": "创造性的特点包括新颖性、独特性和社会价值。\"概括性\"是思维的一般特征。"}, {"type": "单选", "num": 18, "text": "什么是教师获得威信的必要条件", "options": {"A": "教师的仪表、生活作风和习惯", "B": "良好的道德品质", "C": "师生平等交往", "D": "教师给学生的第一印象"}, "answer": "A", "explanation": "教材明确指出，教师的仪表、生活作风和习惯，是教师获得威信的必要条件。"}, {"type": "单选", "num": 19, "text": "公平理论又称为社会比较理论，其提出者是", "options": {"A": "马斯洛", "B": "亚当斯", "C": "洛克", "D": "弗鲁姆"}, "answer": "B", "explanation": "公平理论（社会比较理论）由美国心理学家亚当斯提出。"}, {"type": "单选", "num": 20, "text": "促使需要产生和形成动机的外部条件是", "options": {"A": "目标", "B": "行为", "C": "动机", "D": "诱因"}, "answer": "D", "explanation": "诱因是促使需要产生和形成动机的外部条件。"}, {"type": "单选", "num": 21, "text": "德瑞福斯认为，大多数工作三、四年的教师都能达到教师成长的哪个阶段", "options": {"A": "新手阶段", "B": "优秀新手阶段", "C": "胜任阶段", "D": "熟练阶段"}, "answer": "C", "explanation": "德瑞福斯认为工作三、四年的教师能达到胜任阶段。"}, {"type": "单选", "num": 22, "text": "教学效果如何,教学的有效性能否实现，关键在", "options": {"A": "教材", "B": "学校领导", "C": "教师", "D": "学生"}, "answer": "C", "explanation": "教学效果关键在教师，教师是教学活动的组织者和实施者。"}, {"type": "单选", "num": 23, "text": "有的学生不喜欢读书，可又怕父母责备，读书和受责备都想回避，此类冲突属于动机冲突中的", "options": {"A": "趋避冲突", "B": "多重趋避冲突", "C": "双趋冲突", "D": "双避冲突"}, "answer": "D", "explanation": "不喜欢读书（想回避）又怕父母责备（也想回避），是双避冲突。"}, {"type": "单选", "num": 24, "text": "下列不属于直观动作思维的是", "options": {"A": "聋哑人通过手势交往", "B": "教室的多媒体投影仪坏了，技术人员一边检查相关部件，一边思索损坏原因，最后排除故障。", "C": "在动手重新布置房间之前，我们会先利用头脑中各种装饰物和家具的形象考虑如何进行摆设，形成多种方案，再选择最佳方案。", "D": "4岁前儿童只能在动作中思考问题"}, "answer": "C", "explanation": "直观动作思维依靠实际操作解决问题。C选项利用头脑中形象进行摆设规划，属于具体形象思维（表象思维），不是直观动作思维。"}, {"type": "单选", "num": 25, "text": "什么是教师获得威信所必需的因素", "options": {"A": "教育教学技能和心理素质", "B": "师生平等交往", "C": "教师的仪表、生活作风和习惯", "D": "良好的道德品质"}, "answer": "A", "explanation": "教育教学技能和心理素质是教师获得威信所必需的因素。"}, {"type": "单选", "num": 26, "text": "教师对教育事业积极情感的核心是", "options": {"A": "人格", "B": "价值观", "C": "师爱", "D": "兴趣"}, "answer": "C", "explanation": "师爱是教师对教育事业积极情感的核心，是教师职业道德的基石。"}, {"type": "单选", "num": 27, "text": "教师用于陈述预期学生获得学习结果的行为术语应尽可能", "options": {"A": "不可观察、可测量", "B": "不可观察、不可测量", "C": "可观察、不可测量", "D": "可观察、可测量"}, "answer": "D", "explanation": "教学目标表述应尽可能可观察、可测量，便于教学效果评估。"}, {"type": "单选", "num": 28, "text": "关于问题解决的心理过程，下列说法正确的是", "options": {"A": "桑代克认为，问题解决不是尝试和错误的渐进过程，而是对整个问题情境的突然领悟和豁然开朗，即突然领悟到手段和目的之间的关系。", "B": "试误说认为，问题解决要经过一系列尝试和错误，这对后来的问题解决研究有一定影响。但它认为尝试和错误是盲目的，忽视了认知在问题解决中的作用。", "C": "纽威尔和西蒙提出，问题解决由一系列互相联系的心理组织构成，每一心理组织都把问题分析综合为更狭小、更明确的陈述。一般要经历一般范围、功能解决、特殊解决这三个水平。", "D": "邓克尔认为，问题解决就是在问题空间进行探索、运用一系列认知操作以达到目标的过程。"}, "answer": "B", "explanation": "试误说认为问题解决经过尝试和错误，有一定影响，但忽视了认知的作用。A混淆了桑代克和格式塔学派。"}, {"type": "单选", "num": 29, "text": "关于智力，下列说法不正确的是", "options": {"A": "智力正常是大学生学习、生活与工作的基本心理条件，是心理健康的重要标准。", "B": "衡量大学生的智力是否正常，关键在于看其是否正常地、充分地发挥了效能", "C": "衡量大学生的智力是否正常，看他是否有强烈的求知欲和浓厚的探索兴趣，乐于学习，能适应时代的要求，具有创新能力。", "D": "智力的高低等于成绩的高低"}, "answer": "D", "explanation": "智力高低不等于成绩高低，成绩受多种因素影响。"}, {"type": "单选", "num": 30, "text": "教师运用学习测查的主要目的是", "options": {"A": "教授新知识", "B": "提供练习", "C": "检查学生是否理解了所学的内容", "D": "复习旧知识"}, "answer": "C", "explanation": "教师运用学习测查的主要目的是检查学生是否理解了所学内容。"}, {"type": "单选", "num": 31, "text": "以下关于教师在咨询中常具备的特征，描述错误的是", "options": {"A": "具有自发性和诚恳的态度", "B": "心领神会", "C": "把自己的价值观强加给学生", "D": "没有占有欲"}, "answer": "C", "explanation": "心理咨询中教师应保持价值中立，不能把自己的价值观强加给学生。"}, {"type": "单选", "num": 32, "text": "气质的形成主要依赖于", "options": {"A": "家庭环境", "B": "教育", "C": "社会文化", "D": "先天的生理基础"}, "answer": "D", "explanation": "气质的形成主要依赖于先天的生理基础（高级神经活动类型）。"}, {"type": "单选", "num": 33, "text": "马斯洛认为，向往爱情、需要朋友、参加团体并被团体接纳等需要属于", "options": {"A": "爱与归属的需要", "B": "尊重的需要", "C": "生理需要", "D": "安全需要"}, "answer": "A", "explanation": "向往爱情、需要朋友、被团体接纳属于爱与归属的需要。"}, {"type": "单选", "num": 34, "text": "关于科尔伯格品德发展理论，下列说法正确的是", "options": {"A": "儿童处于前习俗水平这一时期的特征是，个人认识到团体的行为规范，进而接受并付诸实践", "B": "前习俗水平这一时期又分为两个阶段：人际协调的定向阶段和维护权威或秩序的定向阶段", "C": "后习俗水平这一阶段已经发展到超越现实道德规范的约束，达到完全自律的境界。", "D": "工具性的相对主义定向阶段属于后习俗水平。"}, "answer": "C", "explanation": "科尔伯格的后习俗水平已超越现实道德规范约束，达到完全自律。A描述的是习俗水平，B和D描述有误。"}, {"type": "单选", "num": 35, "text": "人格结构的重要组成部分是", "options": {"A": "气质与性格", "B": "认知与动机", "C": "动机和气质", "D": "认知和性格"}, "answer": "A", "explanation": "人格结构的重要组成部分是气质与性格。气质是生物基础，性格是社会核心。"}, {"type": "单选", "num": 36, "text": "根据需要起源的不同，将交往、尊重、求知、审美、劳动、成就等需要归为", "options": {"A": "物质需要", "B": "精神需要", "C": "生理需要", "D": "社会需要"}, "answer": "D", "explanation": "交往、尊重、求知、审美、劳动、成就等是后天形成的社会需要。"}, {"type": "单选", "num": 37, "text": "我国最早运用“中和”概念来描述人格的是", "options": {"A": "《大学》", "B": "《论语》", "C": "《中庸》", "D": "《易经》"}, "answer": "D", "explanation": "教材指出，最早运用“中和”描述人格的是《易经》；《中庸》则是明确提出“中和”概念并将其作为理想人格和个人修养最高准则的典籍。"}, {"type": "单选", "num": 38, "text": "关于品德的四种心理成分，下列说法正确的是", "options": {"A": "它们的发展有阶段性，且可以单独地割裂开来。", "B": "道德行为是品德一个循环中的终末环节，也是更高循环中的依据和基础。", "C": "道德情感是品德的思想基础，是道德认识产生的依据。", "D": "它们分别是道德认识、道德情感、道德意志、道德信念"}, "answer": "B", "explanation": "道德行为是品德循环中的终末环节，也是更高循环的依据。A错误（不能割裂），C错误（道德认识是思想基础），D错误（应为道德行为）。"}, {"type": "单选", "num": 39, "text": "成就需要理论的提出者是", "options": {"A": "赫茨伯格", "B": "马斯洛", "C": "弗鲁姆", "D": "麦克利兰的"}, "answer": "D", "explanation": "成就需要理论由麦克利兰提出。"}, {"type": "单选", "num": 40, "text": "下列关于陈述性知识，说法错误的是", "options": {"A": "陈述性知识是人的长时记忆中的重要内容。", "B": "大部分陈述性知识都能够用语言来表述。", "C": "它是关于人怎样解决问题、如何去做某事的知识。", "D": "能被人用语言来陈述和描述，是有关人所知道的事物状况的知识。"}, "answer": "C", "explanation": "陈述性知识是\"是什么\"的知识。C选项\"如何去做某事\"是程序性知识的定义。"}, {"type": "单选", "num": 41, "text": "马斯洛认为，人们要求稳定、安全、受到保护、有秩序、能免除恐惧和焦虑等需要属于", "options": {"A": "尊重的需要", "B": "爱与归属的需要", "C": "安全需要", "D": "生理需要"}, "answer": "C", "explanation": "要求稳定、安全、受保护、有秩序、免除恐惧焦虑等需要属于安全需要。"}, {"type": "单选", "num": 42, "text": "关于品德的描述，下列说法错误的是", "options": {"A": "品德的形成与发展不仅受社会制约，而且受个体的心理制约。", "B": "品德反映社会生活，它的产生、发展和变化服从于社会的发展规律，属于社会意识的范畴。", "C": "品德的内容则是社会道德规范局部的具体体现，是社会道德要求的部分反映。", "D": "品德又称道德品质，是道德在个体身上的体现，是个人依据一定的社会道德准则和规范行动时所表现出的稳定的心理特征或倾向。"}, "answer": "B", "explanation": "教材区分“品德”和“道德”：道德反映社会生活，产生、发展和变化服从社会发展规律，属于社会意识范畴；品德是道德在个体身上的体现，属于个体意识范畴。选项B把“道德”的特征说成“品德”的特征，因此错误。选项C“品德的内容是社会道德规范局部的具体体现，是社会道德要求的部分反映”与教材原文一致。"}, {"type": "单选", "num": 43, "text": "具有胆小孤僻、行动迟缓、情感体验深刻、善于觉察等特征的人属于以下哪种气质类型", "options": {"A": "粘液质", "B": "抑郁质", "C": "胆汁质", "D": "多血质"}, "answer": "B", "explanation": "抑郁质的特点是胆小孤僻、行动迟缓、情感体验深刻、善于觉察。"}, {"type": "单选", "num": 44, "text": "下列大学生中常见的不合理信念中的绝对化要求的是", "options": {"A": "“如果我这次竞聘不顺利，我这一辈子就完了”", "B": "“如果我这门课考不好，我真是一个无用的人”", "C": "“尺有所长，寸有所短”", "D": "“我的表现必须得到所有人的高度评价”"}, "answer": "D", "explanation": "\"我的表现必须得到所有人的高度评价\"中使用\"必须\"，是绝对化要求。"}, {"type": "单选", "num": 45, "text": "提出了“学习的最佳期”的概念的心理学家是", "options": {"A": "弗洛伊德", "B": "维果茨基", "C": "皮亚杰", "D": "埃里克森"}, "answer": "B", "explanation": "\"学习的最佳期\"概念由维果茨基提出。"}, {"type": "单选", "num": 46, "text": "教学是否有效的最主要的标准是", "options": {"A": "学生的投入", "B": "教师的投入", "C": "学生的进步和发展", "D": "教师的进步和发展"}, "answer": "C", "explanation": "教学有效性的最主要标准是学生的进步和发展。"}, {"type": "单选", "num": 47, "text": "在课程的开始阶段就要", "options": {"A": "确立学习目标", "B": "使学生适应课堂教学", "C": "复习先前知识", "D": "呈现新内容"}, "answer": "A", "explanation": "课程开始阶段应首先确立学习目标。"}, {"type": "单选", "num": 48, "text": "一般说来，激发学生创造意识的主要方法不包括：", "options": {"A": "培养良好的否定意识", "B": "培养良好的问题意识", "C": "勤于思考", "D": "给予权威答案"}, "answer": "D", "explanation": "教材在“大学生创造性的培养”中提出，激发大学生创造意识的主要方法有：勤于思考、培养良好的问题意识、培养良好的否定意识。A、B、C均属于主要方法；“给予权威答案”不利于问题意识和否定意识的形成，因此不包括在内。"}, {"type": "单选", "num": 49, "text": "高校教师职业角色形成的三个阶段不包括", "options": {"A": "认同阶段", "B": "认知阶段", "C": "内化阶段", "D": "信念形成阶段"}, "answer": "C", "explanation": "教材列出的高校教师职业角色形成阶段是认知阶段、认同阶段和信念形成阶段，不包括内化阶段。"}, {"type": "单选", "num": 50, "text": "麦克利兰研究人类的需要与动机的工具是", "options": {"A": "问卷法", "B": "访谈法", "C": "“主题统觉投射测验”", "D": "罗夏墨迹测验"}, "answer": "C", "explanation": "麦克利兰使用主题统觉测验（TAT）测量成就动机，属于投射测验。"}, {"type": "单选", "num": 51, "text": "下列属于知识的负迁移的是", "options": {"A": "一种学习使另一学习所需时间或所需练习次增加", "B": "一种学习使另一学习具有了良好的心理准备状态", "C": "已经具有的知识经验使学习者顺利地解决了面临的问题", "D": "一种学习使另一学习活动所需时间或练习次数减少"}, "answer": "A", "explanation": "负迁移是消极干扰。A选项增加时间或次数是负迁移。其他三项是正迁移。"}, {"type": "单选", "num": 52, "text": "将学习分为接受学习和发现学习的心理学家是", "options": {"A": "奥苏伯尔", "B": "加涅", "C": "布卢姆", "D": "詹姆斯"}, "answer": "A", "explanation": "奥苏伯尔将学习分为接受学习和发现学习。"}, {"type": "单选", "num": 53, "text": "弗洛姆强调产生大量心理健康者或“创发者”的唯一途径是", "options": {"A": "社会变革", "B": "“中和”", "C": "自我实现", "D": "机能充分发挥"}, "answer": "A", "explanation": "弗洛姆认为产生\"创发者\"的唯一途径是社会变革。"}, {"type": "单选", "num": 54, "text": "马斯洛认为，自尊和受到别人尊重的需要属于", "options": {"A": "爱与归属的需要", "B": "尊重的需要", "C": "生理需要", "D": "安全需要"}, "answer": "B", "explanation": "自尊和受到别人尊重的需要属于尊重的需要（esteem needs）。"}, {"type": "单选", "num": 55, "text": "以下哪项不是高等教育的特征：", "options": {"A": "职业定向", "B": "注重发展和创新", "C": "非“大众化”", "D": "以成人为对象"}, "answer": "C", "explanation": "高等教育已从精英化走向大众化，\"非大众化\"不是高等教育的特征。"}, {"type": "单选", "num": 56, "text": "具有活泼好动、反应迅速、情绪发生快而多变、兴趣容易转移等特征的人属于以下哪种气质类型", "options": {"A": "多血质", "B": "胆汁质", "C": "抑郁质", "D": "粘液质"}, "answer": "A", "explanation": "多血质的特点是活泼好动、反应迅速、情绪发生快而多变、兴趣容易转移。"}, {"type": "单选", "num": 57, "text": "在师生互动中，影响教学效果的最为关键性因素是", "options": {"A": "语言沟通", "B": "眼神交流", "C": "肢体语言", "D": "面部表情"}, "answer": "A", "explanation": "语言沟通是师生互动中影响教学效果的最关键因素。"}, {"type": "单选", "num": 58, "text": "下列大学生中常见的不合理信念中的过分概况化的是", "options": {"A": "“如果我这次竞聘不顺利，我这一辈子就完了”", "B": "“如果我这门课考不好，我真是一个无用的人”", "C": "“尺有所长，寸有所短”", "D": "“我的表现必须得到所有人的高度评价”"}, "answer": "B", "explanation": "过分概括化是以偏概全的不合理信念。B选项将\"考试考不好\"等同于\"无用的人\"，是典型的过分概括化。A是糟糕至极，D是绝对化要求。"}, {"type": "单选", "num": 59, "text": "成就动机低的人，愿意选择的职业特征是", "options": {"A": "风险高、独立决策少", "B": "风险小、独立决策多", "C": "风险高、独立决策多", "D": "风险小、独立决策少"}, "answer": "D", "explanation": "成就动机低的人倾向于选择风险小、独立决策少的职业。"}, {"type": "单选", "num": 60, "text": "提出人格发展的八阶段论的心理学家是", "options": {"A": "弗洛伊德", "B": "维果茨基", "C": "皮亚杰", "D": "埃里克森"}, "answer": "D", "explanation": "人格发展八阶段论由埃里克森提出（心理社会发展理论）。"}, {"type": "单选", "num": 61, "text": "马斯洛认为，具有健全人格的人是", "options": {"A": "自我实现的人", "B": "机能充分发挥的人", "C": "“成熟者”", "D": "创发者"}, "answer": "A", "explanation": "马斯洛将具有健全人格的人称为\"自我实现的人\"。"}, {"type": "单选", "num": 62, "text": "在道德情感形成的形式上，不包括", "options": {"A": "工具性的相对主义", "B": "直觉的道德感", "C": "与具体的道德形象相联系的情绪体验", "D": "意识到道德伦理的情绪体验"}, "answer": "A", "explanation": "道德情感形成形式包括：直觉的道德感、与具体道德形象相联系的情绪体验、意识到道德伦理的情绪体验。\"工具性的相对主义\"是柯尔伯格道德发展理论中的一个阶段，不是道德情感形式。"}, {"type": "单选", "num": 63, "text": "高等教育过程中的心理现象不包括", "options": {"A": "教师心理", "B": "家长心理", "C": "高校教师和大学生之间相互作用的心理", "D": "高校学生的心理"}, "answer": "B", "explanation": "高等教育心理学研究教师心理、学生心理和师生互动心理。家长心理不属于核心内容。"}, {"type": "单选", "num": 64, "text": "“鱼与熊掌，不可兼得”属于动机冲突中的", "options": {"A": "双趋冲突", "B": "双避冲突", "C": "趋避冲突", "D": "多重趋避冲突"}, "answer": "A", "explanation": "鱼与熊掌不可兼得是两者都想要但只能选其一，属于双趋冲突（两个目标都想追求）。"}, {"type": "单选", "num": 65, "text": "下列属于具体形象思维的是", "options": {"A": "在动手重新布置房间之前，我们会先利用头脑中各种装饰物和家具的形象考虑如何进行摆设，形成多种方案，再选择最佳方案。", "B": "3岁前儿童只能在动作中思考问题", "C": "聋哑人通过手势交往", "D": "教室的多媒体投影仪坏了，技术人员一边检查相关部件，一边思索损坏原因，最后排除故障。"}, "answer": "A", "explanation": "具体形象思维借助表象思考。A选项在头脑中利用形象进行规划是具体形象思维。B和D是直观动作思维。"}, {"type": "单选", "num": 66, "text": "关于发散思维的独特性，下列说法错误的是", "options": {"A": "指对问题提出超乎寻常的、新颖的、独特的见解，即以前所未有的新观点、新角度去反映事物。", "B": "它最能代表发散思维的本质，是最高层次的发散特征。", "C": "表现为发散的“新异”、“独到”。", "D": "指思考方式变化多端，思维产品的种类不拘一格，能举一反三，触类旁通，随机应变，思维不受定势束缚，能产生多种多样的新观点。"}, "answer": "D", "explanation": "发散思维的独特性指提出超乎寻常的新颖独特见解。D描述的是变通性（flexibility，灵活多变、举一反三），不是独特性。"}, {"type": "单选", "num": 67, "text": "马斯洛认为，人类最原始的基本需要，包括饮、食、衣、居、性等需要属于", "options": {"A": "尊重的需要", "B": "爱与归属的需要", "C": "安全需要", "D": "生理需要"}, "answer": "D", "explanation": "马斯洛认为最原始的基本需要是生理需要。"}, {"type": "单选", "num": 68, "text": "“个人对于人生目的和意义的根本看法和态度，是一定的世界观在人生问题上的反映”这句话描述的是", "options": {"A": "世界观", "B": "职业观", "C": "人生观", "D": "价值观"}, "answer": "C", "explanation": "这是人生观的标准定义。"}, {"type": "单选", "num": 69, "text": "大学生动机的冲突性表现在", "options": {"A": "多样性和学习动机占主导地位", "B": "由于大学生面临着学习、交往、升学、职业等多方面选择", "C": "大学生为了获得真才实学而勤奋学习", "D": "大学生不轻易将内心活动表露出来，他们的动机和行为之间也经常不一致"}, "answer": "B", "explanation": "大学生动机冲突性表现在面临学习、交往、升学、职业等多方面选择时的矛盾。"}, {"type": "单选", "num": 70, "text": "教师的角色间冲突不包括", "options": {"A": "模范公民同教师实际地位平庸的矛盾", "B": "模范公民同普通人的冲突", "C": "教师对学生的爱心同执法者身份的矛盾", "D": "知识传授者同知识建设者的矛盾"}, "answer": "C", "explanation": "教师爱心与执法者的矛盾属于角色内冲突，不是角色间冲突。"}, {"type": "单选", "num": 71, "text": "以下不属于赫尔巴特提出的学习过程的阶段：", "options": {"A": "感觉阶段", "B": "记忆阶段", "C": "理解阶段", "D": "遗忘阶段"}, "answer": "D", "explanation": "赫尔巴特学习阶段为：感觉（明了）、记忆（联想）、理解（系统）、应用（方法）。遗忘阶段不是赫尔巴特提出的。"}, {"type": "单选", "num": 72, "text": "状态型激励理论不包括", "options": {"A": "归因理论", "B": "公平理论", "C": "双因素理论", "D": "挫折理论"}, "answer": "C", "explanation": "状态型激励理论包括归因理论、公平理论和挫折理论。双因素理论属于内容型激励理论。"}, {"type": "单选", "num": 73, "text": "具有安静稳重、反应缓慢、沉默寡言、情绪不易外露、注意稳定但难于转移、善于忍耐等特征的人属于以下哪种气质类型", "options": {"A": "粘液质", "B": "抑郁质", "C": "胆汁质", "D": "多血质"}, "answer": "A", "explanation": "粘液质的特点是安静稳重、反应缓慢、沉默寡言、情绪不易外露、注意稳定、善于忍耐。"}, {"type": "单选", "num": 74, "text": "教师的主要作用是", "options": {"A": "维护学生心理健康", "B": "开展教学活动", "C": "传授给学生知识", "D": "管理班级秩序"}, "answer": "C", "explanation": "教师的主要作用是传授知识。"}, {"type": "单选", "num": 75, "text": "以下关于价值观的说法不正确的是", "options": {"A": "人的价值包括社会价值和自我价值", "B": "价值观是人们以自身需要为尺度对事物重要性认识的观念系统", "C": "如果一个人不追求对社会贡献，只追求个人需要满足，把社会价值和个人价值对立起来，就不可能实现个人的自我价值", "D": "是个人对于人生目的和意义的根本看法和态度，是一定的世界观在人生问题上的反映"}, "answer": "D", "explanation": "D选项是人生观的定义，不是价值观的定义。价值观是以自身需要为尺度对事物重要性的观念系统。"}, {"type": "单选", "num": 76, "text": "奥尔波特在哈佛大学长期研究高心理健康水平的人，并把他们称作", "options": {"A": "“此时此地”型人", "B": "“成熟者”", "C": "机能充分发挥型人", "D": "自我实现型人"}, "answer": "B", "explanation": "奥尔波特将高心理健康水平的人称为\"成熟者\"。马斯洛称\"自我实现者\"，罗杰斯称\"机能充分发挥者\"。"}, {"type": "单选", "num": 77, "text": "激励的中介机制是", "options": {"A": "行为", "B": "目标", "C": "诱因", "D": "动机"}, "answer": "D", "explanation": "激励的中介机制是动机，动机是连接需要和行为的中介变量。"}, {"type": "单选", "num": 78, "text": "认知地图是哪位心理学家提出的", "options": {"A": "巴甫洛夫", "B": "考夫卡", "C": "斯金纳", "D": "托尔曼"}, "answer": "D", "explanation": "认知地图由美国心理学家托尔曼通过白鼠迷宫实验提出。"}, {"type": "单选", "num": 79, "text": "人格的基本特征不包括", "options": {"A": "社会性", "B": "整体性", "C": "多变性", "D": "独特性"}, "answer": "C", "explanation": "人格的基本特征包括独特性、稳定性、整体性、社会性和功能性。\"多变性\"不是人格特征。"}, {"type": "单选", "num": 80, "text": "需要层次论的提出者是", "options": {"A": "赫茨伯格", "B": "马斯洛", "C": "弗鲁姆", "D": "麦克利兰的"}, "answer": "B", "explanation": "需要层次论由人本主义心理学家马斯洛提出。"}, {"type": "单选", "num": 81, "text": "“翻开相册会在看到某张照片时会心一笑，而在看到另外一张照片时眉头深锁”这句话描述的是哪种记忆起作用：", "options": {"A": "动作记忆", "B": "情绪记忆", "C": "语词－逻辑记忆", "D": "形象记忆"}, "answer": "B", "explanation": "看到照片会心一笑或眉头深锁是情绪感受被重新唤起，属于情绪记忆。"}, {"type": "单选", "num": 82, "text": "以下不属于大学生中常见的自我认知问题的是", "options": {"A": "抑郁", "B": "虚荣", "C": "自负", "D": "自卑"}, "answer": "A", "explanation": "自卑、自负、虚荣是自我认知问题。抑郁属于情绪问题。"}, {"type": "单选", "num": 83, "text": "教师有时不可避免地成为学生仇视的对象，此时他是在扮演什么样的角色", "options": {"A": "替罪羊", "B": "心理咨询和治疗专家", "C": "侦探和纪律执行者", "D": "家长的代理人"}, "answer": "A", "explanation": "教师成为学生仇视对象时扮演的是\"替罪羊\"角色，是消极角色定位。"}, {"type": "单选", "num": 84, "text": "学习时间理论的提出者是", "options": {"A": "卡罗尔", "B": "布鲁姆", "C": "凯勒", "D": "斯金纳"}, "answer": "A", "explanation": "学习时间理论由美国教育心理学家卡罗尔提出，他认为学习时间是影响学习效果的关键变量。"}, {"type": "单选", "num": 85, "text": "教师的情操不包括", "options": {"A": "美感", "B": "求知欲", "C": "道德感", "D": "理智感"}, "answer": "B", "explanation": "教师的情操包括道德感、理智感和美感。求知欲属于理智感的内容，但不是情操的独立分类。"}, {"type": "单选", "num": 86, "text": "期望理论的提出者是", "options": {"A": "洛克", "B": "斯金纳", "C": "马斯洛", "D": "弗鲁姆"}, "answer": "D", "explanation": "期望理论由弗鲁姆（Vroom）提出：动机=效价×期望。"}, {"type": "单选", "num": 87, "text": "下列大学生的合理信念的是", "options": {"A": "“如果我这门课考不好，我真是一个无用的人”", "B": "“如果我这次竞聘不顺利，我这一辈子就完了”", "C": "“我的表现必须得到所有人的高度评价”", "D": "“尺有所长，寸有所短”"}, "answer": "D", "explanation": "\"尺有所长，寸有所短\"是客观辩证的合理信念。其他三项均为不合理信念。"}, {"type": "单选", "num": 88, "text": "气质类型说最早可追溯到", "options": {"A": "罗马医生盖伦", "B": "古希腊医学家希波克拉底", "C": "我国古代教育家孔子", "D": "德国精神病学家克瑞奇米尔"}, "answer": "B", "explanation": "气质类型说最早可追溯到古希腊医学家希波克拉底，他提出四种气质类型。"}, {"type": "单选", "num": 89, "text": "下列不属于吉尔福特认为发散思维所拥有的特点是", "options": {"A": "流畅性", "B": "概括性", "C": "变通性", "D": "独特性"}, "answer": "B", "explanation": "吉尔福特认为发散思维包括流畅性、变通性和独特性。\"概括性\"不是发散思维特点。"}, {"type": "单选", "num": 90, "text": "最近发展区理论的提出者是", "options": {"A": "布鲁姆", "B": "卡罗尔", "C": "维果茨基", "D": "凯勒"}, "answer": "C", "explanation": "最近发展区理论由苏联心理学家维果茨基提出，指儿童现有发展水平与在成人帮助下可能达到的发展水平之间的差距。"}, {"type": "单选", "num": 91, "text": "根据满足需要的对象不同，将人对智力、道德、审美、音乐、美术的需要和劳动交往、学习和参加社会活动需要归为", "options": {"A": "精神需要", "B": "物质需要", "C": "社会需要", "D": "生理需要"}, "answer": "A", "explanation": "智力、道德、审美、音乐、美术等需要属于精神需要。"}, {"type": "单选", "num": 92, "text": "关于道德的描述，下列说法错误的是", "options": {"A": "从反映内容上看，道德反映的内容比品德反映的内容要广阔得多，概括得多。", "B": "人们依据道德规范来辨别是非、善恶、美丑，指导或调节行为。", "C": "道德产生的力量源泉则是个人需要。", "D": "道德的内容是社会生活的总体要求，是对经济基础的反映，是调节社会关系的行为规范的完整体系。"}, "answer": "C", "explanation": "道德产生的力量源泉是社会需要（社会发展的需要），不是个人需要。"}, {"type": "单选", "num": 93, "text": "双因素理论的提出者是", "options": {"A": "赫茨伯格", "B": "马斯洛", "C": "弗鲁姆", "D": "麦克利兰的"}, "answer": "A", "explanation": "双因素理论由赫茨伯格提出。"}, {"type": "单选", "num": 94, "text": "程序性知识的表征方法是", "options": {"A": "表象", "B": "命题", "C": "图式", "D": "产生式"}, "answer": "D", "explanation": "程序性知识是关于\"如何做\"的知识，其表征方式主要是产生式（production），以IF-THEN条件语句形式存储。"}, {"type": "单选", "num": 95, "text": "“重赏之下，必有勇夫”说的是什么的作用", "options": {"A": "诱因", "B": "抱负水准", "C": "兴趣", "D": "需要"}, "answer": "A", "explanation": "\"重赏之下必有勇夫\"说明诱因的作用。"}, {"type": "单选", "num": 96, "text": "下列不属于知识的正迁移的是", "options": {"A": "一种学习使另一学习所需时间或所需练习次增加", "B": "一种学习使另一学习具有了良好的心理准备状态", "C": "已经具有的知识经验使学习者顺利地解决了面临的问题", "D": "一种学习使另一学习活动所需时间或练习次数减少"}, "answer": "A", "explanation": "正迁移是积极促进作用。A选项\"增加时间或次数\"是负迁移的表现（消极干扰）。"}, {"type": "单选", "num": 97, "text": "根据需要起源的不同，将饮食、运动、休息、睡眠、排泄、配偶、嗣后等需要归为", "options": {"A": "物质需要", "B": "精神需要", "C": "生理需要", "D": "社会需要"}, "answer": "C", "explanation": "根据需要起源不同，饮食、运动、休息等是先天就有的生理需要（自然需要）。"}, {"type": "单选", "num": 98, "text": "巴甫洛夫通过狗分泌唾液的实验揭示了什么理论", "options": {"A": "脑功能学说", "B": "精神分析理论", "C": "经典条件反射理论", "D": "操作性条件作用理论"}, "answer": "C", "explanation": "巴甫洛夫通过狗分泌唾液实验揭示了经典条件反射理论。"}, {"type": "单选", "num": 99, "text": "具有精力旺盛、直率热情、行动敏捷、情绪易于激动、心情变化剧烈、脾气暴躁等特征的人属于以下哪种气质类型", "options": {"A": "多血质", "B": "胆汁质", "C": "抑郁质", "D": "粘液质"}, "answer": "B", "explanation": "胆汁质的特点是精力旺盛、直率热情、情绪易激动、脾气暴躁。多血质活泼好动，粘液质安静稳重，抑郁质胆小孤僻。"}, {"type": "单选", "num": 100, "text": "韦纳认为，人在对自己的成败理由进行分析时有6种主要因素，其中可控的是", "options": {"A": "努力", "B": "能力", "C": "机遇", "D": "任务难度"}, "answer": "A", "explanation": "韦纳归因理论六因素中，只有努力是唯一可控因素。能力是稳定不可控的，机遇和任务难度也是不可控的。"}, {"type": "单选", "num": 101, "text": "下列不属于大学生的道德认识能力发展的突出表现：", "options": {"A": "深刻性", "B": "全面性", "C": "片面性", "D": "独立性"}, "answer": "C", "explanation": "大学生道德认识能力发展表现为深刻性、全面性和独立性。\"片面性\"不是发展表现。"}, {"type": "单选", "num": 102, "text": "大学生激励目标的设置要", "options": {"A": "模糊、有针对性", "B": "模糊、无针对性", "C": "具体、有针对性", "D": "具体、无针对性"}, "answer": "C", "explanation": "激励目标设置要具体、有针对性。"}, {"type": "单选", "num": 103, "text": "下列大学生中常见的不合理信念中的“糟的很”的是", "options": {"A": "“如果我这次竞聘不顺利，我这一辈子就完了”", "B": "“如果我这门课考不好，我真是一个无用的人”", "C": "“尺有所长，寸有所短”", "D": "“我的表现必须得到所有人的高度评价”"}, "answer": "A", "explanation": "\"糟糕至极\"是把一件坏事的结果想得极其糟糕。A选项将竞聘不顺利等同于一辈子完了，是典型的糟糕至极。"}, {"type": "单选", "num": 104, "text": "人格障碍与正常人格的主要区别不包括", "options": {"A": "主观的感受性", "B": "日常的普遍性", "C": "社会的接受性", "D": "生活的适应性"}, "answer": "B", "explanation": "教材列出人格障碍与正常人格的主要区别为社会的接受性、生活的适应性和主观的感受性，不包括日常的普遍性。"}, {"type": "单选", "num": 105, "text": "过程型激励理论不包括", "options": {"A": "弗鲁姆的期望理论", "B": "马斯洛的需要层次论", "C": "斯金纳的强化理论", "D": "洛克的目标理论"}, "answer": "B", "explanation": "马斯洛需要层次论是内容型激励理论，不是过程型。过程型包括期望理论、强化理论、目标理论。"}, {"type": "单选", "num": 106, "text": "教师的角色内冲突不包括", "options": {"A": "模范公民同普通人的冲突", "B": "学生的朋友和知己、心理咨询和治疗学家同团体的领导、侦探和纪律执行者的矛盾", "C": "知识的传授者与学生自主学习的矛盾", "D": "教师对学生的爱心同执法者身份的矛盾"}, "answer": "A", "explanation": "模范公民同普通人的冲突是角色间冲突，不是角色内冲突。"}, {"type": "单选", "num": 107, "text": "下列关于爬山法与手段-目的分析法的说法中，错误的是", "options": {"A": "都属于算法的一种。", "B": "爬山法与手段-目的分析法的不同在于：有时人们为了实现最终目标，不得不采取迂回方式，暂时扩大初始状态与目标状态的差异（暂时“退回去”或“欲进先退”）以有利于问题解决。", "C": "爬山法即采用一定方法，有时是迂回方式，逐步降低初始状态和目标状态的差异以解决问题。", "D": "手段-目的分析指将需要达到的问题的目标状态分析成若干子目标，采用一定手段，消除差异，通过实现一系列子目标最终达到总目标。"}, "answer": "A", "explanation": "爬山法和手段-目的分析法都属于启发法（heuristics），而不是算法（algorithm）。算法保证解决问题但费时，启发法依靠经验策略。"}, {"type": "单选", "num": 108, "text": "建构主义的教学以什么为中心", "options": {"A": "多媒体", "B": "教材", "C": "学生", "D": "教师"}, "answer": "C", "explanation": "建构主义教学以学生为中心，学生是知识的主动建构者。"}, {"type": "单选", "num": 109, "text": "在心理学研究中，用来研究人格形成与发展中生物遗传因素作用最好的方法是", "options": {"A": "问卷法", "B": "测验法", "C": "双生子研究法", "D": "实验室实验法"}, "answer": "C", "explanation": "双生子研究法是研究人格形成中遗传因素作用的最好方法。"}, {"type": "单选", "num": 110, "text": "根据满足需要的对象不同，将饮食、运动、休息、睡眠、排泄、配偶、嗣后等需要归为", "options": {"A": "物质需要", "B": "精神需要", "C": "生理需要", "D": "社会需要"}, "answer": "A", "explanation": "教材按满足需要的对象不同，将需要分为物质需要和精神需要。饮食、运动、休息、睡眠、排泄、配偶、嗣后等属于物质需要。"}, {"type": "单选", "num": 111, "text": "习惯化是指", "options": {"A": "由于重复刺激引起的反应性下降，它涉及反应的减少，而不是新反应的习得。", "B": "感受能力和肌肉能力下降", "C": "人的感受能力发生了变化", "D": "由于刺激重复使有机体对它的反应性增强，即有机体对环境中的某一特定刺激更容易作出反应"}, "answer": "A", "explanation": "习惯化是指由于重复刺激引起的反应性下降，涉及反应的减少，而不是新反应的习得。"}, {"type": "单选", "num": 112, "text": "由亚里士多德完成的历史上第一部论述心理现象的著作是（ ）", "options": {"A": "《理想国》", "B": "《论灵魂》", "C": "《乌托邦》", "D": "《论人性》"}, "answer": "B", "explanation": "亚里士多德的《论灵魂》是历史上第一部系统论述心理现象的著作。"}, {"type": "单选", "num": 113, "text": "下列不属于桑代克的“学习公律”是", "options": {"A": "练习律", "B": "效果律", "C": "准备律", "D": "消退率"}, "answer": "D", "explanation": "桑代克三大学习公律是准备律、练习律和效果律。消退率不是桑代克提出的。"}, {"type": "单选", "num": 114, "text": "考试中的“怯场”现象主要由什么造成的", "options": {"A": "动机过强", "B": "动机过低", "C": "中等动机", "D": "没有动机"}, "answer": "A", "explanation": "考试怯场主要由动机过强造成。根据耶克斯-多德森定律，动机过强导致焦虑水平过高，影响发挥。"}, {"type": "单选", "num": 115, "text": "安德森（J·Anderson，1990）和加涅（E·Gagne et al.，1993）等人认为，程序性知识的获得主要的阶段不包括：", "options": {"A": "联合阶段", "B": "陈述阶段", "C": "自动化阶段", "D": "识记阶段"}, "answer": "D", "explanation": "安德森和加涅认为程序性知识的获得经历三个阶段：陈述阶段、联合阶段、自动化阶段。识记阶段(D)不属于程序性知识获得的阶段。"}, {"type": "单选", "num": 116, "text": "现代心理健康运动的开展使人们对教师产生了什么样的新角色期待", "options": {"A": "替罪羊", "B": "心理咨询和治疗专家", "C": "学生的朋友和知己", "D": "模范公民"}, "answer": "B", "explanation": "现代心理健康运动期待教师承担\"心理咨询和治疗专家\"角色。"}, {"type": "单选", "num": 117, "text": "下列不属于遗忘理论的是", "options": {"A": "模块说", "B": "衰退说", "C": "提取失败说", "D": "同化说"}, "answer": "A", "explanation": "遗忘理论主要包括衰退说、干扰说、提取失败说和同化说。\"模块说\"是记忆存储模型，不是遗忘理论。"}, {"type": "单选", "num": 118, "text": "关于皮亚杰和柯尔伯格的研究成果对学校德育的启发意义，下列说法不正确的是", "options": {"A": "道德认识水平的提高与思维水平的提高平行。", "B": "道德判断水平的高低对道德行为选择有重要制约作用。", "C": "要以道德伦理说教来达到教育目标", "D": "道德认识的发展是循序渐进的"}, "answer": "C", "explanation": "皮亚杰和柯尔伯格的研究表明道德认识发展是循序渐进的。以道德伦理说教来达到教育目标不是他们的观点。"}, {"type": "单选", "num": 119, "text": "大学生在择业时，有的工作经济收入高但工作环境较差，有的工作经济收入低但工作环境较好，此类冲突属于动机冲突中的", "options": {"A": "双趋冲突", "B": "双避冲突", "C": "趋避冲突", "D": "多重趋避冲突"}, "answer": "D", "explanation": "多个职业选择各有优劣，每个都有吸引和排斥方面，属于多重趋避冲突。"}, {"type": "单选", "num": 120, "text": "关于学习，以下说法不正确的是", "options": {"A": "动物和人类都可以进行学习。", "B": "心理学中的学习是指个体在生活中由于经验而产生的行为或行为潜能的比较持久的变化。", "C": "学习只存在于人类的活动中，动物不存在学习。", "D": "学习的发生以行为和行为潜能的改变为标志。"}, "answer": "C", "explanation": "动物也存在学习（如条件反射实验），学习不仅存在于人类。"}, {"type": "单选", "num": 121, "text": "马斯洛还认为，自我实现者并不是普遍存在的，大约只有多少人能够完全达到自我实现。", "options": {"A": "4%左右", "B": "2%左右", "C": "3%左右", "D": "1%左右"}, "answer": "D", "explanation": "马斯洛认为仅约1%的人能达到自我实现的境界。"}, {"type": "单选", "num": 122, "text": "什么是成为好教师的关键", "options": {"A": "时间投入", "B": "情感投入", "C": "金钱投入", "D": "知识投入"}, "answer": "B", "explanation": "情感投入是成为好教师的关键，是教师专业发展的内在动力。"}, {"type": "单选", "num": 123, "text": "建构主义教学的具体模式不包括", "options": {"A": "案例教学", "B": "个别化教学", "C": "发现学习", "D": "合作学习"}, "answer": "A", "explanation": "教材在“建构主义教学的具体模式”中列举合作学习、发现学习和个别化教学；案例教学属于其他教学模式，因此“不包括”应选A。"}, {"type": "单选", "num": 124, "text": "凯勒计划的原理是", "options": {"A": "托尔曼目的行为主义", "B": "班杜拉的社会学习", "C": "巴普洛夫条件性反射", "D": "斯金纳操作性条件反射"}, "answer": "D", "explanation": "凯勒计划（个人化教学系统）以斯金纳的操作性条件反射为理论基础，强调小步教学、自定步调和及时反馈。"}, {"type": "单选", "num": 125, "text": "马斯洛认为，人们追求实现自己的能力，并使之完善化的需要。", "options": {"A": "爱与归属的需要", "B": "自我实现的需要", "C": "生理需要", "D": "安全需要"}, "answer": "B", "explanation": "自我实现的需要是追求实现自己能力并使之完善化的需要，是马斯洛需要层次的最高层。"}, {"type": "单选", "num": 126, "text": "下列关于培养大学生良好自我意识的途径中不正确的做法是", "options": {"A": "放纵自我", "B": "积极悦纳自我", "C": "有效控制自我", "D": "正确认识自我"}, "answer": "A", "explanation": "放纵自我是不正确的做法。正确途径是正确认识、积极悦纳、有效控制自我。"}, {"type": "单选", "num": 127, "text": "布鲁姆的掌握学习理论更强调什么在学习中的作用", "options": {"A": "学习时间", "B": "学习准备", "C": "矫正性反馈", "D": "学生参与"}, "answer": "B", "explanation": "教材指出，布卢姆的掌握学习理论没有把能力作为学习的决定性因素，而是更强调学习准备在学习中的作用。"}, {"type": "单选", "num": 128, "text": "目标设置理论的提出者是", "options": {"A": "弗鲁姆", "B": "马斯洛", "C": "斯金纳", "D": "洛克"}, "answer": "D", "explanation": "目标设置理论由洛克（Edwin Locke）提出。"}, {"type": "单选", "num": 129, "text": "激励作为过程以什么告终", "options": {"A": "目标实现需要满足", "B": "行动", "C": "需要", "D": "动机"}, "answer": "A", "explanation": "激励过程以目标实现和需要满足告终。"}, {"type": "单选", "num": 130, "text": "下列不属于对学习对象理解的水平是：", "options": {"A": "初级水平的理解", "B": "一般水平的理解", "C": "高级水平的理解", "D": "中级水平的理解"}, "answer": "B", "explanation": "教材把对学习对象的理解分为初级水平、中级水平和高级水平三种，不包括“一般水平”。"}, {"type": "单选", "num": 131, "text": "旅游是很有吸引力的活动，但耗费时间、精力和钱财，此类冲突属于动机冲突中的", "options": {"A": "双趋冲突", "B": "双避冲突", "C": "趋避冲突", "D": "多重趋避冲突"}, "answer": "C", "explanation": "旅游既有吸引力又有耗费时间和钱财的消极面，属于趋避冲突。"}, {"type": "单选", "num": 132, "text": "相比中小学老师，高校教师都身兼教师与什么的双重身份", "options": {"A": "反思者或研究者", "B": "指导者或促进者", "C": "科学家或思想家", "D": "组织者或管理者"}, "answer": "C", "explanation": "教材指出，高校教师往往同时兼有教师和科学家，或教师和思想家/科学家的双重身份。"}, {"type": "单选", "num": 133, "text": "在阿特金森看来，个体在竞争时会产生两种动机：追求成功的动机和回避失败的动机。成就动机比失败动机强的人倾向于选择做什么难度的工作", "options": {"A": "高", "B": "中等", "C": "低", "D": "无"}, "answer": "B", "explanation": "阿特金森的成就动机理论指出，追求成功的动机强的人倾向于选择中等难度的任务，这类任务既有挑战性又有实现的可能性。"}, {"type": "单选", "num": 134, "text": "人格一词最初来源于", "options": {"A": "古埃及语", "B": "古希腊语", "C": "古罗马语", "D": "古巴比伦语"}, "answer": "B", "explanation": "\"人格\"一词最初来源于古希腊语\"persona\"（面具）。"}, {"type": "单选", "num": 135, "text": "皮亚杰的认知发展论中属于婴儿感知运动阶段的特征是", "options": {"A": "认知活动有了守恒性", "B": "获得了科学思维、假设-演绎推理等逻辑推理能力", "C": "开始具有信号功能", "D": "主要通过协调感觉输入和依靠动作来认识世界"}, "answer": "D", "explanation": "感知运动阶段（0-2岁）儿童主要通过协调感觉和动作来认识世界。"}, {"type": "多选", "num": 1, "text": "大学生中常见的自我认知问题主要有", "options": {"A": "自卑", "B": "自负", "C": "虚荣", "D": "抑郁"}, "answer": "ABC", "explanation": "自我认知问题：自卑、自负、虚荣。抑郁是情绪问题。"}, {"type": "多选", "num": 2, "text": "以下属于图式的特征的是：", "options": {"A": "图式有简单和复杂、抽象和具体、高级和低级之分。", "B": "图式描述的是具有一定概括程度的知识，但不是定义。", "C": "图式是在旧知识与新信息相互联系的基础上，通过“同化”与“顺应”而形成的，是经验的积极组织。", "D": "图式不是事物的各个部分的简单相加，而是按照一定规律由各个部分构成的有机整体。"}, "answer": "ABCD", "explanation": "图式特征：有不同层次、概括性知识、同化顺应形成、有机整体。"}, {"type": "多选", "num": 3, "text": "下列属于道德情感的表现", "options": {"A": "集体主义情感", "B": "爱国主义情感", "C": "道德评价", "D": "道德信念"}, "answer": "AB", "explanation": "道德情感表现：集体主义情感、爱国主义情感等。道德评价和道德信念不是情感。"}, {"type": "多选", "num": 4, "text": "培养大学生良好自我意识的途径", "options": {"A": "有效控制自我", "B": "正确认识自我", "C": "放纵自我", "D": "积极悦纳自我"}, "answer": "ABD", "explanation": "培养途径：正确认识自我、积极悦纳自我、有效控制自我。C(放纵自我)错误。"}, {"type": "多选", "num": 5, "text": "下列做法可以提高大学生问题解决能力的是", "options": {"A": "建立接纳意见的气氛", "B": "鼓励大学生仔细地界定问题", "C": "教给大学生分析问题的方法", "D": "鼓励大学生多角度地提出假设"}, "answer": "ABCD", "explanation": "提高问题解决能力：多角度假设、教分析方法、仔细界定问题、建立接纳气氛。"}, {"type": "多选", "num": 6, "text": "道德认识是人的认知过程在品德上的表现，它的形成由以下层次构成：", "options": {"A": "道德信念的产生", "B": "道德判断的发展", "C": "道德概念的形成", "D": "道德知识的掌握"}, "answer": "ABCD", "explanation": "道德认识形成层次：道德知识掌握→道德概念形成→道德判断发展→道德信念产生。"}, {"type": "多选", "num": 7, "text": "关于品德的描述，下列说法正确的是", "options": {"A": "品德的内容则是社会道德规范局部的具体体现，是社会道德要求的部分反映。", "B": "品德又称道德品质，是道德在个体身上的体现，是个人依据一定的社会道德准则和规范行动时所表现出的稳定的心理特征或倾向。", "C": "品德的形成与发展不仅受社会制约，而且受个体的心理制约。", "D": "品德反映社会生活，它的产生、发展和变化服从于社会的发展规律，属于社会意识的范畴。"}, "answer": "ABC", "explanation": "教材区分道德与品德：品德是道德在个体身上的体现，既受社会制约，也受个体心理制约，是社会道德规范在个体身上的具体反映。D项把“道德”反映社会生活、属于社会意识的表述误用于“品德”，不正确。"}, {"type": "多选", "num": 8, "text": "大学生的心理健康包括以下方面", "options": {"A": "情绪稳定，适应良好，有幸福感和成就感", "B": "形成了优良的心理品质", "C": "心智潜能得到了充分发挥", "D": "具有反社会人格"}, "answer": "ABC", "explanation": "心理健康包括：情绪稳定适应良好、优良心理品质、心智潜能发挥。反社会人格是不健康表现。"}, {"type": "多选", "num": 9, "text": "大学生心理健康教育的方法与途径有", "options": {"A": "开展心理健康教育", "B": "优化大学生的成长环境", "C": "建立心理咨询机构", "D": "提高大学生的挫折耐受力"}, "answer": "ABCD", "explanation": "方法途径：开展心理健康教育、优化环境、建立咨询机构、提高耐受力。"}, {"type": "多选", "num": 10, "text": "按照记忆的内容，可以将记忆分为", "options": {"A": "形象记忆", "B": "语词－逻辑记忆", "C": "情绪记忆", "D": "动作记忆"}, "answer": "ABCD", "explanation": "按内容记忆分：形象记忆、语词-逻辑记忆、情绪记忆、动作记忆。"}, {"type": "多选", "num": 11, "text": "下列属于影响大学生心理健康的个人因素中认知方面是", "options": {"A": "遗传因素", "B": "自我评价偏差", "C": "神经系统的先天素质不健全", "D": "存在不合理的认知方式和信念"}, "answer": "BD", "explanation": "认知因素：不合理认知方式和信念、自我评价偏差。A和C是生理因素。"}, {"type": "多选", "num": 12, "text": "高等教育文化选择途径主要有哪几种", "options": {"A": "培养目标", "B": "课程和教材", "C": "教师群体", "D": "校园环境"}, "answer": "ABCD", "explanation": "文化选择途径：培养目标、课程教材、教师群体、校园环境。"}, {"type": "多选", "num": 13, "text": "下列关于图式，说法正确的是", "options": {"A": "是指外界客观物体的抽象类似物在人头脑中的再现形式。", "B": "图式是围绕某一个主题组织起来的知识表征和贮存方式，是陈述性知识表征的整合单位。", "C": "将获得知识以图式形式，围绕某一主题相互联系起来，形成一定的知识单元，将会有效地促进人对知识的存储和运用。", "D": "是将具有线性特征的事物按照一定的顺序排列。"}, "answer": "BC", "explanation": "B(图式是主题组织知识)、C(图式形式促进存储)正确。A描述表象，D描述线性排序。"}, {"type": "多选", "num": 14, "text": "记忆的时间分类可分为", "options": {"A": "永久记忆", "B": "长时记忆", "C": "短时记忆", "D": "感觉记忆"}, "answer": "BCD", "explanation": "记忆时间分类：感觉记忆、短时记忆、长时记忆。永久记忆不是标准分类。"}, {"type": "多选", "num": 15, "text": "关于算法和启发法，下列说法正确的是", "options": {"A": "启发式是个体根据已有的知识经验，在问题空间中进行较少的搜索，以达到解决问题的方法。", "B": "算法不能保证问题一定能解决，但用这种方法解决问题省时省力。", "C": "启发法的优点是保证能够解决问题，但有时需要大量的尝试，因而费时费力。", "D": "算法是一种随机尝试式的问题解决策略。在问题空间中，搜索所有可能的解决问题方法，并逐一加以尝试，最终使问题得以解决。"}, "answer": "AD", "explanation": "A(启发法是已有知识经验搜索)、D(算法是随机尝试)正确。B(算法保证解决但费时)、C(启发法不保证解决)错误。"}, {"type": "多选", "num": 16, "text": "一般说来，激发学生创造意识的主要方法中包括：", "options": {"A": "培养良好的否定意识", "B": "培养良好的问题意识", "C": "勤于思考", "D": "给予权威答案"}, "answer": "ABC", "explanation": "教材明确列出激发大学生创造意识的主要方法：勤于思考，对问题紧抓不放；培养良好的问题意识；培养良好的否定意识。给予权威答案会压制质疑和探索，不属于激发创造意识的方法。因此选A、B、C。"}, {"type": "多选", "num": 17, "text": "斯腾伯格在专家型教师原型观基础上，总结出专家型教师的基本特征", "options": {"A": "迅速有效地发现学生存在的问题", "B": "有丰富的组织化的专门知识，并能有效运用", "C": "解决教学领域问题的高效", "D": "创造性地解决问题，有很强的洞察力"}, "answer": "BCD", "explanation": "专家型教师特征：丰富组织化知识、高效解决问题、创造性洞察力。\"迅速发现学生问题\"不准确。"}, {"type": "多选", "num": 18, "text": "一般来说，思维的过程包括", "options": {"A": "抽象与概括", "B": "具体化与系统化", "C": "分析与综合", "D": "比较与分类"}, "answer": "ABCD", "explanation": "思维过程：分析与综合、比较与分类、抽象与概括、具体化与系统化。"}, {"type": "多选", "num": 19, "text": "关于品德和道德，下列说法正确的是", "options": {"A": "道德是在个体身上的体现，是个人依据一定的社会道德准则和规范行动时所表现出的稳定的心理特征或倾向。", "B": "品德是一种社会现象，是调整人们相互关系的各种行为规范和准则。", "C": "品德支配和调节着个体的道德行为，属于个体意识的范畴。", "D": "道德反映社会生活，它的产生、发展和变化服从于社会的发展规律，属于社会意识的范畴。"}, "answer": "CD", "explanation": "C(品德属于个体意识)、D(道德属于社会意识)正确。A和B把两者定义混淆了。"}, {"type": "多选", "num": 20, "text": "下列属于陈述性知识的表征方式是", "options": {"A": "线性排序", "B": "图式", "C": "表象", "D": "命题"}, "answer": "ABCD", "explanation": "教材在“知识的表征”部分明确说，陈述性知识以语言描述为主，表征方式主要包含表象、命题、线性排序和图式；并说明图式是命题、表象和线型排序三种基本表征形式的综合。因此A线性排序、B图式、C表象、D命题都属于陈述性知识的表征方式。"}, {"type": "多选", "num": 21, "text": "心理发展的特征", "options": {"A": "反映活动从混沌未分化向着分化、专门化演变；", "B": "反映活动从不随意性、被动性向着随意性、主动性演变；", "C": "从认识客体的外部现象向着认识事物的内部本质演变；", "D": "对周围事物的态度从不稳定向着稳定演变；"}, "answer": "ABCD", "explanation": "心理发展特征：分化的专门化、从被动到主动、外部到内部、不稳定到稳定。"}, {"type": "多选", "num": 22, "text": "关于品德和道德，下列说法正确的是", "options": {"A": "个体的品德对社会道德状况有一定的反作用。", "B": "品德和道德是相辅相成、辩证统一的关系。", "C": "品德是社会道德的个体化。", "D": "社会道德风气影响品德的形成与发展。"}, "answer": "ABCD", "explanation": "A(品德反作用于道德)、B(相辅相成)、C(品德是道德个体化)、D(道德风气影响品德)均正确。"}, {"type": "多选", "num": 23, "text": "关于道德的描述，下列说法正确的是", "options": {"A": "人们依据道德规范来辨别是非、善恶、美丑，指导或调节行为。", "B": "从反映内容上看，道德反映的内容比品德反映的内容要广阔得多，概括得多。", "C": "道德的内容是社会生活的总体要求，是对经济基础的反映，是调节社会关系的行为规范的完整体系。", "D": "道德产生的力量源泉则是个人需要。"}, "answer": "ABC", "explanation": "A(辨别是非)B(道德更广阔)C(对经济基础反映)正确。D错误(力量源泉是社会需要)。"}, {"type": "多选", "num": 24, "text": "下列属于一级强化物的是", "options": {"A": "娱乐", "B": "食物", "C": "安全", "D": "钱"}, "answer": "BC", "explanation": "一级强化物通常指能直接满足基本需要、无需学习即可起强化作用的刺激。食物和安全可归入一级强化物；娱乐和钱更多属于习得性或二级强化物。"}, {"type": "多选", "num": 25, "text": "关于皮亚杰提出的儿童道德发展阶段，下列说法正确的是", "options": {"A": "自律阶段的儿童已经不把规则看成是不可改变的，而是把它看作是同伴之间的共同约定，是可以改变的。", "B": "他律阶段的儿童对外在权威表现出绝对尊敬和顺从的愿望。", "C": "处在公正阶段的孩子，他们认为，服从、听话就是好孩子，否则就是坏孩子。", "D": "处在权威阶段的儿童，他们的公正观念或正义感是在可逆的道德观念上发展起来。"}, "answer": "AB", "explanation": "A(自律阶段规则可改变)、B(他律阶段服从权威)正确。C(听话是好孩子是他律)、D(权威阶段不是公正阶段)。"}, {"type": "多选", "num": 26, "text": "安德森（J·Anderson，1990）和加涅（E·Gagne et al.，1993）等人认为，程序性知识的获得主要包括以下阶段：", "options": {"A": "识记阶段", "B": "自动化阶段", "C": "陈述阶段", "D": "联合阶段"}, "answer": "BCD", "explanation": "程序性知识获得阶段：陈述阶段、联合阶段、自动化阶段。识记阶段不是。"}, {"type": "多选", "num": 27, "text": "关于习惯化，下列说法不正确的是", "options": {"A": "由于刺激重复使有机体对它的反应性增强，即有机体对环境中的某一特定刺激更容易作出反应。", "B": "人的感受能力发生了变化", "C": "感受能力和肌肉能力下降", "D": "由于重复刺激引起的反应性下降，它涉及反应的减少，而不是新反应的习得。"}, "answer": "ABC", "explanation": "习惯化是反应下降不是增强。A描述敏感化，BC不准确。D是习惯化的正确定义。"}, {"type": "多选", "num": 28, "text": "下列属于程序性知识的是", "options": {"A": "礼尚往来", "B": "滴水之恩，当涌泉相报", "C": "以牙还牙", "D": "投桃报李"}, "answer": "ABCD", "explanation": "程序性知识是关于\"如何做\"的知识。这些成语都是关于在特定情境下的行为规则。"}, {"type": "多选", "num": 29, "text": "在影响教师威信形成的客观因素中，最主要的是", "options": {"A": "社会对待教师职业的态度", "B": "教师职业的社会地位", "C": "教育行政机关、学校领导对教师的态度", "D": "学生对教师工作的认识和态度"}, "answer": "AB", "explanation": "教材指出，影响教师威信形成的客观因素很多，但其中最主要的是社会对待教师的态度和教师的社会地位。"}, {"type": "多选", "num": 30, "text": "皮亚杰和柯尔伯格的研究成果，对学校德育有以下启发意义", "options": {"A": "道德判断水平的高低对道德行为选择有重要制约作用。", "B": "道德认识水平的提高与思维水平的提高平行。", "C": "道德认识的发展是循序渐进的", "D": "要以道德伦理说教来达到教育目标"}, "answer": "ABC", "explanation": "启发意义：道德发展循序渐进的、与思维水平平行、判断水平制约行为。D(说教)不是他们的观点。"}, {"type": "多选", "num": 31, "text": "心理发展的特点", "options": {"A": "不平衡性", "B": "普遍性和差异性", "C": "连续性与阶段性", "D": "具有一定的方向性和顺序性"}, "answer": "ABCD", "explanation": "心理发展特点：连续性与阶段性、方向性与顺序性、不平衡性、普遍性与差异性。"}, {"type": "多选", "num": 32, "text": "关于品德和道德，下列说法正确的是", "options": {"A": "道德是一种社会现象，是调整人们相互关系的各种行为规范和准则。", "B": "品德又称道德品质，是道德在个体身上的体现，是个人依据一定的社会道德准则和规范行动时所表现出的稳定的心理特征或倾向。", "C": "道德反映社会生活，它的产生、发展和变化服从于社会的发展规律，属于社会意识的范畴。", "D": "品德支配和调节着个体的道德行为，属于个体意识的范畴。"}, "answer": "ABCD", "explanation": "A(道德是行为规范)、B(品德是道德体现)、C(道德是社会意识)、D(品德是个体意识)均正确。"}, {"type": "多选", "num": 33, "text": "教师的教育机智主要表现在以下哪几个方面", "options": {"A": "善于掌握分寸", "B": "善于对症下药", "C": "善于随机应变", "D": "善于因势利导"}, "answer": "ABCD", "explanation": "教育机智表现：因势利导、随机应变、对症下药、掌握分寸。"}, {"type": "多选", "num": 34, "text": "下列属于品德心理结构的特征的是", "options": {"A": "整体性", "B": "简单性", "C": "复杂性", "D": "敏感性"}, "answer": "AC", "explanation": "品德心理结构特征包括整体性和复杂性。简单性和敏感性不是其特征。"}, {"type": "多选", "num": 35, "text": "下列关于爬山法与手段-目的分析法的说法中，正确的是", "options": {"A": "都属于算法的一种。", "B": "爬山法与手段-目的分析法的不同在于：有时人们为了实现最终目标，不得不采取迂回方式，暂时扩大初始状态与目标状态的差异（暂时“退回去”或“欲进先退”）以有利于问题解决。", "C": "爬山法即采用一定方法，有时是迂回方式，逐步降低初始状态和目标状态的差异以解决问题。", "D": "手段-目的分析指将需要达到的问题的目标状态分析成若干子目标，采用一定手段，消除差异，通过实现一系列子目标最终达到总目标。"}, "answer": "BCD", "explanation": "A错误(属于启发法不是算法)。BCD正确描述了两者的特点。"}, {"type": "多选", "num": 36, "text": "维果茨基的工具论认为，个体的两种工具是", "options": {"A": "身体工具", "B": "意识工具", "C": "精神工具", "D": "物质工具"}, "answer": "CD", "explanation": "维果茨基工具论：物质工具和精神工具（语言符号）。"}, {"type": "多选", "num": 37, "text": "吉尔福特认为，发散思维有以下特点", "options": {"A": "流畅性", "B": "概括性", "C": "变通性", "D": "独特性"}, "answer": "ACD", "explanation": "发散思维特点：流畅性、变通性、独特性。概括性不是发散思维特点。"}, {"type": "多选", "num": 38, "text": "心理健康具有社会性是因为", "options": {"A": "有相当多的人处于介于健康和不健康的状态中，称为“亚健康状态”。", "B": "不同社会心理健康的标准也有不同。", "C": "处于“亚健康状态”的人是心理障碍的易感人群。", "D": "在一个社会中是健康的、可以接受的行为，在另一个社会中就属于不健康、不可接受甚至是犯罪的行为。"}, "answer": "BD", "explanation": "B(不同社会标准不同)、D(不同社会健康标准不同)正确。A和C描述亚健康状态，不是社会性原因。"}, {"type": "多选", "num": 39, "text": "教师反思的具体方法", "options": {"A": "详细描述", "B": "反思日记", "C": "行动研究", "D": "职业发展"}, "answer": "ABCD", "explanation": "教师反思方法：反思日记、详细描述、职业发展、行动研究。"}, {"type": "多选", "num": 40, "text": "下列属于直观动作思维的是", "options": {"A": "4岁前儿童只能在动作中思考问题", "B": "在动手重新布置房间之前，我们会先利用头脑中各种装饰物和家具的形象考虑如何进行摆设，形成多种方案，再选择最佳方案。", "C": "教室的多媒体投影仪坏了，技术人员一边检查相关部件，一边思索损坏原因，最后排除故障。", "D": "聋哑人通过手势交往"}, "answer": "ACD", "explanation": "直观动作思维依靠实际操作。A(幼儿动作思考)、C(技术员动手思考)、D(聋哑人手势)都是。B是具体形象思维。"}, {"type": "多选", "num": 41, "text": "关于科尔伯格道德发展理论，下列说法错误的是", "options": {"A": "后习俗水平这一阶段已经发展到超越现实道德规范的约束，达到完全自律的境界。", "B": "工具性的相对主义定向阶段属于前习俗水平。", "C": "儿童处于前习俗水平这一时期的特征是，个人认识到团体的行为规范，进而接受并付诸实践", "D": "前习俗水平这一时期又分为两个阶段：人际协调的定向阶段和维护权威或秩序的定向阶段"}, "answer": "CD", "explanation": "C错误(前习俗水平特征是自我中心)、D错误(前习俗水平分为惩罚定向和工具性相对主义)。A和B正确。"}, {"type": "多选", "num": 42, "text": "下列属于大学生的心理健康的八大特征是", "options": {"A": "情绪健康", "B": "智力正常", "C": "社会适应良好", "D": "自我意识正确"}, "answer": "ABCD", "explanation": "心理健康特征包括智力正常、情绪健康、自我意识正确、社会适应良好等。"}, {"type": "多选", "num": 43, "text": "下列属于表象的特性的是", "options": {"A": "可操作性", "B": "多通道性", "C": "概括性", "D": "直观性"}, "answer": "ABCD", "explanation": "表象特性：直观性、概括性、可操作性、多通道性。"}, {"type": "多选", "num": 44, "text": "下列属于影响大学生心理健康的个人因素中生理方面是", "options": {"A": "存在不合理的认知方式和信念", "B": "神经系统的先天素质不健全", "C": "自我评价偏差", "D": "遗传因素"}, "answer": "BD", "explanation": "生理因素包括遗传因素和神经系统先天素质。A和C属于认知/心理因素。"}, {"type": "多选", "num": 45, "text": "关于自负，下列说法正确的是", "options": {"A": "自负往往通过语言、行为方式表现出来。", "B": "自负必须建立在客观现实的基础之上。", "C": "脱离实际的自负，不但不能帮助人成就事业，反而影响自己的生活、学习、工作和人际交往，严重的还会影响心理健康。", "D": "对大学生而言，在适当的范围内，自负可以激发他们的斗志，树立必胜的信心，坚定战胜困难的信念，使他们勇往直前。"}, "answer": "ABCD", "explanation": "教材指出，自负往往通过语言、行为方式表现出来；适当范围内的自负可以激发斗志、树立必胜信心；但自负必须建立在客观现实基础之上，脱离实际的自负会影响生活、学习、工作、人际交往乃至心理健康。因此四项均正确。"}, {"type": "多选", "num": 46, "text": "大学生自我意识发展的障碍有", "options": {"A": "自我中心和从众心理", "B": "过分的独立意识和过分的逆反心理", "C": "过度的自我接受与过度的自我拒绝", "D": "过强的自尊心与过重的自卑感"}, "answer": "ABCD", "explanation": "自我意识障碍包括：过度自我接受与拒绝、过强自尊与过重自卑、过分独立与逆反、自我中心与从众。"}, {"type": "多选", "num": 47, "text": "下列属于影响创造性的社会因素的是", "options": {"A": "早期教育", "B": "学校教育", "C": "年龄", "D": "人格"}, "answer": "AB", "explanation": "社会因素：早期教育和学校教育。年龄和人格是个体因素。"}, {"type": "多选", "num": 48, "text": "关于智力，下列说法正确的是", "options": {"A": "衡量大学生的智力是否正常，看他是否有强烈的求知欲和浓厚的探索兴趣，乐于学习，能适应时代的要求，具有创新能力。", "B": "智力的高低等于成绩的高低", "C": "智力正常是大学生学习、生活与工作的基本心理条件，是心理健康的重要标准。", "D": "衡量大学生的智力是否正常，关键在于看其是否正常地、充分地发挥了效能"}, "answer": "ACD", "explanation": "A(智力正常是心理健康标准)、C(基本心理条件)、D(发挥效能为标准)正确。B(智力=成绩)错误。"}, {"type": "多选", "num": 49, "text": "关于学习过程，以下说法正确的是", "options": {"A": "学生的学习活动同科学家探索客观真理的认知活动相同", "B": "学习过程不需要也不可能事事从头实践", "C": "学习过程等同于认知过程", "D": "学习过程必须从头到尾都有实践的参与。"}, "answer": "BC", "explanation": "教材指出，对大学生而言，认知过程也即学习过程；同时，学习过程不需要也不可能事事从头实践。A、D说法过于绝对，B、C正确。"}, {"type": "多选", "num": 50, "text": "班杜拉把观察学习分为以下几个过程：", "options": {"A": "注意过程", "B": "保持过程", "C": "复制过程", "D": "动机过程"}, "answer": "ABCD", "explanation": "班杜拉观察学习四过程：注意、保持、复制和动机。"}, {"type": "多选", "num": 51, "text": "安德森（Anderson，1980）指出，问题解决有以下特征：", "options": {"A": "操作序列", "B": "目标指引", "C": "得出答案", "D": "认知操作"}, "answer": "ABD", "explanation": "问题解决特征：目标指引、认知操作、操作序列。\"得出答案\"是结果不是特征。"}, {"type": "多选", "num": 52, "text": "下列关于陈述性知识，说法正确的是", "options": {"A": "陈述性知识是人的长时记忆中的重要内容。", "B": "大部分陈述性知识都能够用语言来表述。", "C": "它是关于人怎样解决问题、如何去做某事的知识。", "D": "能被人用语言来陈述和描述，是有关人所知道的事物状况的知识。"}, "answer": "ABD", "explanation": "陈述性知识是\"是什么\"的知识，能用语言陈述，是长时记忆的重要内容。C描述的是程序性知识。"}, {"type": "多选", "num": 53, "text": "道德情感形成的形式包括", "options": {"A": "意识到道德伦理的情绪体验", "B": "与具体的道德形象相联系的情绪体验", "C": "直觉的道德感", "D": "工具性的相对主义"}, "answer": "ABC", "explanation": "道德情感形式：直觉的道德感、与具体道德形象联系的情绪体验、意识到道德伦理的情绪体验。\"工具性的相对主义\"是道德发展阶段概念。"}, {"type": "多选", "num": 54, "text": "精神分析大师弗洛伊德提出了", "options": {"A": "本我", "B": "超我", "C": "自我", "D": "他人"}, "answer": "ABC", "explanation": "弗洛伊德人格结构：本我、自我、超我。"}, {"type": "多选", "num": 55, "text": "教师职业角色压力主要来源于", "options": {"A": "角色超载", "B": "角色冲突", "C": "角色不清", "D": "角色混乱"}, "answer": "AB", "explanation": "教材明确指出，教师职业角色压力主要来源于角色冲突和角色超载。"}, {"type": "多选", "num": 56, "text": "下列属于影响创造性的个体因素的是", "options": {"A": "人格", "B": "年龄", "C": "学校教育", "D": "早期教育"}, "answer": "AB", "explanation": "个体因素包括人格和年龄。学校教育和早期教育是社会/环境因素。"}, {"type": "多选", "num": 57, "text": "美国教育心理学索里和特尔福德认为，教师应担负如下哪几种角色", "options": {"A": "家长的代理人", "B": "知识的传授者", "C": "团体的领导", "D": "模范公民"}, "answer": "ABCD", "explanation": "教师应担负角色：家长代理人、知识传授者、团体领导、模范公民。"}, {"type": "多选", "num": 58, "text": "关于程序性知识，下列说法正确的是", "options": {"A": "大部分程序性知识都能够用语言来表述。", "B": "能被人用语言来陈述和描述，是有关人所知道的事物状况的知识。", "C": "程序性知识既可能涉及人们要完成一项任务所需要的运动技能，也可能涉及在一定条件下使用科学原理的认知技能。", "D": "它是关于人怎样解决问题、如何去做某事的知识."}, "answer": "CD", "explanation": "C(涉及运动技能和认知技能)、D(关于如何做)正确。A(程序性知识难用语言表述)、B(能用语言陈述的是陈述性知识)。"}, {"type": "多选", "num": 59, "text": "影响遗忘的因素", "options": {"A": "识记材料的性质和数量", "B": "学习程度", "C": "识记材料的系列位置", "D": "时间因素"}, "answer": "ABCD", "explanation": "影响遗忘的因素：识记材料的性质和数量、学习程度、识记材料的系列位置、时间因素（遗忘曲线）。"}, {"type": "多选", "num": 60, "text": "下列属于创造性的特点是", "options": {"A": "新颖性", "B": "概括性", "C": "独特性", "D": "社会价值或个人价值"}, "answer": "ACD", "explanation": "创造性特点：新颖性、独特性、社会价值。概括性不是创造性特有特点。"}, {"type": "多选", "num": 61, "text": "关于心理健康的理解，下列说法正确的是", "options": {"A": "心理健康是相对的", "B": "心理健康是一种心理上和行为上的良好状态，是个人所能达到的最佳状态。", "C": "心理健康的人能保持镇静的情绪、坚强的性格、较高的智能、适度的社会适应行为和愉快和谐的情绪。", "D": "心理健康具有动态性"}, "answer": "ABCD", "explanation": "A(相对性)、B(良好状态)、C(保持镇静等)、D(动态性)均正确。"}, {"type": "多选", "num": 62, "text": "关于品德的四种心理成分，下列说法正确的是", "options": {"A": "它们的发展有阶段性，且可以单独地割裂开来。", "B": "道德认识是品德的思想基础，是道德情感产生的依据。", "C": "道德认识是品德一个循环中的终末环节，也是更高循环中的依据和基础。", "D": "在品德的心理结构中，哪种成分是核心，占主导和支配地位，取决于主体与情境、事件的性质及完成事情的难易程度。"}, "answer": "BD", "explanation": "B(认识是思想基础)、D(核心取决于情境)正确。A(不能割裂)、C(行为是终末环节)错误。"}, {"type": "多选", "num": 63, "text": "心理健康具有相对性表现在", "options": {"A": "心理健康不具有动态性", "B": "心理健康与不健康没有绝对的分界", "C": "不同地区社会心理健康有统一标准", "D": "心理健康具有社会性"}, "answer": "BD", "explanation": "心理健康相对性表现：健康与不健康无绝对分界(B)；具有社会性(D)。A(不具有动态性)错误。C(统一标准)错误。"}, {"type": "多选", "num": 64, "text": "以下属于影响知识理解的因素有", "options": {"A": "概念的关键特征。", "B": "学习态度。", "C": "材料的感性程度以及与经验的相关程度。", "D": "新旧知识间的联系。"}, "answer": "ABCD", "explanation": "教材指出，影响知识理解的因素包括概念的关键特征、学习态度、材料的感性程度及其与经验的相关程度、新旧知识间的联系，四项均正确。"}, {"type": "多选", "num": 65, "text": "关于发散思维的独特性，下列说法正确的是", "options": {"A": "表现为发散的“新异”、“独到”。", "B": "指思考方式变化多端，思维产品的种类不拘一格，能举一反三，触类旁通，随机应变，思维不受定势束缚，能产生多种多样的新观点。", "C": "指对问题提出超乎寻常的、新颖的、独特的见解，即以前所未有的新观点、新角度去反映事物。", "D": "它最能代表发散思维的本质，是最高层次的发散特征。"}, "answer": "ACD", "explanation": "独特性表现为新颖独特见解，是最高层特征。B描述的是变通性。"}, {"type": "多选", "num": 66, "text": "大学生心理健康的自我维护方法有", "options": {"A": "用积极心态对待外界事物，创造一个良好和谐的外部环境", "B": "建立正确的自我认识，形成积极的自我概念", "C": "正确看待压力", "D": "坚持健康文明的生活方式"}, "answer": "ABCD", "explanation": "自我维护方法：正确认识自我、正确看待压力、健康生活方式、积极心态对待外界。"}, {"type": "多选", "num": 67, "text": "柯尔伯格把儿童的道德判断分为以下水平", "options": {"A": "习俗水平", "B": "后习俗水平", "C": "自我中心水平", "D": "前习俗水平"}, "answer": "ABD", "explanation": "柯尔伯格道德判断三水平：前习俗水平、习俗水平和后习俗水平。没有\"自我中心水平\"。"}, {"type": "多选", "num": 68, "text": "麦克因泰等人认为，教师在教学活动中扮演什么样的角色", "options": {"A": "组织者的角色", "B": "交流者的角色", "C": "激发者的角色", "D": "管理者的角色"}, "answer": "ABCD", "explanation": "麦金太尔认为教师扮演组织者、交流者、激发者和管理者。"}, {"type": "多选", "num": 69, "text": "高等教育心理学有如下任务", "options": {"A": "描述高校教师和学生的心理现象", "B": "揭示高校教师和学生的心理规律", "C": "预测高校教师和学生的行为", "D": "为高等教育实践提供指导"}, "answer": "ABCD", "explanation": "高等教育心理学任务：描述现象、揭示规律、预测行为、提供指导。"}, {"type": "多选", "num": 70, "text": "促进知识迁移的条件有", "options": {"A": "定势的作用", "B": "知识经验的概括水平", "C": "对材料的理解程度", "D": "学习材料之间的共同因素"}, "answer": "ABCD", "explanation": "促进迁移条件：共同因素、理解程度、概括水平、定势作用。"}, {"type": "多选", "num": 71, "text": "对学习对象的理解分别有三个不同水平：", "options": {"A": "一般水平的理解", "B": "初级水平的理解", "C": "中级水平的理解", "D": "高级水平的理解"}, "answer": "BCD", "explanation": "教材指出，对学习对象的理解分别属于初级水平、中级水平和高级水平三种，不包括一般水平。"}, {"type": "多选", "num": 72, "text": "下列关于大学生的认知特征，说法正确的是", "options": {"A": "思维发展处于成熟期", "B": "创造力发展处于最佳期", "C": "智力发展达到最佳水平", "D": "记忆能力发展达到黄金期"}, "answer": "ABCD", "explanation": "认知特征：智力最佳水平、思维成熟期、创造力最佳期、记忆黄金期。"}, {"type": "多选", "num": 73, "text": "弗勒和布朗根据教师的需要和不同时期关注的焦点，把教师成长划分为哪三个阶段", "options": {"A": "关注生存阶段", "B": "关注情境阶段", "C": "关注学生阶段", "D": "关注教学阶段"}, "answer": "ABC", "explanation": "教师成长三阶段：关注生存、关注情境、关注学生。"}, {"type": "多选", "num": 74, "text": "赫尔巴特认为，学习过程可以分为以下阶段：", "options": {"A": "感觉阶段", "B": "记忆阶段", "C": "理解阶段", "D": "遗忘阶段"}, "answer": "ABC", "explanation": "赫尔巴特学习阶段：感觉、记忆、理解。遗忘阶段不是。"}, {"type": "多选", "num": 75, "text": "下列属于斯金纳的“学习公律”是", "options": {"A": "准备律", "B": "消退率", "C": "练习律", "D": "效果律"}, "answer": "ACD", "explanation": "教材指出，桑代克的学习公律包括准备律、练习律和效果律。消退率属于强化程式或行为消退相关概念，不属于桑代克的学习公律。另外，本题题干有误，应为「下列属于桑代克的“学习公律”是」"}, {"type": "多选", "num": 76, "text": "大学生的心理问题分为以下几个层次", "options": {"A": "心理障碍", "B": "心理疾病", "C": "心理冲突", "D": "心理变态"}, "answer": "ABC", "explanation": "心理问题三层次：心理冲突、心理障碍、心理疾病。心理变态不是标准分类。"}, {"type": "多选", "num": 77, "text": "根据思维任务的性质和解决问题的方式，可以将思维分为", "options": {"A": "抽象逻辑思维", "B": "分析思维", "C": "直观动作思维", "D": "具体形象思维"}, "answer": "ACD", "explanation": "思维按任务性质分：直观动作思维、具体形象思维、抽象逻辑思维。分析思维是按逻辑划分。"}, {"type": "多选", "num": 78, "text": "高等教育心理学对大学生个体心理的研究主要集中", "options": {"A": "社交心理", "B": "品德和人格心理", "C": "知识获得的心理", "D": "学习心理"}, "answer": "BCD", "explanation": "高等教育心理学主要研究学习心理、知识获得的心理、品德和人格心理。社交心理不是主要集中领域。"}, {"type": "多选", "num": 79, "text": "关于品德和道德，下列说法正确的是", "options": {"A": "道德是一种社会现象，是调整人们相互关系的各种行为规范和准则。", "B": "品德又称道德品质，是道德在个体身上的体现，是个人依据一定的社会道德准则和规范行动时所表现出的稳定的心理特征或倾向。", "C": "品德反映社会生活，它的产生、发展和变化服从于社会的发展规律，属于社会意识的范畴。", "D": "道德支配和调节着个体的道德行为，属于个体意识的范畴。"}, "answer": "AB", "explanation": "A(道德是社会现象)、B(品德是道德在个体身上的体现)正确。C(品德属个体意识)、D(道德不属个体意识)错误。"}, {"type": "多选", "num": 80, "text": "高校教师的角色冲突表现在哪几个方面", "options": {"A": "在师生关系上，表现为“教育者”与“服务者”冲突", "B": "在教师与高校行政管理部门的关系上，表现为“被服务者”与“被管理者”的冲突", "C": "在教师与社会的关系上，体现为“引领者”与“被动适应者”的冲突", "D": "在职业理想方面，存在着“志业”和“谋生”的冲突"}, "answer": "ABCD", "explanation": "角色冲突四方面：师生关系、与行政部门关系、与社会关系、职业理想方面。"}, {"type": "多选", "num": 81, "text": "下列关于价值观的说法正确的是", "options": {"A": "如果一个人不追求对社会贡献，只追求个人需要满足，把社会价值和个人价值对立起来，就不可能实现个人的自我价值", "B": "是个人对于人生目的和意义的根本看法和态度，是一定的世界观在人生问题上的反映", "C": "人的价值包括社会价值和自我价值", "D": "价值观是人们以自身需要为尺度对事物重要性认识的观念系统"}, "answer": "ACD", "explanation": "A(个人价值与社会价值统一)、C(价值包括社会价值和自我价值)、D(价值观的定义)正确。B是人生观的定义。"}, {"type": "多选", "num": 82, "text": "关于抽象与概括，下列说法正确的是", "options": {"A": "抽象是概括的前提，没有抽象就无从概括。", "B": "只有通过抽象与概括，才能逐步把握事物的本质与规律。", "C": "抽象与概括相互依存、相辅相成。", "D": "概括是抽象的发展。"}, "answer": "ABCD", "explanation": "A(抽象是前提)、B(把握本质)、C(相互依存)、D(概括是发展)均正确。"}, {"type": "多选", "num": 83, "text": "下列不属于一级强化物的是", "options": {"A": "安全", "B": "钱", "C": "娱乐", "D": "食物"}, "answer": "BC", "explanation": "一级强化物通常指能直接满足基本需要、无需学习即可起强化作用的刺激。钱和娱乐更多属于习得性或二级强化物，因此“不属于一级强化物”的是B、C。"}, {"type": "多选", "num": 84, "text": "关于逆向搜索和手段-目的分析法，下列说法错误的是", "options": {"A": "两者搜索方向相同", "B": "当从初始状态出发有多种途径能够到达目标状态时，采用手段-目的分析较好", "C": "当从初始状态出发可以引出许多途径却只有很少途径能够到达目标状态时，则采用逆向搜索较有效。", "D": "适用范围无差异"}, "answer": "AD", "explanation": "A错误(搜索方向不同)，D错误(适用范围有差异)。B和C正确。"}, {"type": "多选", "num": 85, "text": "下列属于思维的特征是", "options": {"A": "问题性", "B": "创造性", "C": "概括性", "D": "间接性"}, "answer": "ABCD", "explanation": "教材将思维的特征概括为概括性、间接性、问题性和创造性，四项均属于思维特征。"}, {"type": "多选", "num": 86, "text": "关于品德和道德，下列说法正确的是", "options": {"A": "道德的形成与发展受社会发展规律制约，有明显的社会历史性。", "B": "品德的形成与发展不仅受社会制约，而且受个体的心理制约。", "C": "从反映内容上看，道德反映的内容比品德反映的内容要广阔得多，概括得多。", "D": "品德的内容则是社会道德规范局部的具体体现，是社会道德要求的部分反映。"}, "answer": "ABCD", "explanation": "A(道德受社会规律制约)、B(品德受双重制约)、C(道德内容更广阔)、D(品德是社会道德部分反映)均正确。"}, {"type": "多选", "num": 87, "text": "下列属于直觉思维起主要作用的是", "options": {"A": "3岁前儿童只能在动作中思考问题", "B": "魏格纳在看地图时突然闪现出“大陆漂移”的观念", "C": "牛顿被落下的苹果砸中后突然产生了“万有引力”的想法", "D": "聋哑人通过手势交往"}, "answer": "BC", "explanation": "直觉思维是未经分析直接判断。B(魏格纳)和C(牛顿)是直觉思维。AD是直观动作思维。"}, {"type": "多选", "num": 88, "text": "关于皮亚杰提出的儿童道德发展阶段，下列说法错误的是", "options": {"A": "自律阶段的儿童已经不把规则看成是不可改变的，而是把它看作是同伴之间的共同约定，是可以改变的。", "B": "他律阶段的儿童对外在权威表现出绝对尊敬和顺从的愿望。", "C": "处在公正阶段的孩子，他们认为，服从、听话就是好孩子，否则就是坏孩子。", "D": "处在权威阶段的儿童，他们的公正观念或正义感是在可逆的道德观念上发展起来。"}, "answer": "CD", "explanation": "C错误(公正阶段不认为听话就好)、D错误(权威阶段不是可逆道德基础)。AB正确。"}, {"type": "多选", "num": 89, "text": "下列属于遗忘理论的是", "options": {"A": "提取失败说", "B": "同化说", "C": "模块说", "D": "衰退说"}, "answer": "ABD", "explanation": "遗忘理论包括衰退说、干扰说、提取失败说、同化说。\"模块说\"是记忆存储模型。"}, {"type": "多选", "num": 90, "text": "道德情感体验的获得对品德的形成和发展作用十分重要，主要表现在以下几个方面：", "options": {"A": "移情是由道德认知引发道德行为的中介变量", "B": "道德情感引发与支持道德行为", "C": "道德情感深化道德认识", "D": "道德情感是道德品质结构中的重要成分"}, "answer": "ABCD", "explanation": "道德情感的作用：是道德品质的重要成分、深化道德认识、引发支持道德行为、移情是中介变量。"}, {"type": "多选", "num": 91, "text": "关于品德的四种心理成分，下列说法错误的是", "options": {"A": "道德行为是品德一个循环中的终末环节，也是更高循环中的依据和基础。", "B": "它们的发展有阶段性，且可以单独地割裂开来。", "C": "它们分别是道德认识、道德情感、道德意志、道德信念", "D": "道德情感是品德的思想基础，是道德认识产生的依据。"}, "answer": "BCD", "explanation": "A正确(道德行为是终末环节也是更高依据)。B错误(不能割裂)。C错误(应是道德行为，不是信念)。D错误(道德认识是思想基础)。"}, {"type": "多选", "num": 92, "text": "影响程序性知识形成的因素是：", "options": {"A": "足够的练习", "B": "合并小程序，形成大程序", "C": "技能或前提技能的自动化", "D": "完整的陈述性知识"}, "answer": "ABCD", "explanation": "影响程序性知识形成的因素：完整的陈述性知识、前提技能自动化、合并小程序为大程序、足够练习。"}, {"type": "多选", "num": 93, "text": "品德心理结构的特征有", "options": {"A": "历时性与共时性", "B": "稳定性与可变性", "C": "复杂性", "D": "整体性"}, "answer": "ABCD", "explanation": "品德心理结构特征：整体性、复杂性、稳定性与可变性、历时性与共时性。"}, {"type": "多选", "num": 94, "text": "一般说来，创造思维有以下特征", "options": {"A": "具有重要的社会价值", "B": "新颖性", "C": "敏锐性", "D": "首创性"}, "answer": "ABCD", "explanation": "创造思维特征：新颖性、首创性、敏锐性和社会价值。"}, {"type": "多选", "num": 95, "text": "品德的心理成分", "options": {"A": "道德意志", "B": "道德行为", "C": "道德认识", "D": "道德情感"}, "answer": "ABCD", "explanation": "品德四成分：道德认识、道德情感、道德意志、道德行为。"}, {"type": "多选", "num": 96, "text": "我国学者认为，问题解决包括", "options": {"A": "分析问题", "B": "发现问题", "C": "验证假设", "D": "提出假设"}, "answer": "ABCD", "explanation": "问题解决四阶段：发现问题、分析问题、提出假设、验证假设。"}, {"type": "多选", "num": 97, "text": "教师扮演的角色对学生而言有不同作用，这些作用可以按感情因素排列，其中起消极作用的有", "options": {"A": "侦探和纪律执行者", "B": "替罪羊", "C": "心理咨询和治疗学家", "D": "家长的代理人"}, "answer": "AB", "explanation": "教师角色中起消极作用的是侦探和纪律执行者、替罪羊。"}, {"type": "多选", "num": 98, "text": "大学生心理健康的自我维护方法有", "options": {"A": "对青春期和性成熟状态的良好适应", "B": "建立正确的自我认识，形成积极的自我概念", "C": "合理宣泄情绪", "D": "坚持健康文明的生活方式"}, "answer": "ABCD", "explanation": "教材“大学生心理健康的自我维护”包括树立正确的自我认识、坚持健康文明的生活方式、合理宣泄情绪、对青春期和性成熟状态的良好适应等内容，四项均正确。"}, {"type": "多选", "num": 99, "text": "教师扮演的角色对学生而言有不同作用，这些作用可以按感情因素排列，其中起权威者作用的", "options": {"A": "家长的代理人", "B": "知识的传授者", "C": "团体的领导", "D": "模范公民"}, "answer": "ABCD", "explanation": "起权威作用的角色：家长代理人、知识传授者、团体领导、模范公民。"}, {"type": "多选", "num": 100, "text": "教师反思的阶段", "options": {"A": "具体经验阶段", "B": "观察分析阶段", "C": "重新概括阶段", "D": "积极的验证阶段"}, "answer": "ABCD", "explanation": "反思阶段：具体经验、观察分析、重新概括、积极验证。"}, {"type": "多选", "num": 101, "text": "下列属于知识的正迁移的是", "options": {"A": "一种学习使另一学习所需时间或所需练习次增加", "B": "一种学习使另一学习具有了良好的心理准备状态", "C": "已经具有的知识经验使学习者顺利地解决了面临的问题", "D": "一种学习使另一学习活动所需时间或练习次数减少"}, "answer": "BCD", "explanation": "正迁移是积极促进的迁移。A(增加时间/次数)是负迁移。B(良好心理准备)、C(顺利解决问题)、D(减少时间/次数)都是正迁移。"}, {"type": "多选", "num": 102, "text": "教师扮演的角色对学生而言有不同作用，这些作用可以按感情因素排列，其中起支持作用的有", "options": {"A": "心理咨询和治疗学家", "B": "学生的朋友和知己", "C": "知识的传授者", "D": "团体的领导"}, "answer": "AB", "explanation": "起支持作用的角色：心理咨询和治疗学家、学生的朋友和知己。"}, {"type": "多选", "num": 103, "text": "心理健康与大学生关系重大，它的作用包括", "options": {"A": "促进大学生独立发展", "B": "促进大学生全面发展", "C": "促进大学生个性完善", "D": "促进大学生取得成功"}, "answer": "ABCD", "explanation": "教材指出，心理健康对大学生具有重要作用，包括促进全面发展、促进独立发展、促进个性完善，也有助于大学生取得成功。"}, {"type": "多选", "num": 104, "text": "借助于思维的间接性，人们可以通过已知来推断未知，主要表现为：", "options": {"A": "它使人的认识能力突破了时空的限制。", "B": "它使人能够超越感官的局限来认识事物、揭露事物的本质和规律", "C": "反映事物之间的关系", "D": "反映事物的本质属性或一类事物的共同特征"}, "answer": "AB", "explanation": "间接性表现：突破时空限制、超越感官局限。CD是概括性的表现。"}, {"type": "多选", "num": 105, "text": "大学生的学习动机主要有", "options": {"A": "谋求职业和满足生活的动机", "B": "事业成就的动机", "C": "报答性和附属的学习动机", "D": "自我实现和自我提高的动机"}, "answer": "ABCD", "explanation": "大学习动机包括：报答性和附属动机、自我实现动机、事业成就动机、谋求职业动机。"}, {"type": "多选", "num": 106, "text": "关于学习，以下说法正确的是", "options": {"A": "学习只存在于人类的活动中，动物不存在学习。", "B": "学习的发生以行为和行为潜能的改变为标志。", "C": "动物和人类都可以进行学习。", "D": "心理学中的学习是指个体在生活中由于经验而产生的行为或行为潜能的比较持久的变化。"}, "answer": "BCD", "explanation": "B(行为改变标志)、C(动物也可学习)、D(学习定义)正确。A(只有人类学习)错误。"}, {"type": "多选", "num": 107, "text": "关于逆向搜索和手段-目的分析法，下列说法正确的是", "options": {"A": "两者搜索方向相同", "B": "当从初始状态出发有多种途径能够到达目标状态时，采用手段-目的分析较好", "C": "当从初始状态出发可以引出许多途径却只有很少途径能够到达目标状态时，则采用逆向搜索较有效。", "D": "适用范围无差异"}, "answer": "BC", "explanation": "B(多种途径时手段-目的分析好)、C(少数途径时逆向搜索有效)正确。A(方向不同)、D(范围有差异)错误。"}, {"type": "多选", "num": 108, "text": "下列说法正确的是", "options": {"A": "道德技能的掌握有助于实现道德目的，它将指导人做出对他人和社会具有道德意义的事情。", "B": "道德意志的作用就在于发动与既定目的相符的行动，制止与既定目的相悖的行动。", "C": "道德信念的形成和道德评价能力的完善是衡量大学生道德认识成熟的主要标志。", "D": "道德认识的形成是品德形成的客观标志。"}, "answer": "ABC", "explanation": "A(道德技能助实现道德目的)、B(道德意志发动阻止)、C(信念评价是成熟标志)正确。D(行为是客观标志，不是认识)。"}, {"type": "多选", "num": 109, "text": "大学生常见的心理冲突有", "options": {"A": "适应心理问题", "B": "性生理成熟与性心理相对幼稚的心理冲突", "C": "交往与闭锁的心理冲突", "D": "理想化和现实感的心理冲突"}, "answer": "BCD", "explanation": "心理冲突：理想化与现实感、交往与闭锁、性成熟与性心理幼稚。适应心理问题不是心理冲突类型。"}, {"type": "判断", "num": 1, "text": "专家型教师与新手在课堂教学中存在的差异有：课时计划的差异、课堂过程的差异和课后评价的差异", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "专家型教师与新手在课时计划、课堂过程和课后评价存在差异。"}, {"type": "判断", "num": 2, "text": "人格不具有跨时间反应的稳定性和跨情境行为的一致性", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "人格具有跨时间稳定性和跨情境一致性。"}, {"type": "判断", "num": 3, "text": "就业指导的主要任务是帮助大学生了解自己、了解职业，帮助大学生找到适合个性特点的工作岗位并适应职业生活。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "就业指导帮助大学生了解自己和职业。"}, {"type": "判断", "num": 4, "text": "挫折与攻击之间有必然的因果联系", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "挫折与攻击之间没有必然的因果联系。"}, {"type": "判断", "num": 5, "text": "集体规范的作用都是积极的", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "集体规范的作用不总是积极的，也可能有消极作用。"}, {"type": "判断", "num": 6, "text": "德国心理学家斯普兰格根据社会文化生活方式将人的价值观分为经济型、理论型、审美型、社会型、政治型和宗教型。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "斯普兰格将价值观分为六种类型。"}, {"type": "判断", "num": 7, "text": "应付挫折的方法有：正确对待挫折；改变情境；适当的精神发泄和开展心理咨询工作", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "应付挫折的方法包括正确对待、改变情境、精神发泄和心理咨询。"}, {"type": "判断", "num": 8, "text": "所有教学都是有意义和有价值的", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "并非所有教学都是有意义和价值的。"}, {"type": "判断", "num": 9, "text": "智力成分子理论是智力三元论的核心。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "智力成分亚理论是智力三元论的核心。"}, {"type": "判断", "num": 10, "text": "“滴水之恩，当涌泉相报”属于陈述性知识。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "滴水之恩当涌泉相报属于程序性知识，不是陈述性知识。"}, {"type": "判断", "num": 11, "text": "心理学中的学习是指个体在生活中由于经验而产生的行为或行为潜能的比较持久的变化。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "心理学中学习的定义。"}, {"type": "判断", "num": 12, "text": "就业观念指导是就业指导的重要内容，主要是对大学生进行思想教育，引导学生正确认识自我、认识职业，科学合理地选定求职目标。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "就业观念指导是就业指导的重要内容。"}, {"type": "判断", "num": 13, "text": "定势对知识迁移的作用总是积极的。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "定势对迁移有积极和消极两方面的作用。"}, {"type": "判断", "num": 14, "text": "普通教育的对象是各年龄段的人，而高等教育的对象是大学生和研究生", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "高等教育的对象是大学生和研究生，但普通教育对象主要是青少年。"}, {"type": "判断", "num": 15, "text": "奥苏泊尔认为，学校情景中的成就动机至少包括三方面的动机成分，分别是认知的内驱力、自我提高的内驱力和附属的内驱力", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "奥苏伯尔认为成就动机包括认知内驱力、自我提高内驱力和附属内驱力。"}, {"type": "判断", "num": 16, "text": "让学生体验到经过自身努力获取成功，是推动学生不断进取的关键因素。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "让学生体验自身努力获取成功是推动进取的关键。"}, {"type": "判断", "num": 17, "text": "有效教学有利于提高教师的教学技能和专业水平", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "有效教学有利于提高教师教学技能和专业水平。"}, {"type": "判断", "num": 18, "text": "亚当斯认为当一个人感到他所获得报酬的结果与投入的比值和作为比较对象的这个比值相等时，就有了公平感觉", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "亚当斯公平理论认为人们比较投入产出比来判断公平。"}, {"type": "判断", "num": 19, "text": "焦虑是具有进化意义的情绪，它能促使人鼓起力量去应付即将发生的危机。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "焦虑具有进化意义，能促使人应对危机。"}, {"type": "判断", "num": 20, "text": "人格的发展受童年经验影响。幸福的童年有利于儿童向健康人格发展，不幸的儿童也会引发不良人格的形成，二者存在一一对应的关系", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "童年经验与人格发展不是一一对应关系。"}, {"type": "判断", "num": 21, "text": "陈述性知识在人的头脑中是以“产生式”的形式表征的；而程序性知识是以命题、表象、图示和线性排序的方式表征的。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "陈述性知识以命题、表象、图式、线性排序表征；程序性知识以产生式表征。题干说反了。"}, {"type": "判断", "num": 22, "text": "教师给学生的第一印象对教师威信的获得有较大影响", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "第一印象对教师威信获得有较大影响。"}, {"type": "判断", "num": 23, "text": "就业指导的总目标是协助大学生做出职业选择，解决就业问题。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "就业指导总目标是协助学生做出职业选择解决就业问题。"}, {"type": "判断", "num": 24, "text": "人格形成与发展的影响因素有生物遗传因素、社会文化因素、家庭环境因素、早期童年经验、学校教育因素和自然物理因素", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人格影响因素包括生物遗传、社会文化、家庭环境、童年经验、学校教育和自然物理因素。"}, {"type": "判断", "num": 25, "text": "有效教学有利于全面落实素质教育的要求", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "有效教学有利于落实素质教育。"}, {"type": "判断", "num": 26, "text": "事物的外形、颜色、所能发出的声音特征、乃至闻起来或吃起来的味道都是属于形象记忆。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "事物的外形颜色声音味道等属于形象记忆。"}, {"type": "判断", "num": 27, "text": "气质与性格都是人的个性心理特征，二者既有联系又有区别，相互影响，彼此制约", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "气质与性格既有联系又有区别。"}, {"type": "判断", "num": 28, "text": "教学反思有助于营造浓厚的教学研究氛围", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教学反思有助于营造教学研究氛围。"}, {"type": "判断", "num": 29, "text": "我国学者认为，问题解决包括发现问题、分析问题、提出假设和验证假设四个相互联系的阶段。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "问题解决四阶段：发现问题、分析问题、提出假设、验证假设。"}, {"type": "判断", "num": 30, "text": "价值观是个人对于人生目的和意义的根本看法和态度，是一定的世界观在人生问题上的反映。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "题干是人生观的定义，不是价值观的定义。"}, {"type": "判断", "num": 31, "text": "多进行测验比没有测验更能促进学生学习，但测验也不易过多、过滥。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "适当测验促进学习但不宜过多过滥。"}, {"type": "判断", "num": 32, "text": "挫折行为的表现特征主要有攻击、退化和妥协。这些表现通常以综合的形式出现。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "挫折行为表现有攻击、退化和妥协。"}, {"type": "判断", "num": 33, "text": "思维是人脑借助言语、表象或动作实现的、对客观事物的性质及关系的概括的和间接的反映。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "思维的定义（间接性和概括性的反映）。"}, {"type": "判断", "num": 34, "text": "定势对知识迁移的作用总是消极的。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "定势对迁移的作用既有积极也有消极。"}, {"type": "判断", "num": 35, "text": "根据班集体的形成和发展水平，可以将班集体分为简单聚合型、一般型和成熟型", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "班集体分为简单聚合型、一般型和成熟型。"}, {"type": "判断", "num": 36, "text": "通过概括，反映事物的本质属性或一类事物的共同特征和事物之间的关系。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "概括能反映事物的本质属性和关系。"}, {"type": "判断", "num": 37, "text": "就业指导是高校的一项重要工作。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "就业指导是高校工作的重要组成部分。"}, {"type": "判断", "num": 38, "text": "皮亚杰提出了人格发展的八阶段论", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "人格发展八阶段论是埃里克森提出的，不是皮亚杰。"}, {"type": "判断", "num": 39, "text": "模块论认为大脑的不同部分与不同智力有关。所以，智力研究的一个重要任务就是分离负责不同智力的脑区。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "模块论认为大脑不同部分与不同智力有关。"}, {"type": "判断", "num": 40, "text": "教师的教育机智主要表现在以下四个方面：善于因势利导、善于随机应变、善于对症下药和善于掌握分寸", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师教育机智的四个方面。"}, {"type": "判断", "num": 41, "text": "成语“耳濡目染”指的就是无意记忆起作用。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "耳濡目染指无意记忆。"}, {"type": "判断", "num": 42, "text": "斯金纳进行了婴儿的恐惧形成实验。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "进行婴儿恐惧形成实验的是华生（小阿尔伯特实验），不是斯金纳。"}, {"type": "判断", "num": 43, "text": "大学生就业政策是国家制定的高层次人力资源配置准则的体现，是调控、约束、导向毕业生择业行为的基本依据。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学生就业政策是人力资源配置准则的体现。"}, {"type": "判断", "num": 44, "text": "教师扮演的角色对学生而言有不同作用，这些作用可以按感情因素排列，其中起支持作用的有心理咨询和治疗学家与学生的朋友和知己", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "心理咨询学家和朋友知己起支持作用。"}, {"type": "判断", "num": 45, "text": "卡特尔认为流体智力随着生理的成长而变化，随着机体的衰老而减退。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "卡特尔认为流体智力随生理成长变化，随衰老减退。"}, {"type": "判断", "num": 46, "text": "个体的人格是在遗传、成熟、环境、教育等因素的交互作用下形成的，不同的遗传因素及教育环境，形成了各自独特的心理特点", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人格在遗传、成熟、环境、教育等因素交互作用下形成。"}, {"type": "判断", "num": 47, "text": "人际交往的基本原则有交互性原则、自我价值保护原则和情境控制原则", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人际交往基本原则包括交互性、自我价值保护和情境控制。"}, {"type": "判断", "num": 48, "text": "“一朝被蛇咬，十年怕井绳”，“十个电工，九个兔子胆”，都属于敏感化。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "一朝被蛇咬十年怕井绳和十个电工九个兔子胆都属于敏感化（反应增强）。"}, {"type": "判断", "num": 49, "text": "皮尔斯认为认为，一个心理健康的人应该是充分地理解并坚定地立足于自己的“此时此地”的人，那些念念不忘过去，或对未来想入非非的人，通常表现出人格的不平衡。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "皮尔斯强调\"此时此地\"的重要性。"}, {"type": "判断", "num": 50, "text": "有效的教学有利于学生提高学习效率和学习能力", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "有效教学有利于学生提高学习效率和学习能力。"}, {"type": "判断", "num": 51, "text": "人格的基本特征包括：独特性、稳定性、整体性、社会性和功能性", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人格的基本特征：独特性、稳定性、整体性、社会性和功能性。"}, {"type": "判断", "num": 52, "text": "动机强度与工作效率之间的关系不是一种线性关系，而是倒U形曲线关系。中等强度的动机最有利于任务完成", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "动机强度与工作效率呈倒U形曲线关系。"}, {"type": "判断", "num": 53, "text": "“因材施教”是一条重要的教学原则，其依据就是学生的个别差异", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "因材施教依据学生的个别差异。"}, {"type": "判断", "num": 54, "text": "目前，自学能力已经成为衡量大学生学业拓展能力的重要指标。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "自学能力是衡量大学生学业拓展能力的重要指标。"}, {"type": "判断", "num": 55, "text": "从教师的职业要求来看，成熟的教师应具备以下的人格特征：成熟的自我意识、崇高的品德和正确的人生观、有职业特色的需要、兴趣和价值观、富有创新精神和良好的性格", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "成熟教师应具备这些人格特征。"}, {"type": "判断", "num": 56, "text": "社会榜样促进学习和动机的产生", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "社会榜样促进学习和动机。"}, {"type": "判断", "num": 57, "text": "教学反思有助于促进学生学习", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教学反思有助于促进学生学习。"}, {"type": "判断", "num": 58, "text": "“堕胎”这一行为在中国和在美国就有不同的含义，这表明不同社会心理健康的标准也有不同。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "堕胎在不同国家含义不同，表明心理健康标准的社会差异。"}, {"type": "判断", "num": 59, "text": "培养大学生健全人格的途径与措施包括：认识自我，优化人格整合；学会自我教育；增强挫折耐受力；养成良好习惯；建立和谐的人际关系以及加强文化修养", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "培养健全人格的途径和措施。"}, {"type": "判断", "num": 60, "text": "“医生虽然不能直接看到病毒对人体的侵袭，但根据对病人的各项检查结果和已有经验，就能诊断病情”这句话描述的是思维的创造性。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "医生根据检查结果诊断病情，描述的是思维的间接性，不是创造性。"}, {"type": "判断", "num": 61, "text": "习惯化由于刺激重复使有机体对它的反应性增强，即有机体对环境中的某一特定刺激更容易作出反应。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "习惯化是反应性下降而非增强。题干描述的是敏感化。"}, {"type": "判断", "num": 62, "text": "通过制定社团章程来规范社团工作行为和活动程序，比仅靠人指导更有效。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "制定章程比仅靠人指导更有效。"}, {"type": "判断", "num": 63, "text": "从整体上讲，气质并无好坏优劣之分，任何一种气质都有其积极和消极的方面，气质类型也不会对一个人的品德、智力发展水平以及将来的成就、贡献和价值起决定性作用", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "气质无好坏优劣之分。"}, {"type": "判断", "num": 64, "text": "罗杰斯认为，健全人格是一个过程而不是一种状态，是一种趋势而不是一个终点，它是不断向前的。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "罗杰斯认为健全人格是过程不是状态。"}, {"type": "判断", "num": 65, "text": "弗勒和布朗根据教师的需要和不同时期关注的焦点，把教师成长划分为关注生存、关注情境和关注学生三个阶段", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "弗勒和布朗的教师成长三阶段。"}, {"type": "判断", "num": 66, "text": "动机和情境因素影响学习", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "动机和情境因素影响学习。"}, {"type": "判断", "num": 67, "text": "在PASS模型中，注意系统是基础，同时性加工—继时性加工系统处于中间层次，计划系统为最高层次。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "PASS模型：注意系统为基础，同时-继时加工中间，计划最高。"}, {"type": "判断", "num": 68, "text": "教师威信的维护和发展，通常取决于以下几个方面：教师要有坦荡的胸怀，实事求是的态度、教师要正确认识、合理运用自己的威信、教师要有不断进取的敬业精神以及教师要言行一致，做学生的楷模", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师威信的维护发展需要坦荡胸怀、合理运用威信、进取精神和言行一致。"}, {"type": "判断", "num": 69, "text": "动物和人类都可以进行学习。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "动物和人类都可以学习。"}, {"type": "判断", "num": 70, "text": "气质与性格的联系表现为：气质影响性格的表现形式；气质影响性格形成与发展的速度；性格对气质有重要的调节作用，在一定程度上可掩盖和改造气质", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "气质与性格的联系和影响正确。"}, {"type": "判断", "num": 71, "text": "气质与人的道德品质、智力发展和成就高低有直接的联系。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "气质与道德品质、智力发展和成就高低没有直接联系。"}, {"type": "判断", "num": 72, "text": "学习者需要练习、反馈和复习", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "学习者需要练习、反馈和复习。"}, {"type": "判断", "num": 73, "text": "对集体成员来说，个体目标必须与整体目标一致，当整体目标和个体目标发生矛盾时，应以集体目标为重，修正个人目标。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "个体目标应与整体目标一致，矛盾时以集体为重。"}, {"type": "判断", "num": 74, "text": "埃里克森认为，人格发展包括了机体成熟、自我成长和社会关系这三个不可分割的过程。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "埃里克森认为人格发展包括机体成熟、自我成长和社会关系三过程。"}, {"type": "判断", "num": 75, "text": "情感成分是人际关系得以形成和维系的理性条件", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "情感成分是人际关系形成和维系的\"核心\"但不是\"理性条件\"。情感是非理性的。"}, {"type": "判断", "num": 76, "text": "文化传承、文化选择、文化批判、文化创造是高等教育的功能", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "文化传承、选择、批判、创造是高等教育的文化功能。"}, {"type": "判断", "num": 77, "text": "维果茨基提出了“学习的最佳期”的概念。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "维果茨基提出学习的最佳期概念。"}, {"type": "判断", "num": 78, "text": "根据心理异常的严重程度，我们将大学生的心理问题分为心理冲突、心理障碍、心理疾病三个层次。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "心理问题层次分为心理冲突、心理障碍、心理疾病。"}, {"type": "判断", "num": 79, "text": "德瑞福斯根据教师教学专长的一般过程，将教师成长划分为五个阶段：新手阶段、优秀新手阶段、胜任阶段、熟练阶段和专家阶段", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "德瑞福斯将教师成长分为五个阶段。"}, {"type": "判断", "num": 80, "text": "人格对个人行为具有调节功能", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人格对个人行为具有调节功能。"}, {"type": "判断", "num": 81, "text": "教师威信不会对教育、教学的成效产生巨大的影响作用。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教师威信对教育教学成效有巨大影响。"}, {"type": "判断", "num": 82, "text": "陈述性知识和程序性知识都是人的长时记忆中的重要内容。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "陈述性知识和程序性知识都是长时记忆的重要内容。"}, {"type": "判断", "num": 83, "text": "学习只存在于人类的活动中，动物不存在学习。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "动物也存在于学习，学习不仅存在于人类。"}, {"type": "判断", "num": 84, "text": "心理健康具有社会性是因为不同社会心理健康的标准也有不同。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "心理健康具有社会性是因为不同社会标准不同。"}, {"type": "判断", "num": 85, "text": "米尔格伦认为，在人际网络中，两个陌生人可以通过“亲友的亲友”建立联系，这中间最多只要通过5个朋友就能达到目的。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "米尔格伦提出六度分隔理论（最多通过五个朋友）。"}, {"type": "判断", "num": 86, "text": "英国心理学家培因和法国心理学家李波特按照知、情、意三种心理机能在性格结构中谁占优势，将人的性格分为三种类型：理智型、情绪型和意志型", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "培因和李波特按知、情、意将性格分为理智型、情绪型和意志型。"}, {"type": "判断", "num": 87, "text": "了解品德心理结构的历时性与共时性这一特征，则在品德教育与培养中，应根据学生年龄阶段特点和品德结构发展状况有侧重地进行品德的培养与教育。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "应根据学生年龄阶段和品德结构特点进行培养教育。"}, {"type": "判断", "num": 88, "text": "“滴水之恩，当涌泉相报”属于程序性知识。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "滴水之恩当涌泉相报是关于\"如何做\"的社会规则，属于程序性知识。"}, {"type": "判断", "num": 89, "text": "一个管理良好的课堂就是没有行为问题的课堂。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "管理良好的课堂不是没有行为问题，而是能有效处理行为问题。"}, {"type": "判断", "num": 90, "text": "心理学家所讲的关键期只存在于人身上，而动物没有关键期。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "关键期既存在于人身上也存在于动物身上。"}, {"type": "判断", "num": 91, "text": "物质需要只包括生理需要，不包含社会需要。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "物质需要不仅包括生理需要，也包括某些社会需要。"}, {"type": "判断", "num": 92, "text": "习惯化是指由于重复刺激引起的反应性下降，它涉及反应的减少，而不是新反应的习得。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "习惯化的正确定义（反应性下降）。"}, {"type": "判断", "num": 93, "text": "敏感化由于刺激重复使有机体对它的反应性增强，即有机体对环境中的某一特定刺激更容易作出反应。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "敏感化的正确定义。"}, {"type": "判断", "num": 94, "text": "在商店买东西的顾客群、公共汽车上的乘客群、在影剧院看电影的观众群，这些都不是真正意义上的群体。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "顾客群、乘客群、观众群没有共同目标和持续互动，不是真正意义上的群体。"}, {"type": "判断", "num": 95, "text": "高校教师成长和培养的途径有：系统的理论学习、课堂教学观摩、微型教学实践、教学决策训练和教学反思训练", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高校教师成长途径包括理论学习、观摩、微型教学、决策训练和反思训练。"}, {"type": "判断", "num": 96, "text": "“自我同一性”指个体对自己的本质、信念、人生意义的前后一致性的自我意识。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "自我同一性的定义。"}, {"type": "判断", "num": 97, "text": "在发现教学中，教师应当鼓励学生通过自己发现概念与原理来学习。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "发现教学中教师应鼓励学生自己发现概念和原理。"}, {"type": "判断", "num": 98, "text": "奥苏伯尔将学习分为接受学习和发现学习。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "奥苏伯尔将学习分为接受学习和发现学习。"}, {"type": "判断", "num": 99, "text": "学生有无进步或发展是教学有无效益的唯一指标", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "学生有无进步是教学有无效益的唯一指标。"}, {"type": "判断", "num": 100, "text": "从众有两个基本要素：规范压力和信息压力。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "从众的两个基本要素是规范压力和信息压力。"}, {"type": "判断", "num": 101, "text": "常见的求职择业心理偏差有自卑心理、盲目攀高心理、矛盾心理、冷漠心理和实惠心理", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "常见求职择业心理偏差包括自卑、盲目攀高、矛盾、冷漠和实惠心理。"}, {"type": "判断", "num": 102, "text": "马斯洛认为，个体即使无法满足较低层次的生理、安全、归属和爱的需要，也能达到高层次的自我实现。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "马斯洛认为低层次需要未满足时难以达到高层次自我实现。"}, {"type": "判断", "num": 103, "text": "教师是教学活动的计划者和组织者", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师是教学活动的计划者和组织者。"}, {"type": "判断", "num": 104, "text": "艾宾浩斯遗忘曲线揭示了遗忘的规律。即，遗忘的进程不是均衡的，在学习之后立即开始，而且进展很快，以后就逐渐变慢。到了一定时间以后，几乎就不再遗忘了。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "艾宾浩斯遗忘曲线揭示了遗忘先快后慢的规律。"}, {"type": "判断", "num": 105, "text": "群体极化经常表现出两种倾向：一种叫冒险偏移；另一种叫谨慎偏移。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "群体极化包括冒险偏移和谨慎偏移。"}, {"type": "判断", "num": 106, "text": "人类心理是共同性和差别性的统一", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人类心理是共同性和差别性的统一。"}, {"type": "判断", "num": 107, "text": "心理健康不是一种固定的状态，而是一种不断发展的过程。健康没有止境，是人的理想追求。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "心理健康是动态发展的过程。"}, {"type": "判断", "num": 108, "text": "相对于鱼的图式而言，动物的图式是一个复杂图式，因为鱼属于动物；对于鱼来说，动物的图式是高级的、上位的图式，鱼的图式则是低级的、下位的图式。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "图式有层次之分，动物的图式是鱼图式的上位/高级图式。"}, {"type": "判断", "num": 109, "text": "维果茨基的工具论认为，个体有两种工具：一是物质工具，二是精神工具。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "维果茨基工具论包括物质工具和精神工具。"}, {"type": "判断", "num": 110, "text": "对大学生而言，在适当的范围内，自负可以激发他们的斗志，树立必胜的信心，坚定战胜困难的信念，使他们勇往直前。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "适度的自负（自信）可以激发斗志。"}, {"type": "判断", "num": 111, "text": "人本主义心理学家提倡的学习理论将范围扩大到了对学习者整个人的成长历程的解释。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人本主义学习理论关注学习者整个人格成长。"}, {"type": "判断", "num": 112, "text": "教师对学生的期望、期待和关注是影响学生的学业成绩和人格的一个重要因素。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师期望对学生有重要影响（罗森塔尔效应/皮格马利翁效应）。"}, {"type": "判断", "num": 113, "text": "人格障碍不同于精神病，但二者是相互转化的。严重的人格障碍者如果没有及时有效地进行矫正，会成为精神病的高发人群，给个体或社会造成精神痛苦与危害。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人格障碍不同于精神病，但严重者可能转化为精神病。"}, {"type": "判断", "num": 114, "text": "美国心理学家布鲁姆将认知领域的教学目标分为知识、领会、运用、分析、综合和评价。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "布鲁姆将认知目标分为知识、领会、运用、分析、综合和评价。"}, {"type": "判断", "num": 115, "text": "男性和女性的智力在总体水平上不存在差异", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "男女智力总体水平不存在差异。"}, {"type": "判断", "num": 116, "text": "教师应当通过变化、活动或幽默等方式活跃课堂气氛，以维持学生的注意力", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师应通过变化活动幽默等方式活跃课堂气氛。"}, {"type": "判断", "num": 117, "text": "一般而言，高校就业系统的主要职能部门是学校就业指导中心", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高校就业系统主要职能部门是就业指导中心。"}, {"type": "判断", "num": 118, "text": "卡特尔认为晶体智力是经验的结晶，是以习得经验为基础的认知能力。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "卡特尔认为晶体智力是以习得经验为基础的认知能力。"}, {"type": "判断", "num": 119, "text": "根据调控发生的时间将教学监控能力分为在线调控型和线下调控型", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教学监控能力分为在线调控型和线下调控型。"}, {"type": "判断", "num": 120, "text": "需要、动机、行为和目标（包括诱因）是激励的四大基本要素，在管理中是激励的着眼点", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "需要、动机、行为和目标是激励的四大基本要素。"}, {"type": "判断", "num": 121, "text": "舒茨的人际需要三维论认为，每一个体在人际互动中都有包容、支配和情感需要。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "舒茨人际需要三维论包括包容、支配和情感需要。"}, {"type": "判断", "num": 122, "text": "奥苏伯尔认为，遗忘是一种积极的现象，是知识的组织和认知结构的简化过程。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "奥苏伯尔认为遗忘是积极现象，是知识组织的简化过程（同化说）。"}, {"type": "判断", "num": 123, "text": "男性和女性的智力结构存在差异，各有自己的智力优势", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "男女智力结构存在差异，各有优势。"}, {"type": "判断", "num": 124, "text": "程序性知识（“知道怎样做”）比陈述性知识（“知道是什么”）更适宜于采用直接教学", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "陈述性知识比程序性知识更适合直接教学。程序性知识更需要练习和实践。"}, {"type": "判断", "num": 125, "text": "埃里克森认为，一个完整的人生周期共分八个阶段。每一个阶段都由一对冲突或两极对立的矛盾组成，并形成一种危机。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "埃里克森八阶段每阶段都有冲突或危机。"}, {"type": "判断", "num": 126, "text": "兴趣是学生进行生涯规划的重要依据，它可以增强对所选择的生活或学习的满意度和稳定性，可以促进个人能力的发挥。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "兴趣是生涯规划的重要依据。"}, {"type": "判断", "num": 127, "text": "遗传素质不仅是品德发展的物质基础或自然前提，也是品德发展的潜在因素。人的品德发展是建立在遗传的物质条件基础之上的。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "遗传素质是品德发展的物质基础和潜在因素。"}, {"type": "判断", "num": 128, "text": "职业生涯规划一般可划分成长期、探索期、建立期、维持期和衰退期五个时期。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "职业生涯规划分为成长期、探索期、建立期、维持期和衰退期。"}, {"type": "判断", "num": 129, "text": "对一般的教学能力而言，高校教师应掌握包括专业知识、组织教材的能力、言语表达能力、组织教学的能力以及教学多媒体运用能力等", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高校教师应掌握这些教学能力。"}, {"type": "判断", "num": 130, "text": "教师是学生环境和学生集体的管理者", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师是学生环境和集体的管理者。"}, {"type": "判断", "num": 131, "text": "就当代大学生而言，健全人格的特点主要体现在以下几个方面：有正确的自我认知能力、有良好的适应社会环境的能力、有心理与行为和谐一致的能力、具有良好的自我调节能力、有探求新知和创新的能力和具有良好的人际交往能力", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学生健全人格的特点。"}, {"type": "判断", "num": 132, "text": "随着时代变迁，现代教育观念则更强调教师是学生学习活动的组织者、指导者和帮助者", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "现代教育观念强调教师是组织者、指导者和帮助者。"}, {"type": "判断", "num": 133, "text": "动机是推动和维持人们活动的内部原因或动力。人的一切活动总是受动机的调节和支配。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "动机是推动和维持活动的内部原因或动力。"}, {"type": "判断", "num": 134, "text": "爱利丝（Ellis）1894年出版《男人和女人》一书，标志着性别差异研究的开始", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "爱利丝1894年出版《男人和女人》标志性别差异研究开始。"}, {"type": "判断", "num": 135, "text": "教师扮演的角色对学生而言有不同作用，这些作用可以按感情因素排列，其中起权威者作用的有家长的代理人、知识的传授者、团体的领导和模范公民", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "家长代理人、知识传授者、团体领导、模范公民起权威者作用。"}, {"type": "判断", "num": 136, "text": "目标设置理论认为绩效反馈能带来更高的绩效", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "目标设置理论认为绩效反馈能带来更高绩效。"}, {"type": "判断", "num": 137, "text": "在新的形势下，对大学生进行相应的就业指导工作已迫在眉睫。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "对新形势下大学生进行就业指导工作很重要。"}, {"type": "判断", "num": 138, "text": "大学生中常见的自我认知问题主要有自卑、自负、虚荣。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学生常见自我认知问题包括自卑、自负、虚荣。"}, {"type": "判断", "num": 139, "text": "皮连生将广义的教学过程概括为六个环节：陈述目标、分析任务、确定学生的原有水平、课堂教学活动设计、师生的相互作用过程和教学评价", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "皮连生将教学过程概括为六个环节。"}, {"type": "判断", "num": 140, "text": "个体自我意识水平的高低，是决定去个性化行为会不会发生的关键因素。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "个体自我意识水平是决定去个性化行为的关键因素。"}, {"type": "判断", "num": 141, "text": "抉择平衡单是进行生涯抉择的一种具体练习方式。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "抉择平衡单是生涯抉择的练习方式。"}, {"type": "判断", "num": 142, "text": "研究性学习的根本目标在于培养学生的创新能力和实践能力。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "研究性学习的根本目标是培养创新能力和实践能力。"}, {"type": "判断", "num": 143, "text": "教师的成长过程是一个由新手到熟手，向专家型教师发展的过程", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师成长是由新手到专家的发展过程。"}, {"type": "判断", "num": 144, "text": "教师指导学生进行归因时应引导大学生对自己的成败做有利的归因，即对成败做有利于今后的学习和适应的归因", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师应引导大学生做有利归因。"}, {"type": "判断", "num": 145, "text": "布朗芬布伦纳将个体置于五个环境系统中进行考察。这五个系统分别为：微系统、外系统、中介系统、宏系统和时序系统", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "布朗芬布伦纳生态系统理论包括微系统、中介系统、外系统、宏系统和时序系统。"}, {"type": "判断", "num": 146, "text": "在评定气质时，不能认为一种气质类型就是好的、积极的，另一种气质类型就是差的、消极的。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "气质无好坏优劣之分。"}, {"type": "判断", "num": 147, "text": "大学生常见的人格障碍有偏执型人格障碍、强迫型人格障碍、分裂型人格障碍、反社会型人格障碍和攻击型人格", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学生常见人格障碍包括偏执型、强迫型、分裂型、反社会型和攻击型。"}, {"type": "判断", "num": 148, "text": "人格是个体独特的心理结构", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人格是个体独特的心理结构。"}, {"type": "判断", "num": 149, "text": "将获得知识以图式形式，围绕某一主题相互联系起来，形成一定的知识单元，将会有效地促进人对知识的存储和运用。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "图式形式组织知识能有效促进存储和运用。"}, {"type": "判断", "num": 150, "text": "PAC分析论认为，人格由三种比重不同的心理状态构成，这就是“父母”、“成人”、“儿童”。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "PAC分析论认为人格由父母、成人、儿童三种状态构成。"}, {"type": "判断", "num": 151, "text": "皮连生将认知目标分为3类：陈述性知识，智慧技能和认知策略。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "皮连生将认知目标分为陈述性知识、智慧技能和认知策略。"}, {"type": "判断", "num": 152, "text": "人格障碍的自我调适的方法有反向观念法、行为禁止法、情绪调整法和习惯纠正法", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人格障碍自我调适方法包括反向观念法、行为禁止法、情绪调整法和习惯纠正法。"}, {"type": "判断", "num": 153, "text": "张积家认为教师除担任由教师职务所决定的角色外，在社会生活中还担任知识的建设者、社区活动的组织者和普通公民的角色", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "张积家认为教师还担任知识建设者、社区活动组织者和普通公民角色。"}, {"type": "判断", "num": 154, "text": "教育和教学是高校教师的主要活动", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教育和教学是高校教师的主要活动。"}, {"type": "判断", "num": 155, "text": "我国古代医书《黄帝内经》根据阴与阳两种力量在人身上的比例不同，将人分为太阴型、少阴型、阴阳和平型、少阳型和太阳型五种不同的气质类型", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "黄帝内经将气质分为太阴、少阴、阴阳和平、少阳、太阳五型。"}, {"type": "判断", "num": 156, "text": "大学生要建立良好的人际关系，要有相应技巧。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "建立良好人际关系需要相应技巧。"}, {"type": "判断", "num": 157, "text": "群体内大多数成员的意见会产生一种无形的力量，使群体内的每一成员自觉或不自觉地保持与大多数人的一致性，这就是群体压力。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "群体压力使成员与大多数人保持一致。"}, {"type": "判断", "num": 158, "text": "学生不会受到教师道德伦理价值体系的影响", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "学生会受教师道德伦理价值体系影响。"}, {"type": "判断", "num": 159, "text": "学生的气质类型是因材施教的重要心理学依据。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "气质类型是因材施教的重要心理学依据。"}, {"type": "判断", "num": 160, "text": "加德纳认为就智力的结构而言，智力不是某种能力或围绕某种能力的几种能力的整合，而是由相对独立、相互平等的八种智力构成", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "加德纳提出多元智力理论，智力由八种相对独立的智力构成。"}, {"type": "判断", "num": 161, "text": "维持一定的教学秩序是有效教学的前提", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "维持教学秩序是有效教学的前提。"}, {"type": "判断", "num": 162, "text": "大学生的需要激励内容有满足发展需要激励、满足情感需要激励和满足成就与尊重需要激励", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学生需要激励包括发展需要、情感需要和成就尊重需要。"}, {"type": "判断", "num": 163, "text": "自我评价偏差是大学生产生心理问题的主要原因。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "自我评价偏差是大学生产生心理问题的主要原因。"}, {"type": "判断", "num": 164, "text": "大学生的情绪比中学生稳定。中学生的情绪往往受制于外部刺激，较少有情绪累积；大学生则有更稳定、更深刻的情绪", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学生的情绪比中学生更稳定深刻。"}, {"type": "判断", "num": 165, "text": "非正式群体对正式群体的影响都是积极的", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "非正式群体对正式群体的影响不总是积极的。"}, {"type": "判断", "num": 166, "text": "人格并非是一个单一的概念，而是一类概念的综合体。它是对人的整体描述，反映了人的整体性。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人格是对人的整体描述，反映整体性。"}, {"type": "判断", "num": 167, "text": "高校要运用心理学原理和方法，针对大学生心理发展特点和择业中暴露出来的心理问题，及时进行择业心理教育与指导。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高校应运用心理学原理进行择业心理教育指导。"}, {"type": "判断", "num": 168, "text": "教师还可以根据课堂活动形式采用多种座位安排形式，集体教学时可采用传统的“秧田型”排列；小组讨论时则可以采用“会晤型”和“马蹄型”排列。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "座位安排应根据活动形式灵活调整。"}, {"type": "判断", "num": 169, "text": "动机由需要转化而来，但两者之间仍有严格的区分。需要是行为积极性的源泉，动机是行为的直接原因。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "动机由需要转化而来，需要是源泉，动机是直接原因。"}, {"type": "判断", "num": 170, "text": "魏格纳在看地图时突然闪现出“大陆漂移”的观念，这属于直觉思维起主要作用。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "魏格纳的大陆漂移观念是直觉思维的典型例子。"}, {"type": "判断", "num": 171, "text": "习惯化是指人的感受能力发生了变化。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "习惯化是反应性下降，题干描述不准确。"}, {"type": "判断", "num": 172, "text": "学习者通过学习的各个阶段而不断进步", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "学习者通过学习阶段不断进步。"}, {"type": "判断", "num": 173, "text": "目标设置理论认为如果能力和目标的可接受性不变，目标越困难，绩效水平越高", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "目标越困难，如果能力和可接受性不变，绩效水平越高。"}, {"type": "判断", "num": 174, "text": "品德是一定的社会道德规范在个体头脑中的反映和在个体行为中的具体体现。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "品德是社会道德规范在个体头脑中的反映和行为体现。"}, {"type": "判断", "num": 175, "text": "建构主义的教学观强调自下而上的教学，而非自上而下的教学。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教材指出，建构主义强调自上而下的教学，这种取向与传统的自下而上的教学策略相反。因此题干说法错误。"}, {"type": "判断", "num": 176, "text": "动机与行为的关系十分复杂：同一行为可能有不同动机，相似或相同的动机可能引起不同行为，在同一个体身上，行为动机可能多种多样", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "动机与行为关系复杂，同一行为可能有不同动机。"}, {"type": "判断", "num": 177, "text": "只有加强教师的教学反思，教师的教学水平才能不断提高，教学效果才会越来越好。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "加强教学反思能提高教学水平。"}, {"type": "判断", "num": 178, "text": "一般来说，群体中地位低的人不易出现从众行为，地位高的人容易出现从众行为", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "地位低的人容易出现从众行为，地位高的人不易从众。"}, {"type": "判断", "num": 179, "text": "道德情感是道德品质中的重要组成部分，没有道德情感，也就没有个人的品德，它对人的道德行为有巨大的支撑作用。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "道德情感是道德品质的重要组成部分。"}, {"type": "判断", "num": 180, "text": "群体规范指群体所确定的行为标准。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "群体规范是群体所确定的行为标准。"}, {"type": "判断", "num": 181, "text": "班风对学生品德形成有着更直接的影响。班集体凝聚力越强，班集体力量就越显著。同时，集体舆论会对班集体成员的思想观念和行为方式产生很大影响。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "班风对学生品德有直接影响。"}, {"type": "判断", "num": 182, "text": "我国古代教育家孔子将人分成三种性格：狂者、狷者和中行", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "孔子将人分为狂者、狷者和中行三种性格。"}, {"type": "判断", "num": 183, "text": "马斯洛认为，生理需要如果得不到满足，人类的生存就难以保障。从这个意义上说，它是推动人们行动的最强大动力。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "马斯洛认为生理需要是最基本的，是推动行动的最强大动力。"}, {"type": "判断", "num": 184, "text": "托尔曼提出认知地图的概念。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "托尔曼提出认知地图概念。"}, {"type": "判断", "num": 185, "text": "赫茨伯格将只能防止不满意感产生的因素称之为“保健因素”", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "赫茨伯格将只能防止不满的因素称为保健因素。"}, {"type": "判断", "num": 186, "text": "短时记忆指的是信息保持在5秒至2分钟之内的记忆，容量很小，大约为7±2个单位。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "短时记忆保持5秒到2分钟，容量为7±2个单位。"}, {"type": "判断", "num": 187, "text": "有一种特性是优秀教师所共有的，这就是教学的意识性。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "优秀教师共有的特性是教学的意识性。"}, {"type": "判断", "num": 188, "text": "教师知识越多，教学效果越好", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教师知识多不等于教学效果好。"}, {"type": "判断", "num": 189, "text": "教师是一个角色丛，各种角色的角色规范不一致，就会造成角色冲突", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师角色丛中角色规范不一致造成角色冲突。"}, {"type": "判断", "num": 190, "text": "由于人的遗传素质不同，生活环境不同，所受的教育不同，从事的实践活动也不同，所处的社会地位不同，因而也形成了各不相同的心理特点。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "不同遗传和生活环境形成不同的心理特点。"}, {"type": "判断", "num": 191, "text": "大学生中常见的自我认知问题主要有自卑、自负、虚荣和抑郁。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "教材中大学生自我意识发展的障碍主要包括自我否定和自我拒绝、过强的自尊心与过重的自卑感、自我中心和从众心理等；“自卑、自负、虚荣和抑郁”不能概括为大学生常见的主要自我认知问题。"}, {"type": "判断", "num": 192, "text": "政策指导是就业指导的前提。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "政策指导是就业指导的前提。"}, {"type": "判断", "num": 193, "text": "大学生目标激励主要表现在确立目标和目标行为的指导上。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "大学生目标激励包括确立目标和目标行为指导。"}, {"type": "判断", "num": 194, "text": "需要是人的积极性的源泉，是人活动的基本动力。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "需要是人的积极性源泉。"}, {"type": "判断", "num": 195, "text": "在教学过程中，应根据不同的学习要求和不同的学习阶段，有侧重地传授陈述性知识或程序性知识。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "应根据不同学习要求和阶段有侧重地传授不同知识。"}, {"type": "判断", "num": 196, "text": "精神分析大师弗洛伊德提出了自我、本我、超我的概念", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "弗洛伊德提出自我、本我、超我的概念。"}, {"type": "判断", "num": 197, "text": "人生观是个人对于人生目的和意义的根本看法和态度，是一定的世界观在人生问题上的反映。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "这是人生观的标准定义。"}, {"type": "判断", "num": 198, "text": "可以通过在高校开设就业指导课程的方式，提升学生的各项求职技能。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "开设就业指导课程可提升学生求职技能。"}, {"type": "判断", "num": 199, "text": "健全人格是指人格的生理、心理、社会、道德和审美各要素的完美统一、平衡和协调，是生物进化所赋予人的本性充分发展时所能达到的境界", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "这是健全人格的定义。"}, {"type": "判断", "num": 200, "text": "斯卡尔等人指出“遗传－环境－行为表现”的关系随着个体年龄发展而变化，并具体表现为被动式、唤起式和主动式三种形式", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "斯卡尔认为遗传-环境-行为表现的关系随年龄发展变化。"}, {"type": "判断", "num": 201, "text": "遗传与环境相互作用论认为遗传与环境、成熟与学习的作用是静态的", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "遗传与环境相互作用论认为遗传与环境作用是动态的，非静态的。"}, {"type": "判断", "num": 202, "text": "描述性的研究方法可以揭示出两个变量之间的因果关系和相关关系", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "描述性研究只能揭示相关关系，不能揭示因果关系。"}, {"type": "判断", "num": 203, "text": "3岁以前的儿童也具有发达的抽象逻辑思维。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "3岁前儿童没有发达的抽象逻辑思维，主要是直观动作思维。"}, {"type": "判断", "num": 204, "text": "干扰说认为遗忘是记忆痕迹由于得不到强化而逐渐减弱，以至于最后消退。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "题干描述的是衰退说。干扰说认为遗忘是信息相互干扰所致。"}, {"type": "判断", "num": 205, "text": "有效教学有利于提高学生的非智力因素", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "有效教学有利于提高学生非智力因素。"}, {"type": "判断", "num": 206, "text": "高校教师的角色冲突表现在以下四个方面：在师生关系上，表现为“教育者”与“服务者”冲突；在教师与高校行政管理部门的关系上，表现为“被服务者”与“被管理者”的冲突；在教师与社会的关系上，体现为“引领者”与“被动适应者”的冲突和在职业理想方面，存在着“志业”和“谋生”的冲突。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "这是高校教师角色冲突的四个表现。"}, {"type": "判断", "num": 207, "text": "健康可分为生理健康和心理健康两方面。一个健康的人，不仅要有健康的躯体，还要有健全的心理。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "健康包括生理健康和心理健康。"}, {"type": "判断", "num": 208, "text": "高等教育的本质特点是专门和高级", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高等教育的本质特点是专门和高级。"}, {"type": "判断", "num": 209, "text": "皮亚杰的认知发展论中属于婴儿感知运动阶段的特征主要通过协调感觉输入和依靠动作来认识世界。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "感知运动阶段特征是通过协调感觉和动作认识世界。"}, {"type": "判断", "num": 210, "text": "提高教学监控能力的技术有：角色改变、教学反馈和现场指导", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "提高教学监控能力的技术包括角色改变、教学反馈和现场指导。"}, {"type": "判断", "num": 211, "text": "相对成熟的大学生而言，坚持用社会意义较小的动机取代社会意义较大的动机的情况普遍存在。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "相对成熟的大学生而言，用社会意义大的动机取代小的动机是普遍现象。"}, {"type": "判断", "num": 212, "text": "生涯彩虹图描绘出生涯发展阶段与角色彼此间交互影响、多重角色生涯发展的状况", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "生涯彩虹图描述发展阶段与角色的交互影响。"}, {"type": "判断", "num": 213, "text": "如果他人在场但每个人的参与程度可以检验和鉴别，就不会产生“浑水摸鱼”的情况。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "如果每个人的参与可检验鉴别，就不会有浑水摸鱼。"}, {"type": "判断", "num": 214, "text": "教师扮演的角色对学生而言有不同作用，这些作用可以按感情因素排列，其中起消极作用的有替罪羊和侦探和纪律执行者", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "替罪羊和侦探纪律执行者起消极作用。"}, {"type": "判断", "num": 215, "text": "建构主义的教学通常采用大量的合作学习。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "建构主义教学采用大量合作学习。"}, {"type": "判断", "num": 216, "text": "完型-顿悟说属于行为主义的观点。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "完型-顿悟说属于格式塔学派，不是行为主义。"}, {"type": "判断", "num": 217, "text": "定势对知识迁移的作用既有积极的，也有消极的。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "定势对迁移的作用既有积极也有消极。"}, {"type": "判断", "num": 218, "text": "马斯洛认为，在同一时间、地点和条件下，人存在多种需要，为人最渴望得到而又未得到满足的需要是优势需要，它对人的行为起决定性作用。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "优势需要对人的行为起决定性作用。"}, {"type": "判断", "num": 219, "text": "匿名因素是产生去个性化现象的诱因", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "匿名因素是去个性化现象的诱因。"}, {"type": "判断", "num": 220, "text": "遗忘的动机说认为任何遗忘都有动机。记不起是因为不想记，于是就把信息压抑到潜意识中去。如果压抑被解除，记忆就可以恢复。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "遗忘的动机说（压抑说）认为遗忘是被压抑到潜意识。"}, {"type": "判断", "num": 221, "text": "小学生学习乘法总是从同数连加入手，因为有关加法的知识是学习乘法的基础。新旧知识的有机联系，能帮助学生对新知识的理解。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "新旧知识有机联系能帮助理解新知识。"}, {"type": "判断", "num": 222, "text": "如何引导大学生到合适的地区、行业和岗位上去，从而实现人尽其才、才尽其用，是就业指导的重要任务。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "引导大学生到合适岗位是人尽其才的重要任务。"}, {"type": "判断", "num": 223, "text": "柯林斯等人提出的探究式教学对辅导者和学习者有较高要求", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "探究式教学对辅导者和学习者有较高要求。"}, {"type": "判断", "num": 224, "text": "气质与性格的区别表现为：气质更多地受个体高级神经活动类型的制约，主要是先天的；性格更多地受社会生活条件的制约，主要是后天的；气质与性格的发生发展也并不总是同步的。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "气质先天、性格后天，两者发展不同步。"}, {"type": "判断", "num": 225, "text": "心理学家所讲的关键期是指，人或动物的某些行为与能力发展的某一段时间，如果此时给以适当的良性刺激，会促使行为与能力得到更好的发展；反之，则会阻碍发展甚至导致行为与能力的缺失。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "关键期的定义。"}, {"type": "判断", "num": 226, "text": "年龄小、社会阅历少的人因为好奇心强，容易模仿别人。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "年龄小、社会阅历少的人因好奇心强容易模仿。"}, {"type": "判断", "num": 227, "text": "激励的作用有：调动人的积极性，开发人的潜能；造就良性竞争环境；激励是教育和管理中最重要的职能", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "激励的作用包括调动积极性、开发潜能、造就竞争环境。"}, {"type": "判断", "num": 228, "text": "目标设置理论认为参与设置自己的目标可以提高目标接受性", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "参与设置目标可以提高目标接受性。"}, {"type": "判断", "num": 229, "text": "完型-顿悟说属于格式塔学派的观点。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "完型-顿悟说属于格式塔学派的观点。"}, {"type": "判断", "num": 230, "text": "人际关系指人们在活动中直接的心理关系。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "人际关系是人们在活动中直接的心理关系。"}, {"type": "判断", "num": 231, "text": "认知成分是人际关系的核心", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "情感成分是人际关系的核心，非认知成分。"}, {"type": "判断", "num": 232, "text": "挫折反应的个体差异，由以下因素引起：个体的抱负水平、个体的挫折耐受力和个体对挫折的经验", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "挫折反应个体差异由抱负水平、耐受力和经验引起。"}, {"type": "判断", "num": 233, "text": "生态环境、气候条件、空间拥挤程度等这些自然物理因素都会影响人格", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "自然物理因素会影响人格。"}, {"type": "判断", "num": 234, "text": "主体性教学评价不仅关注结果，更加重视过程", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "主体性教学评价既关注结果更重视过程。"}, {"type": "判断", "num": 235, "text": "轻微的嫉妒叫羡慕，它对人的行为有积极的推动作用，促使个体通过增加努力去参与竞争。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "轻微嫉妒叫羡慕，有积极推动作用。"}, {"type": "判断", "num": 236, "text": "女性在成功的情境下多做内部归因，在失败的情境下多做外部归因", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "女性在成功时做外部归因（运气），失败时做内部归因（能力）。题干说反了。"}, {"type": "判断", "num": 237, "text": "激励，一般指一个有机体在追求某些既定目标时的意愿程度。它含有引起需要、激发动机、鼓励行为、形成动力的意义。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "激励的定义。"}, {"type": "判断", "num": 238, "text": "可以说，离开了社会道德，品德也就无从谈起。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "离开了社会道德就没有品德的来源。"}, {"type": "判断", "num": 239, "text": "全面发展等于平均发展", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "全面发展不等于平均发展。"}, {"type": "判断", "num": 240, "text": "赫茨伯格将引起对工作的满意感的因素称之为“激励因素”", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "赫茨伯格将引起满意感的因素称为激励因素。"}, {"type": "判断", "num": 241, "text": "马斯洛认为，人的需要是由以下五个等级构成，它们分别是生理需要、安全需要、爱与归属的需要、尊重的需要和自我实现的需要", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "马斯洛需要层次论的五种需要。"}, {"type": "判断", "num": 242, "text": "教师是学校的咨询员，负有引导学生的认知和情感发展的责任", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师是咨询员，负有引导学生的责任。"}, {"type": "判断", "num": 243, "text": "每个人都有着不同的行为反应模式，这就是个人的风格", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "个人的行为反应模式即个人风格。"}, {"type": "判断", "num": 244, "text": "教师组织教学活动的能力包括制定课堂教学计划的能力、正确选择运用教学方法的能力和调节课堂气氛、调动学生积极性的能力", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "教师组织教学能力包括制定计划、选择方法和调节气氛。"}, {"type": "判断", "num": 245, "text": "高校应实行多元的主体性教学评价。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高校应实行多元主体性教学评价。"}, {"type": "判断", "num": 246, "text": "影响教师威信形成的主观因素有：教育教学技能和心理素质、良好的道德品质、教师的仪表、生活作风和习惯、师生平等交往和教师给学生的第一印象", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "这些因素是影响教师威信的主观因素。"}, {"type": "判断", "num": 247, "text": "空气属于一级强化物，而钱属于二级强化物。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "一级强化物直接满足基本需要，无需学习即可起强化作用；二级强化物是经学习获得强化意义的刺激。空气可视为一级强化物，钱属于二级强化物。"}, {"type": "判断", "num": 248, "text": "高校教师的角色期待有教学活动的设计者、大学生学习的指导者和促进者、教学的组织者和管理者、教学的反思者与研究者、平等中的“首席”、科学家或思想家、终身学习者和心理健康的维护者", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "高校教师的角色期待包括这些方面。"}, {"type": "判断", "num": 249, "text": "麦克利兰测量成就动机的方法是投射测验", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "麦克利兰用投射测验测量成就动机。"}, {"type": "判断", "num": 250, "text": "一般来讲，在智力、气质等与生物因素相关较高的特征上，遗传的因素比较重要；在价值观、信念、性格等与社会因素相关较高的特征上，后天环境的因素更为重要。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "生物因素相关高的受遗传影响大，社会因素相关高的受环境影响大。"}, {"type": "判断", "num": 251, "text": "道德的基本结构为“知、情、意、行”，即包含道德认识、道德情感、道德意志和道德行为四个方面。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "道德基本结构为知、情、意、行。"}, {"type": "判断", "num": 252, "text": "最不成熟的同一性状态是同一性混淆", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "同一性混淆是最不成熟的同一性状态。"}, {"type": "判断", "num": 253, "text": "男性在成功的情境下多做外部归因，在失败的情境下多做内部归因", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "男性在成功情境下多做内部归因（能力），失败时多做外部归因。题干说反了。"}, {"type": "判断", "num": 254, "text": "在大学生活中产生不公平现象的主要原因有：错误的攀比心理、奖励制度本身的不完善和工作者的不公正", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "不公平现象的原因包括攀比心理、制度不完善和不公正。"}, {"type": "判断", "num": 255, "text": "目标设置理论认为笼统的目标要比具体的目标效果更好", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "具体的目标比笼统的目标效果更好。"}, {"type": "判断", "num": 256, "text": "在角色认识转化为信念的过程中，实践活动非常重要。", "options": {"A": "对", "B": "错"}, "answer": "A", "explanation": "角色认识转化为信念过程中实践活动重要。"}, {"type": "判断", "num": 257, "text": "家长的职业类型与文化程度不同，并不会对子女品德产生影响。", "options": {"A": "对", "B": "错"}, "answer": "B", "explanation": "家长的职业类型和文化程度会影响子女品德。"}]
};
